-- Poems batch 307
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2ae52cba-6d47-4426-89d2-8a3d13ba1c07','徐程致仕寄之','劉摯','宋','宋诗','song-poetry','','[]','浩然歌笑脫青綸，高調冥冥綵服還。',64,'全唐诗/poet.song.38000.json','["浩然歌笑脫青綸，高調冥冥綵服還。", "智達能遺名跡去，英雄宜爲泰平閑。", "秋風酒榼攜寒野，春雨蘭芽長舊山。", "養已奉親心兩得，世人行止是非間。"]'),
('fa9f50b4-d8cf-4599-9d87-075cacae15e7','宿州靈璧張氏園亭舟過始知之','劉摯','宋','宋诗','song-poetry','','[]','去國身隨濁汴傾，瞥然雙漿若孤鷹。',64,'全唐诗/poet.song.38000.json','["去國身隨濁汴傾，瞥然雙漿若孤鷹。", "不知堤木藏金谷，但見漁人說武陵。", "已許生平倠水石，坐看名利僅蚊蠅。", "從今所至停舟問，詩酒雖衰亦强能。"]'),
('9930829f-d7a4-4c7b-a4a9-f210c5c00592','八月十五日宿平原寄跂蹈','劉摯','宋','宋诗','song-poetry','','[]','去秋今夕艤歸船，雨濕湓江歎隔年。',64,'全唐诗/poet.song.38000.json','["去秋今夕艤歸船，雨濕湓江歎隔年。", "幸此一輪開霽魄，郤嗟千里共秋天。", "更爲來歳悠悠約，安得清光夜夜圓。", "孤館悄然誰晤語，滿庭寒露濕蒼烟。"]'),
('ea7f9dd2-5ea6-4139-acfc-d4afb0b5670a','離汶馬上寄鄉中親舊','劉摯','宋','宋诗','song-poetry','','[]','半月徘徊去魯遲，二年樽酒奉音徽。',64,'全唐诗/poet.song.38000.json','["半月徘徊去魯遲，二年樽酒奉音徽。", "又貪聖寵移金節，還使鄉人笑錦衣。", "天地中間真遠客，田園蕪沒盍來歸。", "東州不擬多時住，已傍蘆溪作釣磯。"]'),
('4fa95ef8-d0fc-49bd-9ad5-9e3822664f89','至金鄉先寄田直孺','劉摯','宋','宋诗','song-poetry','','[]','京雒塵埃各未湔，古城瀟灑向秋天。',64,'全唐诗/poet.song.38000.json','["京雒塵埃各未湔，古城瀟灑向秋天。", "今朝屈指終三伏，此地銜杯已六年。", "老喜交朋頻把臂，拙無材力可求田。", "君當記得鱸魚約，何日相從上釣船。"]'),
('f1cfadef-0f81-4878-9a04-7e5f99f04324','秋浦寄田同年鯁','劉摯','宋','宋诗','song-poetry','','[]','三月鵬雲接翼飛，歳窮飄泊動相思。',64,'全唐诗/poet.song.38000.json','["三月鵬雲接翼飛，歳窮飄泊動相思。", "獨臨谿檻看山處，正是江天欲雪時。", "連轡都門君不至，合簪秋浦我來遲。", "明年尚好方舟去，醉倒春風有舊期。"]'),
('b66c2502-32b0-4d77-b5fe-f2c43edefdef','過任城謁田直孺','劉摯','宋','宋诗','song-poetry','','[]','古邑東風桃李殘，故人高臥白雲間。',64,'全唐诗/poet.song.38000.json','["古邑東風桃李殘，故人高臥白雲間。", "我知原子貧非病，誰識蕭生志抱關。", "相遇正逢春事晚，已衰難伴醉鄉閑。", "卜鄰慚愧當年約，依舊無錢買北山。"]'),
('87a69061-4ef1-4101-9414-161ee0770211','寄尹元佐','劉摯','宋','宋诗','song-poetry','','[]','都城分袂下長淮，聞說靈槎犯斗回。',64,'全唐诗/poet.song.38000.json','["都城分袂下長淮，聞說靈槎犯斗回。", "天上夜蟾千里共，江南秋雁尺書來。", "莫悲琴劍猶羈客，豈有英雄老俗埃。", "此去玉皇恩澤異，龍飛新榜看風雷。"]'),
('f5b41e3a-9bae-40c6-b36a-89699aea954a','寄高陽陳鎬','劉摯','宋','宋诗','song-poetry','','[]','胸中奇藴入天淵，平昔英遊夢寐間。',64,'全唐诗/poet.song.38000.json','["胸中奇藴入天淵，平昔英遊夢寐間。", "寶劍早因靈氣識，臥龍今惜壯圖閑。", "匈奴尚敢乘黄屋，漢騎新聞戍玉關。", "應共將軍話功業，酒酣朝夕望燕山。"]'),
('0224cb45-86f4-4ebb-b306-fff974d9f2a6','寄長沙王源祖','劉摯','宋','宋诗','song-poetry','','["\u8861\u5c71"]','湘水衡山冠楚西，逢君曾與勝游期。',64,'全唐诗/poet.song.38000.json','["湘水衡山冠楚西，逢君曾與勝游期。", "橋躋危蹬尋僧去，月滿歸舟載酒時。", "歳律别來驚易改，琴徽空自寄相思。", "試看湖上梅應老，不解東風贈一枝。"]'),
('04987a21-e5f7-4daa-bd7b-2dc0ce057241','表海亭','劉摯','宋','宋诗','song-poetry','','[]','到此翛翛欲羽翰，長簷危檻壓潺潺。',64,'全唐诗/poet.song.38000.json','["到此翛翛欲羽翰，長簷危檻壓潺潺。", "高低步障千花磴，遠近屏風四境山。", "興爲南樓雖不淺，倦如飛鳥亦知還。", "偷閑擬上三年計，寧願齊侯五月間。"]'),
('7f96a31c-aa75-4fbb-b215-f4483e5a20a6','早春書呈温甫用前韻','劉摯','宋','宋诗','song-poetry','','[]','春皇消息到人間，屈指年華笑側冠。',64,'全唐诗/poet.song.38000.json','["春皇消息到人間，屈指年華笑側冠。", "梅蘂暗黄初過雪，蘭芽淺紫未離寒。", "時哉物逐東風樂，老矣心于勝事難。", "惟有林泉隨處好，可須巖谷隐歸盤。"]'),
('dbb3f648-a8cd-4816-a664-0f6c172a99e7','登照碧亭次韻燕若水','劉摯','宋','宋诗','song-poetry','','[]','記着蓬瀛向此開，清明簾幕望高臺。',64,'全唐诗/poet.song.38000.json','["記着蓬瀛向此開，清明簾幕望高臺。", "老慚蒼鬢親花蕚，病負眷風厭酒杯。", "青蓋綺羅尋徑去，畫船簫鼓轉溪來。", "不知好事樓前客，便有嘲吟倚馬才。"]'),
('74bf10f3-7811-4363-8d6d-6361a0d699a8','憶靈泉山寄龔輔之諫議丈','劉摯','宋','宋诗','song-poetry','','[]','不到靈房二十年，背依叢嶺面平山。',64,'全唐诗/poet.song.38000.json','["不到靈房二十年，背依叢嶺面平山。", "風吹檜柏周遭雨，地蹙岡巒寸尺煙。", "合有高亭臨綠篠，恨無長甃引清泉。", "攜笻占得頻來往，誰似香山白樂天。"]'),
('c72c7920-2a67-40d0-8650-63390696c4bb','次韻余翼贈陳長史繪','劉摯','宋','宋诗','song-poetry','','[]','變化洪纖付一陶，中楹瞻望赭紗袍。',64,'全唐诗/poet.song.38000.json','["變化洪纖付一陶，中楹瞻望赭紗袍。", "有才元子名爲污，失意劉蕡策自高。", "青史異時觀壯士，黄衣何日調南曹。", "居閑更覺新詩好，詞力還堪僕命騷。"]'),
('8d1076ad-3325-400a-ab75-c6b87ecea8f0','次韻觀棋','劉摯','宋','宋诗','song-poetry','','[]','晝永風閑玉局平，機心相軋掌中兵。',64,'全唐诗/poet.song.38000.json','["晝永風閑玉局平，機心相軋掌中兵。", "敵家只欲乘虚奪，完地何勞用刧成。", "縱使仲宣强記在，枉將陶侃寸陰争。", "旁觀有訣君須信，大抵驕貪悔吝生。"]'),
('5793720e-d33b-42ce-b4f6-d301ec989569','盛陶索詩録近作數篇以長句將之','劉摯','宋','宋诗','song-poetry','','[]','太白谿邊思會遇，九華峰下共登臨。',64,'全唐诗/poet.song.38000.json','["太白谿邊思會遇，九華峰下共登臨。", "高樓一别江南醉，幾歳同爲塞北吟。", "漳浦舊懷多感慨，建安遺響未銷沈。", "言雖窮苦君能聽，試寫孤音入夜琴。"]'),
('81ab90eb-81ad-41b6-afae-04fe603efa56','二月二日過吳德仁二首  其一','劉摯','宋','宋诗','song-poetry','','[]','清門令德江南吳，三紀蘭洲心自娱。',64,'全唐诗/poet.song.38000.json','["清門令德江南吳，三紀蘭洲心自娱。", "明時中林隱君子，蚤歳東門賢大夫。", "老去笑談惟玉塵，病餘風韻更冰壺。", "世于出處罕無意，兩忘未見斯人徒。"]'),
('0b0c967d-03c2-41d2-a6cf-588ae7e092b1','二月二日過吳德仁二首  其二','劉摯','宋','宋诗','song-poetry','','[]','三徑長籬依斷崖，築堂能向紫溪開。',64,'全唐诗/poet.song.38000.json','["三徑長籬依斷崖，築堂能向紫溪開。", "案頭日有青精飯，堈面常浮白玉醅。", "坐對雲山飛鳥沒，笑看花木早春回。", "高情不厭城中客，更許時時杖履來。"]'),
('caa12690-27ea-4e25-aba3-42b8e4b7f6b9','貽致政吳德仁朝請','劉摯','宋','宋诗','song-poetry','','[]','四十懸車三十年，白雲山下古溪邊。',64,'全唐诗/poet.song.38000.json','["四十懸車三十年，白雲山下古溪邊。", "松姿鬱鬱霜中壽，鴻意冥冥物外天。", "歸爲田園陶令達，化行鄉黨鄭公賢。", "我慚出處今如此，應得高人一粲然。"]'),
('20c3e48a-58cb-448c-8e37-02bb2ac1fe57','初到蘄州','劉摯','宋','宋诗','song-poetry','','[]','卜築南城三徑開，寛恩容此養衰頽。',64,'全唐诗/poet.song.38000.json','["卜築南城三徑開，寛恩容此養衰頽。", "舟從灔澦堆中出，人是邯鄲道上回。", "憔悴幸非蘭澤去，因緣如爲祖山來。", "江湖本是忘機地，笑許殘年付酒杯。"]'),
('10a312fa-0e1d-4308-bf37-f5d2487bf485','寄鼎州陶使君商翁','劉摯','宋','宋诗','song-poetry','','[]','詩壇曾識舊將軍，新寄長編慰俗塵。',64,'全唐诗/poet.song.38000.json','["詩壇曾識舊將軍，新寄長編慰俗塵。", "夢到鈞天醉聞樂，心疑明月暗投人。", "誰悲正雅全忘古，自是滛哇毎亂真。", "安得高門占旂鼓，與公吟嘯武陵春。"]'),
('38dc15f1-434f-459e-b57d-d7701fbd5365','舟次潯陽寄興國李使君舜卿','劉摯','宋','宋诗','song-poetry','','[]','江南太守畫船飛，湘水羈鴻病翼遲。',64,'全唐诗/poet.song.38000.json','["江南太守畫船飛，湘水羈鴻病翼遲。", "歳晏風霜時易失，人生離合事難期。", "相思坐歎瓊枝隔，寓意徒令玉軫悲。", "遥想翠屏山下望，樓中還有謝公詩。"]'),
('58bf8c95-e4cc-48fa-bdab-dd0572b4dffb','送柳判官引對次鄒主簿韻','劉摯','宋','宋诗','song-poetry','','[]','斯文復古魏郊東，落落名孫祖氣同。',64,'全唐诗/poet.song.38000.json','["斯文復古魏郊東，落落名孫祖氣同。", "待詔方探採蘭舍，最書催見受釐宫。", "十年罇酒瞻燕碣，幾日歌吟笑郢中。", "天下求才君必用，莫悲長劍匣秋風。"]'),
('2b1e03a6-8898-421f-9275-5ba2dce81036','赤岸過柳明之别業','劉摯','宋','宋诗','song-poetry','','[]','主人瀟洒武陵仙，别業河東大道邊。',64,'全唐诗/poet.song.39000.json','["主人瀟洒武陵仙，别業河東大道邊。", "心畫美田皆枕水，手栽佳木已參天。", "園林有地時難者，鐘鼎銘功事莽然。", "倦客過門空大嚼，卜鄰安得買清泉。"]'),
('122aa8f4-93ae-4cda-b0f8-0e5ca67c38e9','青山高竹樓别業昔嘗題詩其壁詩故在而竹樓物故三年矣感而賦詩','劉摯','宋','宋诗','song-poetry','','[]','故人别墅俯青郊，曾許幽人近結茅。',64,'全唐诗/poet.song.39000.json','["故人别墅俯青郊，曾許幽人近結茅。", "苔壁雨荒留舊蹟，竹林雲矗見新梢。", "樓成白玉山無主，鱗出黄金客有肴。", "悵念同游歌楚些，風聲蕭颯鳥咬咬。"]'),
('41589912-21d6-4d6f-a4e8-2b80bfe6ae58','巳日泊桃源亭','劉摯','宋','宋诗','song-poetry','','[]','桃源亭北值佳辰，桃蕚飄殘晼晚春。',64,'全唐诗/poet.song.39000.json','["桃源亭北值佳辰，桃蕚飄殘晼晚春。", "緹幕惜芳林下子，綵袗修禊水邊人。", "風謡漸喜南音變，節物偏于久客新。", "道不與時當勇去，歸心何必計吳蓴。"]'),
('8efd0380-aead-4570-80c0-3dd22b2fa966','病中聞子客被召次中東歸','劉摯','宋','宋诗','song-poetry','','[]','一夜奎星向紫微，朝來黄鵠又東歸。',64,'全唐诗/poet.song.39000.json','["一夜奎星向紫微，朝來黄鵠又東歸。", "謝庭春入新紅藥，吳苑花迎舊繡衣。", "疲馬顧鳴還有戀，驚烏飛匝欲何依。", "無聊病况將離思，併寫孤音白玉徽。"]'),
('e1c2e93f-b447-4a68-908c-a9a18cf4dfdc','再和','劉摯','宋','宋诗','song-poetry','','[]','詩酒相從道久微，東西冠蓋兩將歸。',64,'全唐诗/poet.song.39000.json','["詩酒相從道久微，東西冠蓋兩將歸。", "許公文誥專鴻筆，太白江湖醉錦衣。", "攬轡慨然俱有意，繫匏于此獨無依。", "猶憐謄得河梁句，常與都人記盛徽。"]'),
('bbf59efb-68c2-48c8-8c70-755f2fa9eae6','送鄭毅夫舍人被召五首  其一','劉摯','宋','宋诗','song-poetry','','[]','金魚寶带紫微仙，刺史荆州帝倚賢。',64,'全唐诗/poet.song.39000.json','["金魚寶带紫微仙，刺史荆州帝倚賢。", "仁入刑書無濫獄，政通和氣屢豐年。", "芝函曉下浮雲闕，奎曜宵還北斗天。", "士望區區翰林主，不知舟楫赴商川。"]'),
('27e7f164-163a-4b23-a89d-7dad39b25a0f','送鄭毅夫舍人被召五首  其二','劉摯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','三國遺基楚子宫，洞庭游樂與民同。',64,'全唐诗/poet.song.39000.json','["三國遺基楚子宫，洞庭游樂與民同。", "畫船載酒春波綠，疊鼓隨車夜燭紅。", "愛此南陽歌召父，學如西蜀化文翁。", "去思不用甘棠賦，恩在邦人骨髓中。"]'),
('1bfc04b0-da93-4a74-a40b-1a0b46ff018f','送鄭毅夫舍人被召五首  其三','劉摯','宋','宋诗','song-poetry','','[]','永昭陵上土新乾，又見弓遺四海冤。',64,'全唐诗/poet.song.39000.json','["永昭陵上土新乾，又見弓遺四海冤。", "旒冕嗣天承顧命，金繒傾帑入私門。", "已多困瘠悲邦釁，况有跳梁玩國恩。", "歸奉清閑疏奇藴，席前應講太平源。"]'),
('ae5b02d7-a99d-4e0e-a8f1-228d66a189a2','送鄭毅夫舍人被召五首  其四','劉摯','宋','宋诗','song-poetry','','[]','旌旗占曉動星躔，冠蓋傾都海嶽旋。',64,'全唐诗/poet.song.39000.json','["旌旗占曉動星躔，冠蓋傾都海嶽旋。", "歸覲明堂瞻日表，過家鄖社卜松阡。", "郢山殘雪梅寒後，漢水東風柳暖天。", "無限春風入佳句，何時珠玉看盈編。"]'),
('beec4af4-205f-4951-abd6-887071811e26','送鄭毅夫舍人被召五首  其五','劉摯','宋','宋诗','song-poetry','','[]','簪紱忘懷出處均，行行猶眷楚都春。',64,'全唐诗/poet.song.39000.json','["簪紱忘懷出處均，行行猶眷楚都春。", "嗣皇小毖方求助，太守三公古重民。", "燕厦久依王粲幕，鶚書曾愧孔融賓。", "士儒以義酬知己，敢向東原涕滿巾。"]'),
('f435731b-f2f9-4992-a950-81b4ffd3d8d4','九日病起寄文瑩','劉摯','宋','宋诗','song-poetry','','[]','春城别去已秋窮，猶喜音書繼遞筒。',64,'全唐诗/poet.song.39000.json','["春城别去已秋窮，猶喜音書繼遞筒。", "身外光陰一飛隼，天南蹤迹兩飄蓬。", "夜烏三匝驚明月，胡馬長嘶向北風。", "無酒無人更無菊，重陽愁過鹿皮翁。"]'),
('c00b1b14-b3a9-4ad5-b3cf-d05ecfc86780','春日書事','劉摯','宋','宋诗','song-poetry','','[]','年華歡緒兩蹉跎，颺白浮紅日日多。',64,'全唐诗/poet.song.39000.json','["年華歡緒兩蹉跎，颺白浮紅日日多。", "酒怯病懷無舊戶，睡便春晝長新魔。", "些思楚客招魂語，噫笑梁生憤世歌。", "鳥雀相忘來亦少，不須門外更張羅。"]'),
('af17969f-7463-49d5-8cdc-59ced0fabf09','跂罷西邑時將營山居路有二詩次其韻  其一','劉摯','宋','宋诗','song-poetry','','[]','半年西邑秪徒勞，天數人謀兩不饒。',64,'全唐诗/poet.song.39000.json','["半年西邑秪徒勞，天數人謀兩不饒。", "分定一枝難駐足，時來三組併垂腰。", "是非未了今猶古，飲啄誠安谷亦喬。", "何日一塵能負郭，杖藜春雨看眷苗。"]'),
('1440bed3-4d35-4f7f-827f-53593bfbe762','跂罷西邑時將營山居路有二詩次其韻  其二','劉摯','宋','宋诗','song-poetry','','[]','求田問舍此心勞，兩處如聞勝勢饒。',64,'全唐诗/poet.song.39000.json','["求田問舍此心勞，兩處如聞勝勢饒。", "張氏泉塍近城角，邵家林屋在山腰。", "倒冠來伴樊川杜，飛舄新閑葉縣喬。", "昨日雪霜枯槁地，百般蒼翠發新苗。"]'),
('f9a52aeb-08ab-4252-af86-4fd3909b1ee7','孫少卿鹿頭山詩并畫圖二首  其一','劉摰','宋','宋诗','song-poetry','','[]','誅茅搜險旋尋真，聞說山巖一日新。',64,'全唐诗/poet.song.39000.json','["誅茅搜險旋尋真，聞說山巖一日新。", "佳境留連應有待，先時登覽豈無人。", "披榛好石來如召，隨手清泉應若神。", "不獨山中興勝事，幾多風愛在邦民。"]'),
('6469d421-4b47-42a0-9d96-e125a671fb6e','孫少卿鹿頭山詩并畫圖二首  其二','劉摰','宋','宋诗','song-poetry','','[]','使君鎮爱鹿頭山，圖畫歌吟共爲傳。',64,'全唐诗/poet.song.39000.json','["使君鎮爱鹿頭山，圖畫歌吟共爲傳。", "塵世那知武陵事，時人爭誦永嘉篇。", "行春遊醉常勞夢，按部登臨又隔年。", "有客平生志林壑，坐憐雙眼隔雲煙。"]'),
('0410a707-5ef9-4410-8a94-cadb23e684b9','次韻蔡景繁紅梅三首  其一','劉摰','宋','宋诗','song-poetry','','[]','故人江驛寄瑶華，紫玉枝頭散嫩霞。',64,'全唐诗/poet.song.39000.json','["故人江驛寄瑶華，紫玉枝頭散嫩霞。", "日暗露桃春尚淺，醉餘收面粉難遮。", "綠溪地静東風遇，雕檻香寒曉月斜。", "水滿琉璃聊自喜，不堪塵眼秖空花。"]'),
('4dc4c7d3-da07-470c-ae7f-02bb47e6217e','次韻蔡景繁紅梅三首  其二','劉摰','宋','宋诗','song-poetry','','[]','蕭疏仙梗擢芳華，巧刻圓瓊傅淡霞。',64,'全唐诗/poet.song.39000.json','["蕭疏仙梗擢芳華，巧刻圓瓊傅淡霞。", "素質本非桃杏質，酡顔聊避雪霜遮。", "香含暮雨欄邊散，豔倚春風鬢上斜。", "聞說樽前偏屬黨，青黄朱粉更無花。"]'),
('43e24cb1-2b0b-4e50-ace2-c66bec69e8bf','次韻蔡景繁紅梅三首  其三','劉摰','宋','宋诗','song-poetry','','[]','仙圃瑶林冠物華，靚英明媚洗晴霞。',64,'全唐诗/poet.song.39000.json','["仙圃瑶林冠物華，靚英明媚洗晴霞。", "醉装卻費臙脂暈，紈扇應煩絳粉遮。", "天上念奴春睡足，風前飛燕舞容斜。", "後房宜勸歌聲小，惜愛今年第一花。"]'),
('b5b56f34-b645-4184-9f0b-b0a576a13ec6','再次紅梅','劉摰','宋','宋诗','song-poetry','','[]','色不夭穠始是華，仙家林觀倚雲霞。',64,'全唐诗/poet.song.39000.json','["色不夭穠始是華，仙家林觀倚雲霞。", "春酣白玉醅香入，日射紅鸞扇影遮。", "攅蕚亂鬚能淡佇，抱枝寒蓓更疏斜。", "爲寄瑶林主人語，爭妍應有曲房花。"]'),
('c21b00da-c928-44de-ba32-2e1180c08904','庭前有古槐一株枝葉扶疏廣蔭一畝每當月夕風晨輒爲婆娑其下空翠滴衣心神清越感秋寄興情見乎詞','劉摰','宋','宋诗','song-poetry','','[]','綠玉交柯蔽鬱深，碧蘿寒幄静沈沈。',64,'全唐诗/poet.song.39000.json','["綠玉交柯蔽鬱深，碧蘿寒幄静沈沈。", "最宜初旭晞晴靄，時有珍禽宅翠陰。", "終日對爲佳客伴，幾年相慰故谿心。", "主人已有秋風興，更聽疏蟬抱葉吟。"]'),
('6f6468b5-2539-4414-96b1-757bd43e928b','盆中移白菊','劉摰','宋','宋诗','song-poetry','','[]','九秋風露下星榆，玉刻圓錢散曉株。',64,'全唐诗/poet.song.39000.json','["九秋風露下星榆，玉刻圓錢散曉株。", "人住水涯多白髪，地應花谷近清都。", "按香清酒登新譜，益氣輕身載舊圖。", "移取黄堂朝夕見，北洲亭遠故臺蕪。"]'),
('e3cab862-2656-47cf-9d92-a75b364d1a8b','次南陽錢紫微白菊','劉摰','宋','宋诗','song-poetry','','[]','清根靈氣本仙通，白玉葩華綠玉叢。',64,'全唐诗/poet.song.39000.json','["清根靈氣本仙通，白玉葩華綠玉叢。", "山遠莫尋幽谷水，洲香聊近百花叢。", "神寒縹緲梅同格，英出繁多雪愧工。", "籬下區區醉金蘂，酈卿應笑鹿皮翁。"]'),
('faf4fcf4-7336-42c7-812c-ba2b71f275b8','次韻傅推官宏月菊','劉摰','宋','宋诗','song-poetry','','[]','應憐陶令爱東籬，分付黄花特地遲。',64,'全唐诗/poet.song.39000.json','["應憐陶令爱東籬，分付黄花特地遲。", "百卉浪隨秋色盡，孤芳自與歲寒期。", "冷香直欲梅相鬭，金蘂懸知雪更宜。", "空使詩人詠重九，天公造物本無時。"]'),
('26026d05-09bb-4084-a6ef-a4f1579a5f0d','輓慈聖光獻皇后二首  其一','劉摰','宋','宋诗','song-poetry','','[]','翼子詒孫廟社功，憂勞嘉祐治平中。',64,'全唐诗/poet.song.39000.json','["翼子詒孫廟社功，憂勞嘉祐治平中。", "澤流自配皇圖遠，仙去誰期壽劫空。", "三獻奄違長信殿，萬靈神會永昭宫。", "母儀五十年間事，愁入西郊鼓吹風。"]'),
('e6cddafa-e1a0-413a-9f99-e49f66e4f356','輓慈聖光獻皇后二首  其二','劉摰','宋','宋诗','song-poetry','','[]','孝孫皇帝念終天，毁慕難留王座遷。',64,'全唐诗/poet.song.39000.json','["孝孫皇帝念終天，毁慕難留王座遷。", "廟謚易名尊四字，宸闈行服自三年。", "寶衣鸞鳯藏華殿，哀仗星辰下洛川。", "從此都人想遊幸，無因重見九龍軿。"]'),
('20ba19f6-4a5a-4407-a583-ad3905dd63ea','輓資政殿學士吏部尚書曾公二首  其一','劉摰','宋','宋诗','song-poetry','','[]','懷詔歸來望九霄，伾山纔隔渡河橋。',64,'全唐诗/poet.song.39000.json','["懷詔歸來望九霄，伾山纔隔渡河橋。", "履聲未徹君王聽，車左俄悲道路招。", "韋氏詩書傳秘閣，石家孝謹冠中朝。", "靈輀聞說都門過，愁徹西風鼓吹簫。"]'),
('6dda46d1-2e26-449e-bb90-b25fe5b10fd6','輓資政殿學士吏部尚書曾公二首  其二','劉摰','宋','宋诗','song-poetry','','[]','百歲悲歡俯仰間，訃驚疇昔涕汍瀾。',64,'全唐诗/poet.song.39000.json','["百歲悲歡俯仰間，訃驚疇昔涕汍瀾。", "玉堂天聖傳先契，蘭省元豐事長官。", "寂寂塵音華屋閉，蕭蕭雲木故山寒。", "深心令德今何愧，付與無窮後世看。"]'),
('0414ff2d-a9e4-4bb5-a0b3-e49dc8460346','輓宋次道二首  其一','劉摰','宋','宋诗','song-poetry','','[]','橐筆周旋侍漢宫，慱知前載問無窮。',64,'全唐诗/poet.song.39000.json','["橐筆周旋侍漢宫，慱知前載問無窮。", "朝廷人物儒林丈，家世文章太史公。", "俯仰頓驚華屋換，聲容徒望繐帷空。", "寝門一哭何嗟及，付與悲哀挽鐸風。"]'),
('0c76fa69-203a-4550-beff-27785fdf3ce8','輓宋次道二首  其二','劉摰','宋','宋诗','song-poetry','','[]','平生襟尚苦清通，白首耽心翰墨中。',64,'全唐诗/poet.song.39000.json','["平生襟尚苦清通，白首耽心翰墨中。", "萬卷囊書推沈氏，一時碑字貴顔公。", "塵栖村館稀賓至，山抱佳城與祖同。", "已矣善人那復見，蕭蕭溱洧秖秋風。"]'),
('ef86a360-fdef-46e5-8b26-144eb9d75941','哀吕西臺行父四首  其一','劉摰','宋','宋诗','song-poetry','','[]','大夫門户斗魁旁，落落南宫舊望郎。',64,'全唐诗/poet.song.39000.json','["大夫門户斗魁旁，落落南宫舊望郎。", "收歛壮心書萬卷，沈浮高興酒千觴。", "乘驄始欲新年去，藏壑俄驚半夜亡。", "索我贈言曾未暇，哀懷今變紼塵章。"]'),
('58255e6a-602b-41aa-a0ff-1341e5745636','哀吕西臺行父四首  其二','劉摰','宋','宋诗','song-poetry','','[]','仙骨蕭疏古柏秋，合于塵世獨悠悠。',64,'全唐诗/poet.song.39000.json','["仙骨蕭疏古柏秋，合于塵世獨悠悠。", "人間未熟黄粱飯，天上新成白玉樓。", "隱几不聞遺治命，飛旌何日向西州。", "識君惟有崔夫子，預說衣冠一蜕留。"]'),
('0f8f2648-926f-4038-a5dd-f0a31612af68','哀吕西臺行父四首  其三','劉摰','宋','宋诗','song-poetry','','[]','前月南河欲放船，壺觴一夕暫盤桓。',64,'全唐诗/poet.song.39000.json','["前月南河欲放船，壺觴一夕暫盤桓。", "吐霏珠玉音猶在，風折篔簹墨未乾。", "皎皎不應隨物轉，滔滔從此締交難。", "孤懷幽調誰知者，寂寞金徽不復弹。"]'),
('94a6c8c1-8265-48bf-8a92-e5135755992c','哀吕西臺行父四首  其四','劉摰','宋','宋诗','song-poetry','','[]','吳興空望使君車，道厄陳州亦命歟。',64,'全唐诗/poet.song.39000.json','["吳興空望使君車，道厄陳州亦命歟。", "歸路自爲兜率去，遺忠誰訪茂陵書。", "粃糠世俗心無累，蘭玉階庭善有餘。", "一束生芻猶未至，春風洒涙滿襟裾。"]'),
('81c8d8f3-88da-411d-8ff3-174b59fac82e','次韻唐誦植椶櫚三絕句  其一','劉摰','宋','宋诗','song-poetry','','[]','亭亭員榦直，翦翦翠輪齊。',24,'全唐诗/poet.song.39000.json','["亭亭員榦直，翦翦翠輪齊。", "葉散夜叉様，惡名誰品題。"]'),
('13351483-776d-4f01-a363-4fd093a6d6f8','次韻唐誦植椶櫚三絕句  其二','劉摰','宋','宋诗','song-poetry','','[]','榮悴逐時序，紛紛紅翠多。',24,'全唐诗/poet.song.39000.json','["榮悴逐時序，紛紛紅翠多。", "誰同歲寒操，旁有羽林戈。"]'),
('fd4b5af9-df45-457d-82de-2bfe723238fc','次韻唐誦植椶櫚三絕句  其三','劉摰','宋','宋诗','song-poetry','','[]','種蘭不當户，李以苦見容。',24,'全唐诗/poet.song.39000.json','["種蘭不當户，李以苦見容。", "珍重主人意，東亭非要沖。"]'),
('b25ec3e2-86e1-49d8-b1c1-34f3e70451a3','次長守長歷兩孫自汶寄讀詩韻  其一','劉摰','宋','宋诗','song-poetry','','[]','阿守似其父，丰姿仍秀疏。',24,'全唐诗/poet.song.39000.json','["阿守似其父，丰姿仍秀疏。", "别翁猶數月，書驛且渠渠。"]'),
('b4844317-dac3-418c-a664-4e340af184e3','次長守長歷兩孫自汶寄讀詩韻  其二','劉摰','宋','宋诗','song-poetry','','[]','歷也駒千里，新詩慰遠思。',24,'全唐诗/poet.song.39000.json','["歷也駒千里，新詩慰遠思。", "霜秋魚酒美，來趁壽觴時。"]'),
('7ca6516d-66ab-43b1-94a5-bcfe72c22777','戲簡許敎授','劉摰','宋','宋诗','song-poetry','','[]','雖有董鹽甘寂寞，如聞顔粥更艱辛。',32,'全唐诗/poet.song.39000.json','["雖有董鹽甘寂寞，如聞顔粥更艱辛。", "莫将秉釡論多少，聊爲君家拂甑塵。"]'),
('b1ed0a95-715e-4569-af69-aa1764eec80b','馬融絳帳臺','劉摰','宋','宋诗','song-poetry','','[]','漢守曾爲絳帳師，升堂高弟許摳衣。',32,'全唐诗/poet.song.39000.json','["漢守曾爲絳帳師，升堂高弟許摳衣。", "傳經無復當時事，只有沙禽自在飛。"]'),
('25d2b09e-83fa-404a-b273-4d64412f6919','國風亭','劉摰','宋','宋诗','song-poetry','','[]','地靈真合有清辭，正在中和樂職時。',32,'全唐诗/poet.song.39000.json','["地靈真合有清辭，正在中和樂職時。", "誰道諸詩吟不盡，試看亭上國風詩。"]'),
('fa0bb4c8-7214-4327-8416-ab6c80372570','復古亭','劉摰','宋','宋诗','song-poetry','','[]','功大文雄歲月深，巍然高碣字生金。',32,'全唐诗/poet.song.39000.json','["功大文雄歲月深，巍然高碣字生金。", "臺池得與吾民共，誰識邦家復古心。"]'),
('ac4a9d52-3e19-4e1f-872e-aa246cb793a6','穿楊亭','劉摰','宋','宋诗','song-poetry','','[]','華構翬飛一望中，顔間篆墨颺秋風。',32,'全唐诗/poet.song.39000.json','["華構翬飛一望中，顔間篆墨颺秋風。", "休矜百步穿楊巧，未及當年射虎功。"]'),
('7b6e90a1-60b3-4d6b-8a60-770df50fdc2d','迎春亭','劉摰','宋','宋诗','song-poetry','','[]','亭接東風近曉霞，幾多和氣到萌芽。',32,'全唐诗/poet.song.39000.json','["亭接東風近曉霞，幾多和氣到萌芽。", "也知當日迎春意，不爲松筠只爲花。"]'),
