('4a88430b-4b24-481c-89e7-37dc2cc9714a','予嘉祐中嘗迎先妣來主臨潼元祐丁卯□月赴守遂寧複過是邑凡山林宮寺之勝皆當日奉板輿盍朋簪歲時遊息之處到今二十八年矣因成短詩以敘感慨','李梃','宋','宋诗','song-poetry','','[]','淒涼感舊與懷親，時事居人觸目新。',32,'全唐诗/poet.song.39000.json','["淒涼感舊與懷親，時事居人觸目新。", "獨有溫泉故情在，猶能爲我洗紅塵。"]'),
('abaffa29-72d7-4228-8283-4d11774094c2','挈家登朝元閣晚由東山北下自石甕過朝元山路並斯飛亭皆當日親爲開置今複經從因留拙句','李梃','宋','宋诗','song-poetry','','[]','一別驪山歲已深，林花依舊繡蒼岑。',32,'全唐诗/poet.song.39000.json','["一別驪山歲已深，林花依舊繡蒼岑。", "歸尋當日新開路，隱約苔痕下翠陰。"]'),
('7da37595-a5c1-498d-a2f9-16c32d65408c','題靈泉觀','李梃','宋','宋诗','song-poetry','','[]','山原繚繞水縈紆，繡嶺屏風立座隅。',32,'全唐诗/poet.song.39000.json','["山原繚繞水縈紆，繡嶺屏風立座隅。", "更上朝元最高處，饒君都看渭川圖。"]'),
('03506f8e-a812-467c-870c-3e7dc56bd8bb','贈關淵聖學士','孔夷','宋','宋诗','song-poetry','','[]','吳越聲飛二十年，緇衣空復歎遺編。',64,'全唐诗/poet.song.39000.json','["吳越聲飛二十年，緇衣空復歎遺編。", "紫芝眉宇風塵外，太白文章錦繡前。", "可是石渠方載筆，未應水國要歸田。", "他時雪裏相逢處，能記騎驢孟浩然。"]'),
('948dd094-cb6d-426e-9edf-7593cc64f78c','陪李端叔游穎昌西湖三首  其一','孔夷','宋','宋诗','song-poetry','','["\u897f\u6e56"]','霜風吹老菊離離，水外秋雲送雁飛。',32,'全唐诗/poet.song.39000.json','["霜風吹老菊離離，水外秋雲送雁飛。", "來伴謫仙閑杖腰，滿林丹葉襯斜暉。"]'),
('c0f23363-a5ac-4051-a15d-efb170887712','陪李端叔游穎昌西湖三首  其二','孔夷','宋','宋诗','song-poetry','','["\u897f\u6e56"]','樓影搖波到碧空，拒霜無數隔堤紅。',32,'全唐诗/poet.song.39000.json','["樓影搖波到碧空，拒霜無數隔堤紅。", "只應明夜關山月，憐我相思不寐中。"]'),
('31b99634-c5f7-4850-8079-77cf3bbf342e','陪李端叔游穎昌西湖三首  其三','孔夷','宋','宋诗','song-poetry','','["\u897f\u6e56"]','與世相疏行路難，不禁塵土便思山。',32,'全唐诗/poet.song.39000.json','["與世相疏行路難，不禁塵土便思山。", "山中獨念故人遠，雪舞清聲窗竹閑。"]'),
('89708557-3528-4989-91a0-f96e41fb60ca','寄高郵王定國','孔夷','宋','宋诗','song-poetry','','[]','世路難行肯效尤，蒲萄斗酒換涼州。',64,'全唐诗/poet.song.39000.json','["世路難行肯效尤，蒲萄斗酒換涼州。", "春風不到仲文樹，野水猶沈夢得舟。", "珍重故家青玉案，徜徉鄉社翠雲裘。", "淮南十里鶯花老，月照關山笛裏愁。"]'),
('9f569460-a082-48e0-9432-0c9829985704','句  其一','孔夷','宋','宋诗','song-poetry','','[]','微雨鷺翹艇，夕陽人倚樓。',12,'全唐诗/poet.song.39000.json','["微雨鷺翹艇，夕陽人倚樓。"]'),
('090fd9e4-7e99-47dd-acc3-9de5ae740d6d','句  其二','孔夷','宋','宋诗','song-poetry','','[]','雨晴梨花春有光。',8,'全唐诗/poet.song.39000.json','["雨晴梨花春有光。"]'),
('c15d3634-be14-44e3-b75c-fc2f96131b7b','句  其三','孔夷','宋','宋诗','song-poetry','','[]','砌下梨花一堆雪。',8,'全唐诗/poet.song.39000.json','["砌下梨花一堆雪。"]'),
('beebd5b8-9178-4791-8461-21d9dcb1d2a6','句  其四','孔夷','宋','宋诗','song-poetry','','[]','楊柳不遮春已斷，一枝紅杏出牆頭。',16,'全唐诗/poet.song.39000.json','["楊柳不遮春已斷，一枝紅杏出牆頭。"]'),
('340d7919-12f1-405d-a926-3c5ef607e5cd','曾點','呂大鈞','宋','宋诗','song-poetry','','[]','函丈從容問且酬，展才無不至諸侯。',32,'全唐诗/poet.song.39000.json','["函丈從容問且酬，展才無不至諸侯。", "可憐曾點推嗚瑟，獨對春風詠不休。"]'),
('a9039608-08ca-408b-b7ef-00ff0ad6286f','曾公巖和曾子宣安撫','苗時中','宋','宋诗','song-poetry','','[]','紅旆尋幽東郭旁，泉巖新得冠殊方。',64,'全唐诗/poet.song.39000.json','["紅旆尋幽東郭旁，泉巖新得冠殊方。", "一川氣象天開作，萬古荆榛地蔽藏。", "崖穴乍驚堂室闢，榜名知與日星長。", "異時人指溪橋水，思愛還同召伯棠。"]'),
('db19c6ed-919a-4e96-8e28-34a5eb4a68cb','洪山','韓晉卿','宋','宋诗','song-poetry','','[]','壁立東南第一峰，問名知是葛仙翁。',64,'全唐诗/poet.song.39000.json','["壁立東南第一峰，問名知是葛仙翁。", "丹砂竈逼雲頭近，玉井泉流海眼通。", "六字籀文天篆刻，鼓間洞室石帡幪。", "我來整屐層巒上，無數群峰立下風。"]'),
('3d2ab62b-c6c2-4c2e-bb7f-f00c0dbb0253','句','家定國','宋','宋诗','song-poetry','','[]','桃李從花王。',6,'全唐诗/poet.song.39000.json','["桃李從花王。"]'),
('c8e3c772-664d-409b-ac27-11bf8b10ddec','句','家氏客','宋','宋诗','song-poetry','','[]','笙歌陪酒聖。',6,'全唐诗/poet.song.39000.json','["笙歌陪酒聖。"]'),
('a8ab7cab-638f-49aa-b09a-640da4430668','句','鄭雍','宋','宋诗','song-poetry','','[]','訪古直尋齊守事，誦詩還愛紫微才。',16,'全唐诗/poet.song.39000.json','["訪古直尋齊守事，誦詩還愛紫微才。"]'),
('3dba3e9b-cfe0-4525-9ee7-51f31f3436cd','換蘇印和弟穎叔  其一','蔣之翰','宋','宋诗','song-poetry','','[]','恥向承平便拂衣，鄉邦還得擁旌麾。',64,'全唐诗/poet.song.39000.json','["恥向承平便拂衣，鄉邦還得擁旌麾。", "昔年曾預兒孫列，投老猶疑筆硯隨。", "忠義一門均許國，箕裘萬石亦遭時。", "朝廷虛日方圓任，功業當看帝載熙。"]'),
('b8bb0502-e26f-4e00-8fb3-18c52262d960','換蘇印和弟穎叔  其二','蔣之翰','宋','宋诗','song-poetry','','[]','從來疏拙懶身謀，攬轡登車已倦遊。',32,'全唐诗/poet.song.39000.json','["從來疏拙懶身謀，攬轡登車已倦遊。", "幸有醉鄉爲樂地，何妨吟嘯老東州。"]'),
('47957bf1-29a2-49e3-b1ce-fc0a5b0bb9bb','海州觀放鶻搏兔不中而飛去','沈括','宋','宋诗','song-poetry','','[]','秋霜濯空林，暮日在峰頂。',72,'全唐诗/poet.song.39000.json','["秋霜濯空林，暮日在峰頂。", "冥冥起長風，稍稍絕遺影。", "驍禽值猛搏，俯取不待頃。", "豈非求者乖，矯翮成遠聘、未能謝榛莽，那用遽悼悻。", "此心竟可憐，得失未宜病。"]'),
('1d4e8055-d634-48ec-9d03-0ba66523ee6a','姑熟溪  其一','沈括','宋','宋诗','song-poetry','','[]','新晴渡口百花香，石子池頭鴨弄黄。',32,'全唐诗/poet.song.39000.json','["新晴渡口百花香，石子池頭鴨弄黄。", "卷幔夕陽留不住，好風將雨過梅塘。"]'),
('590019fb-db64-4ac7-bb88-656131a53f0b','姑熟溪  其二','沈括','宋','宋诗','song-poetry','','[]','豹堂春水綠泱渙，謝市雲深柳線長。',32,'全唐诗/poet.song.39000.json','["豹堂春水綠泱渙，謝市雲深柳線長。", "睡熟不知潮信過，船頭晚雨打菰蔣。"]'),
('6651b78b-a520-4974-8395-469776985e49','慈姥磯  其一','沈括','宋','宋诗','song-poetry','','[]','碧山叢叢遮塔暉，蒼崖萬丈涵蒼漪。',32,'全唐诗/poet.song.39000.json','["碧山叢叢遮塔暉，蒼崖萬丈涵蒼漪。", "西風隔江動高樹，山前過帆如鳥飛。"]'),
('1f4fe650-3167-44bf-ac6c-01d7c87d1bf4','慈姥磯  其二','沈括','宋','宋诗','song-poetry','','[]','朝發銅陵暮揚子，年年白浪江中歸。',32,'全唐诗/poet.song.39000.json','["朝發銅陵暮揚子，年年白浪江中歸。", "江人收身苦宜早，一生卻向江中老。"]'),
('4d0a59c0-88e2-4567-8477-79c829f245f6','江南曲','沈括','宋','宋诗','song-poetry','','[]','新秋拂水無行跡，夜夜隨潮過江北。',80,'全唐诗/poet.song.39000.json','["新秋拂水無行跡，夜夜隨潮過江北。", "西風卷雨上半天，渡口微涼含晚碧。", "城頭鼓響日腳垂，天際籠煙鎖山色。", "高樓索莫臨長陌，黄竹一聲無北客。", "時平田苦少人耕，唯有蘆花滿江白。"]'),
('ddb385d5-8f13-4cad-aaf4-d14b1ae6ae42','峨眉亭','沈括','宋','宋诗','song-poetry','','[]','雙峰秀出兩眉彎，翠黛依然監影間。',32,'全唐诗/poet.song.39000.json','["雙峰秀出兩眉彎，翠黛依然監影間。", "終日含顰緣底事，祗應長對望夫山。"]'),
('efbd37a2-2def-4662-931d-6f58943b8432','承天觀','沈括','宋','宋诗','song-poetry','','[]','上士修真地，曾無俗混淆。',48,'全唐诗/poet.song.39000.json','["上士修真地，曾無俗混淆。", "雲根起壇級，江面出松梢。", "軒靜簷垂斗，窗虛洞接茅。", "何當脫塵滓，來結皎然交。"]'),
('0651f202-5634-4a8b-92f1-e038713f11ca','鞦韆','沈括','宋','宋诗','song-poetry','','[]','香入熏爐禁火天，芙蓉深苑鬬秋千。',32,'全唐诗/poet.song.39000.json','["香入熏爐禁火天，芙蓉深苑鬬秋千。", "身輕幾欲隨風去，卻恨恩深不得仙。"]'),
('f2605868-a472-43b8-9b19-f78bd35fb122','雨中過臨平湖','沈括','宋','宋诗','song-poetry','','[]','綠蒲淺水清回環，浪頭雨急聲珊珊。',64,'全唐诗/poet.song.39000.json','["綠蒲淺水清回環，浪頭雨急聲珊珊。", "畫橈驚起遠近雁，宿靄欲亂高低山。", "敗蓬半漏野更好，短纜數斷遲轉間。", "谿翁此日乘浩渺，搔首坐哨煙雲間。"]'),
('7d39b326-e11a-4c8b-b5b2-f0d884afc886','釣臺','沈括','宋','宋诗','song-poetry','','[]','漁釣非良業，相期逐姓名。',48,'全唐诗/poet.song.39000.json','["漁釣非良業，相期逐姓名。", "太平雖不仕，故舊豈無情。", "七里林泉好，三公位貌輕。", "片帆湍石下，誰不仰先生。"]'),
('e5f3a4e8-7247-43d4-ae51-c2952b13179e','仙都山','沈括','宋','宋诗','song-poetry','','[]','苔封輦路上青山，鶴馭遼天去不還。',32,'全唐诗/poet.song.39000.json','["苔封輦路上青山，鶴馭遼天去不還。", "惟有銀河秋月夜，鼎湖煙浪到人間。"]'),
('46cfa164-088f-4573-855c-417e290fbc89','贈天台沖寂道人','沈括','宋','宋诗','song-poetry','','[]','聞說能文山閣老，比年幽興著林泉。',64,'全唐诗/poet.song.39000.json','["聞說能文山閣老，比年幽興著林泉。", "自開鹿苑知何門，不向虎溪今十年。", "寥寥清言坐中士，皎皎寒月山間天。", "不堪世俗看支遁，曾有篇章憶惠連。"]'),
('438a96db-e148-4e02-80b5-478dd9624dc5','十松亭','沈括','宋','宋诗','song-poetry','','[]','空堂無人日長哦，風松助我澗雲和。',64,'全唐诗/poet.song.39000.json','["空堂無人日長哦，風松助我澗雲和。", "蒼顔古木喜相似，愛子亦有淩雲柯。", "歡然相對默終日，意得那須言強多。", "我身未得從心老，嗟爾繫此成蹉跎。"]'),
('1d0a7de4-5fd3-41f2-a47f-98c9839fc8ee','遊山門','沈括','宋','宋诗','song-poetry','','[]','溪水激激山攢攢，蒼崖腹封壁四環。',192,'全唐诗/poet.song.39000.json','["溪水激激山攢攢，蒼崖腹封壁四環。", "一門中嚂俯驚瀾，造物爲此良有源。", "坡顛竅塞淪九淵，吐吞龍螭殆非然。", "又疑猛將血戰還，斬此欲守規爲門。", "至今慘惻風夜寒，殺氣襲水爲屈盤。", "山重地僻道路偏，此境安得與禍連。", "反復不得意所安，將必有理愧莫原。", "山川幽深適素尚，轍蹂萬堅窮躋騫。", "生平所更了可記，怪特若此殆未觀。", "崆峒地首久茫昧，自此稍欲信所傳。", "排雲徑上淩巀薛，力弱盛恐乘以蹎。", "西光戛戛下巖壑，取酒更爲山留連。"]'),
('969d6f73-fbf5-4d28-a955-578a11314b08','開元樂詞  其一','沈括','宋','宋诗','song-poetry','','[]','鸛鵲樓頭日暖，蓬萊殿裏花香。',28,'全唐诗/poet.song.39000.json','["鸛鵲樓頭日暖，蓬萊殿裏花香。", "草綠煙迷步輦，天高日近龍床。"]'),
('4c6a56c9-8c09-420d-b25e-6a6ee92bd9b3','開元樂詞  其二','沈括','宋','宋诗','song-poetry','','[]','樓上正臨宮外，人間不見仙家。',28,'全唐诗/poet.song.39000.json','["樓上正臨宮外，人間不見仙家。", "寒食輕煙薄霧，滿城明月梨花。"]'),
('4fc95705-a831-40ac-b898-d22f925aeee4','開元樂詞  其三','沈括','宋','宋诗','song-poetry','','[]','按舞驪山影裏，回鑾渭水光中。',28,'全唐诗/poet.song.39000.json','["按舞驪山影裏，回鑾渭水光中。", "玉笛一天明月，翠華滿陌東風。"]'),
('31964404-d582-4232-ac33-39b0ff8796d8','開元樂詞  其四','沈括','宋','宋诗','song-poetry','','[]','殿後春旗簇仗，樓前御隊穿花。',28,'全唐诗/poet.song.39000.json','["殿後春旗簇仗，樓前御隊穿花。", "一片紅雲鬧處，外人遙認官家。"]'),
('5400fa5f-1e22-4799-95a5-5d0a4f6c7fd5','延州柳湖  其一','沈括','宋','宋诗','song-poetry','','[]','蕭灑征西府，青林隱萬家。',48,'全唐诗/poet.song.39000.json','["蕭灑征西府，青林隱萬家。", "樓高先見月，山近不藏花。", "雨急喧流水，溪深噪亂鴉。", "笙歌乘酒興，可復問天涯。"]'),
('b9b05176-de36-4354-8185-6bf4970700ce','延州柳湖  其二','沈括','宋','宋诗','song-poetry','','[]','漢使雕陰道，秦關白翟宮。',48,'全唐诗/poet.song.39000.json','["漢使雕陰道，秦關白翟宮。", "山川紅旆裏，日明翠微中。", "社後寒猶峭，春殘草木濃。", "花前江國興，併覺此時同。"]'),
('4b749a4c-587f-4662-adf3-5167af5dfe56','延州柳湖  其三','沈括','宋','宋诗','song-poetry','','[]','日暖閑園草半薰，不堪春興蝶紛紛。',64,'全唐诗/poet.song.39000.json','["日暖閑園草半薰，不堪春興蝶紛紛。", "山煙夢鬆成微雨，關月簾纖出斷雲。", "三弄倚樓喧晚操，六花分隊駐新軍。", "終年不見江淮信，吟向胡笳永夜聞。"]'),
('8b0b0cdc-caa1-493f-ad68-acdfcab0477d','鄜延凱歌  其一','沈括','宋','宋诗','song-poetry','','[]','先取山西十二州，別分牙將打衙頭。',32,'全唐诗/poet.song.39000.json','["先取山西十二州，別分牙將打衙頭。", "回看秦塞低如馬，漸見黄河直北流。"]'),
('f9f9330c-bbf0-4c20-82ec-dd9cd8f22079','鄜延凱歌  其二','沈括','宋','宋诗','song-poetry','','[]','天威略地過黄河，萬里羌人盡漢歌。',32,'全唐诗/poet.song.39000.json','["天威略地過黄河，萬里羌人盡漢歌。", "莫堰橫山倒流水，從教西去作恩波。"]'),
('f88bb7e6-197c-4311-a296-cc216bae1c17','鄜延凱歌  其三','沈括','宋','宋诗','song-poetry','','[]','馬尾胡琴隨漢車，曲聲猶自怨單于。',32,'全唐诗/poet.song.39000.json','["馬尾胡琴隨漢車，曲聲猶自怨單于。", "彎弓莫射雲中雁，歸雁如今不寄書。"]'),
('9d05bfa8-40b1-4f3b-8be6-f9ada6919766','鄜延凱歌  其四','沈括','宋','宋诗','song-poetry','','[]','靈武西涼不用圍，番家總待納王師。',32,'全唐诗/poet.song.39000.json','["靈武西涼不用圍，番家總待納王師。", "城中半是關西種，猶有當時軋喫兒。"]'),
('049ff579-ca33-4ef1-9be7-05ef94d2b5c3','鄜延凱歌  其五','沈括','宋','宋诗','song-poetry','','[]','旗隊渾如錦繡堆，銀裝劍背打回回。',32,'全唐诗/poet.song.39000.json','["旗隊渾如錦繡堆，銀裝劍背打回回。", "先教淨掃安西路，待向河源飲馬來。"]'),
('7b11c303-334b-4c56-86b1-4b9743df357f','二郎山','沈括','宋','宋诗','song-poetry','','[]','二郎山下雪紛紛，旋卓穹廬學塞人。',32,'全唐诗/poet.song.39000.json','["二郎山下雪紛紛，旋卓穹廬學塞人。", "化盡素衣冬末老，石煙多似洛陽塵。"]'),
('a7a15797-7758-4200-ad0b-8b442d9cce3b','光化道中遇雨','沈括','宋','宋诗','song-poetry','','[]','望遠初翻葉，隨風已結陰。',48,'全唐诗/poet.song.39000.json','["望遠初翻葉，隨風已結陰。", "雨蓬宜倦枕，鄉夢入寒衾。", "蓑笠侵鄖俗，溪山動越吟。", "煙波千里去，誰識魏牟心。"]'),
('a5c6ce32-a30c-4cca-a5bf-25f02fccd316','漢東樓','沈括','宋','宋诗','song-poetry','','[]','野草粘天雨未休，客心自冷不關秋。',32,'全唐诗/poet.song.39000.json','["野草粘天雨未休，客心自冷不關秋。", "寨西便是猿啼處，滿目傷心悔上樓。"]'),
('26b37b1c-c892-4d97-9161-729f2206b286','幽命','沈括','宋','宋诗','song-poetry','','[]','山木嘯兮雲幽幽，秣我歸馬兮無爲久留。',101,'全唐诗/poet.song.39000.json','["山木嘯兮雲幽幽，秣我歸馬兮無爲久留。", "江鼯翔兮雨漫漫，回予車兮水漸幰。", "仲何爲兮中野，澹將洋兮疏駕。", "目逝兮形留，鬱逍遙兮日下。", "瀉慕兮流觀，撫節兮浩望。", "駟黄戾兮靡騁，旋吾輯兮焉往。", "不我虛兮斯辰，思何爲兮鞅掌。"]'),
('e1d61846-5a07-48ba-9075-1b07da0c53ce','佚老堂爲江州陶宣德題','沈括','宋','宋诗','song-poetry','','[]','暫來林下問棲遲，已覺絛然悟昨非。',64,'全唐诗/poet.song.39000.json','["暫來林下問棲遲，已覺絛然悟昨非。", "臥起見山寧用買，門牆無物可人揮。", "茵連細草才容藉，淀染濃嵐欲墮衣。", "佳士要當憐寂寞，不應全爲折腰歸。"]'),
('f9609c39-f5b7-4c60-850d-8f6ef0a67d2e','遊秀州東湖','沈括','宋','宋诗','song-poetry','','[]','柳色青天雨乍晴，鴨頭細草繞堤生。',64,'全唐诗/poet.song.39000.json','["柳色青天雨乍晴，鴨頭細草繞堤生。", "林間野日依依見，水底春光寸寸明。", "猶喜亂花時入眼，可能萬事頓忘情。", "無端景物相料理，屢欲顛狂興不成。"]'),
('c70ec277-0e01-4e0c-bb7f-b584855238ee','秀州秋日','沈括','宋','宋诗','song-poetry','','[]','草滿池塘霜送梅，林疏野色近樓臺。',64,'全唐诗/poet.song.39000.json','["草滿池塘霜送梅，林疏野色近樓臺。", "天圍故越侵雲盡，潮上孤城带月回。", "客夢冷隨風葉斷，愁心低逐雁聲來。", "流午又喜經重九，可意黄花是處開。"]'),
('4c2ec572-a108-4038-a68c-fd1e47ef3d1e','蘇小小墓','沈括','宋','宋诗','song-poetry','','[]','古木寒鴉噪夕陽，六朝遺恨草茫茫。',32,'全唐诗/poet.song.39000.json','["古木寒鴉噪夕陽，六朝遺恨草茫茫。", "水如香篆船如葉，咫尺西陵不見郎。"]'),
('ba7c42cc-edd5-46d5-b2ae-62950e203d52','贈故鄉人','沈括','宋','宋诗','song-poetry','','[]','我家已破出他鄉，如連如卓方阜昌。',64,'全唐诗/poet.song.39000.json','["我家已破出他鄉，如連如卓方阜昌。", "豈料囊金隨後散，一齊開鋪鬻文章。", "我今濱死秪如尋，二友猶堪望軒翥。", "從頭借問向來誰，十室九人非舊主。"]'),
('32efff59-e3de-4a8d-af51-759ab4d6410b','金山','沈括','宋','宋诗','song-poetry','','[]','樓臺兩岸水相連，江北江南鏡裏天。',32,'全唐诗/poet.song.39000.json','["樓臺兩岸水相連，江北江南鏡裏天。", "蘆管玉簫齊送夜，一聲飛斷月如煙。"]'),
('efcfbada-3e0b-4a6b-9e62-2ecd25b02300','遊花山寺','沈括','宋','宋诗','song-poetry','','[]','經旬飄雨喜新晴，病馬緣畦取次行。',64,'全唐诗/poet.song.39000.json','["經旬飄雨喜新晴，病馬緣畦取次行。", "老態只應隨日至，春心無意與花爭。", "山川滿目浮煙合，樓板侵天暮靄橫。", "嗟我有身無處用，強攜尊酒入崢嶸。"]'),
('0b9f7092-1cab-43d0-aa2c-b5f0812c2f49','望海樓','沈括','宋','宋诗','song-poetry','','[]','雨聲林外盡，秋色望中添。',48,'全唐诗/poet.song.39000.json','["雨聲林外盡，秋色望中添。", "落日掛疏柳，遠江橫暮簷。", "好風疑有意，墮葉故爭簾。", "爲問樓中客，胡爲盡日淹。"]'),
('ef2ded13-5663-4ca6-80f7-375c75c9480f','潤州甘露寺','沈括','宋','宋诗','song-poetry','','[]','丞相高齋半草萊，舊時風月滿亭臺。',64,'全唐诗/poet.song.39000.json','["丞相高齋半草萊，舊時風月滿亭臺。", "地從日月生時見，天到江山盡處回。", "三國是非春夢斷，六朝城闕野花開。", "心隨潮水漫漫去，流徧煙村半日來。"]'),
('62bc6c5b-dc9a-4f03-939b-30811b43d076','陳丞相故宅','沈括','宋','宋诗','song-poetry','','[]','丞相旌旗久不歸，虛堂寧止歎伊威。',32,'全唐诗/poet.song.39000.json','["丞相旌旗久不歸，虛堂寧止歎伊威。", "綠槐樓閣山蟬響，青草池塘野燕飛。"]'),
('735cccd6-e269-4b58-8b4b-56bc42cf2dd2','丹陽樓','沈括','宋','宋诗','song-poetry','','[]','碧城西轉拂蒼煙，日繞闌干一握天。',64,'全唐诗/poet.song.39000.json','["碧城西轉拂蒼煙，日繞闌干一握天。", "青草暮山歌扇底，美人瑤瑟瞑鴻邊。", "吹聲隱隱江都月，弄影翩翩建業船。", "流盡古來東去水，又將秋色遇樓前。"]'),
('26f646a9-c1ea-4a36-aa28-75f9296220a7','嘗茶','沈括','宋','宋诗','song-poetry','','[]','誰把嫩香名雀舌，定知北客未曾嘗。',32,'全唐诗/poet.song.39000.json','["誰把嫩香名雀舌，定知北客未曾嘗。", "不知靈草天然異，一夜風吹一寸長。"]'),
('f5298929-093b-47f8-8ed0-32e0d1f17b44','圖畫歌','沈括','宋','宋诗','song-poetry','','[]','畫中最妙言山水，摩詰峰巒兩畫起。',387,'全唐诗/poet.song.39000.json','["畫中最妙言山水，摩詰峰巒兩畫起。", "李成筆奪造化功，荆浩開圖論千里。", "范寬石瀾煙樹深，枯木關仝極難比。", "江南董源僧巨然，淡墨輕嵐爲一體。", "宋迪長於遠與乎，王端善作寒江行。", "克明已往道寧逝，郭熙遂得新來名。", "花竹翎花不同等，獨出徐熙入神境。", "趙昌設色古無如，王友劉常亦堪並。", "黄筌居寀及譚宏，鷗鷺春葩蜀中景。", "艾宣孔雀世絕倫，羊仲甫雞皆妙品。", "惟有長沙易元吉，豈止獐鹿人不及。", "鵰鷹飛動羨張涇，番馬胡瓌屹然立。", "濠梁崔白及崔慤，群虎屏風供御幄。", "海州徐易魚水科，鱗鬣如生頗難學。", "金陵佛像王齊翰，顧德謙名皆雅玩。", "老曹菩薩各精神，道士李劉俱偉觀。", "星辰獨尚孫知微，盧氏楞伽亦爲伴。", "勾龍爽筆勢飄颻，錦裏三人共輝煥。", "西川女子分十眉，宮粧撚{絼艮}周昉肥。", "堯民擊壤鼓腹笑，滕王蛺蝶相交飛。", "居寧草蟲名浙右，孤松韋偃稱世希。", "韓幹能爲大宛馬，包鼎虎有驚人威。", "將軍曹霸善圖寫，五花聰馬今傳之。", "馭人相扶似偶語，老杜詠入丹青持。"]'),
('1aaf99c8-f79e-41a9-ba10-22956a756b02','幽人篇  其一','沈括','宋','宋诗','song-poetry','','[]','幽人步影囀春陽，情多無那不成章。',32,'全唐诗/poet.song.39000.json','["幽人步影囀春陽，情多無那不成章。", "恨樓未高着鞭望，南陌無人但垂楊。"]'),
('7423e7ed-fc32-4e83-a004-350dae2c6e20','幽人篇  其二','沈括','宋','宋诗','song-poetry','','[]','天邊夢來情滿床，夢短數覺宵苦長。',32,'全唐诗/poet.song.39000.json','["天邊夢來情滿床，夢短數覺宵苦長。", "起坐作琴舞閨倡，占瓏水中月茫茫。"]'),
('ffd59e7f-86e5-4be2-9c8f-044950211ad3','幽人篇  其三','沈括','宋','宋诗','song-poetry','','[]','蜘蛛做網着屠蘇，蜻蜒故來暈羅襦。',32,'全唐诗/poet.song.39000.json','["蜘蛛做網着屠蘇，蜻蜒故來暈羅襦。", "醮君柏酒情莫疏，無情可能學哺鴣。"]'),
('520d07ba-8ac8-42f3-ab65-e0d3f5d6ba4b','歸計','沈括','宋','宋诗','song-poetry','','[]','住山人少說山多，空只年年憶薜蘿。',32,'全唐诗/poet.song.39000.json','["住山人少說山多，空只年年憶薜蘿。", "不是自心應不信，眼前歸計又蹉跎。"]'),
('fce5157d-662e-41b8-a562-3e460b4a7e26','歎老','沈括','宋','宋诗','song-poetry','','[]','爲覓少年心不得，當時感舊已潸然。',32,'全唐诗/poet.song.39000.json','["爲覓少年心不得，當時感舊已潸然。", "情懷此日君休問，又老當時二十年。"]'),
('996a53fd-f0f7-4faf-b924-ff0f7562b3f0','雨中紅梅盛開折送李野夫','沈括','宋','宋诗','song-poetry','','[]','輕苞滿檻簇花鈿，雲幕低垂黯淡天。',64,'全唐诗/poet.song.39000.json','["輕苞滿檻簇花鈿，雲幕低垂黯淡天。", "巫峽人歸街暮雨，阿溪家遠隔非煙。", "少分山客紅雲破，擬奪星郎錦帳鮮。", "未上春風惜寒晚，故教開向眾芳前。"]'),
('0c3418f3-2993-4ebd-b08b-27184632ffcd','次韻辛著作興化園池詩  其一','沈括','宋','宋诗','song-poetry','','[]','能文騎省幸鄰船，多病中散自蕭然。',64,'全唐诗/poet.song.39000.json','["能文騎省幸鄰船，多病中散自蕭然。", "□橋鳥啼深竹裏，晴渚夢遶楊花邊。", "難分桃杏春滿目，不斷水月波如煙。", "□須移居速相就，已有的的新生蓮。"]'),
('709d6af8-69ca-4cd6-9f63-cd0a430f9fe6','次韻辛著作興化園池詩  其二','沈括','宋','宋诗','song-poetry','','[]','東來重見郭翻船，目極滄洲似渺然。',64,'全唐诗/poet.song.39000.json','["東來重見郭翻船，目極滄洲似渺然。", "浪信小橈穿竹去，不知佳景向誰邊。", "白頭趙將心仍在，多病萊蕪竈不煙。", "惟有王家風月地，時時客看滿池蓮。"]'),
('8eb03a3e-3929-4f62-89ab-e73b96ef061b','寄永嘉王博士','沈括','宋','宋诗','song-poetry','','[]','十萬橐鞬臨易水，五營旗鼓出中山。',32,'全唐诗/poet.song.39000.json','["十萬橐鞬臨易水，五營旗鼓出中山。", "去年今日西岑別，回首吳山夢寐間。"]'),
('f3fdaf55-5561-4126-a96a-ad40e1f26578','賀仲雨斗門','沈括','宋','宋诗','song-poetry','','[]','濯錦江邊唱絕強，孤青和者亦夔襄。',96,'全唐诗/poet.song.39000.json','["濯錦江邊唱絕強，孤青和者亦夔襄。", "歷年雖久地相遠，在寢豈止升渠堂。", "縱能帖石防頹岸，隨寓幽居供賞朊。", "何如是處斗門雄，莆壤萬農生贊歡。", "莊周笑我機械深，夏王見我須賞音。", "莫道白頭猶未遇，等勞一片活人心。"]'),
('893e8a5d-0ded-4bf1-85ac-2c9eb502a73d','自題水閣絕句','沈括','宋','宋诗','song-poetry','','[]','三間水閣賈耘老，一首佳詞沈會宗。',32,'全唐诗/poet.song.39000.json','["三間水閣賈耘老，一首佳詞沈會宗。", "無限當時好風月，如今總屬績溪翁。"]'),
('428aab36-65f0-4070-aa51-b01616bdad59','浩燕堂','沈括','宋','宋诗','song-poetry','','[]','西堂昔時冷蕭條，使君名高堂爲高。',208,'全唐诗/poet.song.39000.json','["西堂昔時冷蕭條，使君名高堂爲高。", "流虹碎□勤鐫雕，粉黛翕倏隨揮毫。", "太守浩燕觴九牢，門前過客羅百艘。", "簷褕曄曄爛亭臯，切雲危冠控豪曹。", "秋鶴霜毛飛錦袍，六鵲曳地橫金腰。", "輕羅韜煙媚中宵，緩歌閣舞縈雲髾。", "趙人手提千牛刀，目視大犗如鴻毛。", "太守巨筆驅波濤，指畫風雲慘動搖。", "佩牛带犢如銷膏，區區古人無是超。", "吳秔如脂敢百筲，連車折軸棄道交。", "釜區爭先走名豪，旋鱸掣酒飛千舠。", "杜伯稱觥釃醲醪，翳翳禾黍藏笙簫。", "太守浩燕樂歲饒，豈徒割烹盈大庖。"]'),
('da756677-76c2-4511-a388-849ff563db42','句  其一','沈括','宋','宋诗','song-poetry','','[]','百辟九霄環帝座。',8,'全唐诗/poet.song.39000.json','["百辟九霄環帝座。"]'),
('4b36a22c-dc7a-4586-ab49-5f5cc155de34','句  其二','沈括','宋','宋诗','song-poetry','','[]','艇子隔溪語，水光冰玉壺。',12,'全唐诗/poet.song.39000.json','["艇子隔溪語，水光冰玉壺。"]'),
('71db9cf7-f9b2-4358-b434-23a58bb04d02','句  其三','沈括','宋','宋诗','song-poetry','','[]','白差烏鬼作鷓鶿。',8,'全唐诗/poet.song.39000.json','["白差烏鬼作鷓鶿。"]'),
('5487f855-7f70-43b3-9195-1718ed87a090','句  其四','沈括','宋','宋诗','song-poetry','','[]','黄金碾畔綠塵飛，碧玉甌中翠濤起。',16,'全唐诗/poet.song.39000.json','["黄金碾畔綠塵飛，碧玉甌中翠濤起。"]'),
('ab1a8efb-73ad-4dc3-abc9-5db6749e18e0','句  其五','沈括','宋','宋诗','song-poetry','','[]','四蹄雙翻驚草頭，飛入平原不沾土。',16,'全唐诗/poet.song.39000.json','["四蹄雙翻驚草頭，飛入平原不沾土。"]'),
('d282b1cb-18df-4243-ab32-60e769c783ea','送程給事知越州','沈括','宋','宋诗','song-poetry','','[]','鸞臺倦直出黄扉，魚浦雙旌入翠微。',64,'全唐诗/poet.song.39000.json','["鸞臺倦直出黄扉，魚浦雙旌入翠微。", "閣老清規三省舊，使君高興五湖歸。", "卻從江海瞻青瑣，聊過丘園戲錦衣。", "一拂京塵浩南望，蓬萊閣靜簿書稀。"]'),
('1d81ebba-eb5b-490a-9860-83a2c6d6e335','寄贈舒州徐處土','沈括','宋','宋诗','song-poetry','','[]','昔愛灊川游，青林覆幽石。',120,'全唐诗/poet.song.39000.json','["昔愛灊川游，青林覆幽石。", "道人攜手行，蕭然名山客。", "誰知隋世路，譬如羈飛翮。", "林皋未脫去，紛紛頭欲白。", "輕負皇人經，猶懷稚川策。", "幸已棄韋带，遠謝功名跡。", "聊希閉關士，正苦身爲役。", "別來二千日，還丹應有術。", "毋忘絳囊贈，使我升仙籍。", "將酬金鐶脆，青綾三萬尺。"]'),
('2582f03e-3faf-4eea-9c8b-88723a3df005','游二禪師道場','沈括','宋','宋诗','song-poetry','','[]','勝境東西白，高僧一二禪。',48,'全唐诗/poet.song.39000.json','["勝境東西白，高僧一二禪。", "只知行道處，不記住山時。", "澗月中分照，林花各自妍。", "披雲尋舊址，猶在絳峰旁。"]'),
('e5cddd2d-bd86-4456-8e89-4b21f096a28c','題孤嶺','蔣之奇','宋','宋诗','song-poetry','','[]','蛟綃翦下碧雙垂，歸挹清流背紫微。',32,'全唐诗/poet.song.39000.json','["蛟綃翦下碧雙垂，歸挹清流背紫微。", "北向更登孤嶺去，此身還入白雲飛。"]'),
('4b4140bf-88aa-4418-ad96-1a64d4525833','春帖子','蔣之奇','宋','宋诗','song-poetry','','[]','昧旦求衣向曉雞，蓬萊仗下日將西。',32,'全唐诗/poet.song.39000.json','["昧旦求衣向曉雞，蓬萊仗下日將西。", "花添漏鼓三聲遠，柳映春旗一色齊。"]'),
('fea95e5e-e51e-46cf-b78b-60a4bd4e0329','和鮑娘題兌溪驛','蔣之奇','宋','宋诗','song-poetry','','[]','盡日行荒徑，全家出瘴嵐。',24,'全唐诗/poet.song.39000.json','["盡日行荒徑，全家出瘴嵐。", "鮑娘詩句好，今夜宿江南。"]'),
('1cb3c74e-4875-4b12-93ad-85b09af2ac14','和兄之翰寵換蘇印  其一','蔣之奇','宋','宋诗','song-poetry','','[]','久次含香厭粉闈，懇求茂苑得州麾。',64,'全唐诗/poet.song.39000.json','["久次含香厭粉闈，懇求茂苑得州麾。", "卻尋舊日池臺勝，猶憶當年几杖隨。", "入里下車修敬日，過家上冢致哀時。", "應憐二弟猶羈絆，萬里邊沙遠帥熙。"]'),
('0b38bc20-1e02-4f31-b14a-7cf30cd3fca3','和兄之翰寵換蘇印  其二','蔣之奇','宋','宋诗','song-poetry','','[]','早同侍宦向長洲，今擁旌麾訪舊游。',32,'全唐诗/poet.song.39000.json','["早同侍宦向長洲，今擁旌麾訪舊游。", "自古風流詩酒地，韋蘇州後蔣蘇州。"]'),
('e79c298a-2a66-420f-8889-2e46ed097bd0','贈海陵天慶觀樂子長真人碑','蔣之奇','宋','宋诗','song-poetry','','[]','瑤壇三級滿蒼苔，想像真人飲赤杯。',32,'全唐诗/poet.song.39000.json','["瑤壇三級滿蒼苔，想像真人飲赤杯。", "颯颯仙風動杉檜，只應飇馭暫歸來。"]'),
('dfefbe62-7566-49d0-a825-4f0847447045','和祕閣曝書會','蔣之奇','宋','宋诗','song-poetry','','[]','宴豆追儒雅，簪纓成禮容。',48,'全唐诗/poet.song.39000.json','["宴豆追儒雅，簪纓成禮容。", "中天開璧府，左海見鼇峰。", "汗簡陳三館，仙遊列玉京。", "丹青浮象魏，盛典照蓬瀛。"]'),
('0dfcc9ee-16c3-481a-9b1b-1b29dd146102','寄米元章','蔣之奇','宋','宋诗','song-poetry','','[]','京城汩沒興如何，歸棹翩翩返薜蘿。',64,'全唐诗/poet.song.39000.json','["京城汩沒興如何，歸棹翩翩返薜蘿。", "盡室生涯寄京口，滿床圖籍鎖巖阿。", "六朝人物東流盡，千古山河北固多。", "爲借文殊方丈地，中間容箇病維摩。"]'),
('f31372c2-0e1b-4cb0-a439-1b3870967848','即事','蔣之奇','宋','宋诗','song-poetry','','[]','渭水岐山不出兵，卻攜慧劍錦官城。',64,'全唐诗/poet.song.39000.json','["渭水岐山不出兵，卻攜慧劍錦官城。", "醉來身外窮通小，老去人間毀譽輕。", "捫虱雄豪空自許，屠龍工巧竟何成。", "雅聞岷下多區芋，聊試寒爐玉糝羹。"]'),
('67d078c4-27f3-4e9a-ac7a-67035625bbad','遊朝陽巖遂登西亭','蔣之奇','宋','宋诗','song-poetry','','[]','昔遊不在遠，幽巖臨治城。',252,'全唐诗/poet.song.39000.json','["昔遊不在遠，幽巖臨治城。", "嶔岑俯瀟碧，庨豁延陽明。", "綠澗可徑八，滑路偪仄行。", "泉源自何來，涓涓玉鏘鳴。", "疑穿雲雷窟，常带魚龍腥。", "寒江凈瀉鏡，怪石坐開屏。", "幽鳥馴可羅，潛蛟深莫罾。", "梯險接層棧，冠顛聳危亭。", "俯睨極玄窞，仰攀窮青冥。", "蹇曠出物表，高虛挹玄英。", "惜哉非吾土，不得憩此生。", "舊業寄陽羨，故園依晉陵。", "秋風滆湖白，春色頤山青。", "一從紳笏去，遂使猨鶴驚。", "迂疏暗時機，孱瑣叨官榮。", "謫棄分所宜，愧恧顔已盈。", "人生詎有幾，世累吾方輕。", "願言解羈紲，上疏還簪纓。", "寧居召魂魄，恬養休性情。", "紛華屏外慕，沖澹嚴中扃。", "窮年伴農圃，畢志先疇耕。"]'),
('3f1869ce-b208-47e6-a437-fba65c1530b1','澹巖','蔣之奇','宋','宋诗','song-poetry','','[]','零陵水石天下聞，澹山之勝難具論。',384,'全唐诗/poet.song.39000.json','["零陵水石天下聞，澹山之勝難具論。", "初從崖口入地底，始見殿閣開重門。", "乃知茲洞最殊絕，洞中金碧開祇園。", "寬平可容萬人坐，仰視有若覆盎盆。", "虛明最宜朝日照，陰晦常有黑雲屯。", "盤虯夭矯垂乳下，巨獸突兀巨石蹲。", "木香一株在巖壁，人跡峭絕不可捫。", "靈仙飛游享此供，常駕飇馭乘雲軒。", "我來正逢春雨霽，氛翳開廓陽景溫。", "呀然雙穴露天半，籠絡萬象將並吞。", "只疑七竅混沌在，五竅忘失兩竅存。", "神奇遺跡未泯滅，至今猶有斧鑿痕。", "雲床石屏極隈隩，昔有居士常潛蟠。", "避秦不出傲徵召，美名遂入賢水源。", "咸通曾爲二蛇窟，元暢演法蛇輒遷。", "從茲其中建佛剎，棲隱不復聞世喧。", "惜哉此景久埋沒，但與赤子安枯禪。", "次山子厚愛山水，探索幽隱窮晨昏。", "朝陽迫迮若就狴，石角禿鬝如朝髠。", "豪篇矜誇過其實，稱譽珉石爲璵璠。", "環觀珍寶欲奄有，不到勝處天所慳。", "嗟予至此駭未睹，不暇稱讚徒驚嘆。", "恨無雄文壓奇怪，好事略與二子班。", "蕪詞願勒巖上石，勿使歲久詞滅漫。"]'),
('008bb283-0ee3-43a9-8937-fbd7082aee86','清光亭','蔣之奇','宋','宋诗','song-poetry','','[]','鄭圃僕射陂，漢陽郎官湖。',48,'全唐诗/poet.song.39000.json','["鄭圃僕射陂，漢陽郎官湖。", "郎官何爲名，張謂佩使符。", "泛觴江城南，乃與太白俱。", "明月一萬頃，清光天下無。"]'),
('33d9bd22-0c95-4ce8-b378-3340f70c07a8','萍鄉即事','蔣之奇','宋','宋诗','song-poetry','','[]','地接長沙近，鄉名自古聞。',48,'全唐诗/poet.song.39000.json','["地接長沙近，鄉名自古聞。", "毛山千嶂雪，玉女一堆雲。", "拱木扶霄上，飛泉觸石分。", "霜風萍實老，目斷楚江濆。"]'),
('692d2102-e135-4413-a56a-e2b2376a2a6b','重湖閣','蔣之奇','宋','宋诗','song-poetry','','[]','宮亭彭蠡接揚瀾，浩蕩橫空六月寒。',33,'全唐诗/poet.song.39000.json','["宮亭彭蠡接揚瀾，浩蕩橫空六月寒。", "試問風波何以險，老僧只有管倚闌干。"]'),
('8b960b38-fdb9-4742-a6e2-5da07a19f118','水西示劉尉','蔣之奇','宋','宋诗','song-poetry','','[]','役役塵埃倦客情，偶逢佳節得閑行。',32,'全唐诗/poet.song.39000.json','["役役塵埃倦客情，偶逢佳節得閑行。", "憑君爲把如椽筆，便向蒼崖記姓名。"]'),
('0a448016-40fe-419d-bd20-7c7064eb89b2','題到氏田舍','蔣之奇','宋','宋诗','song-poetry','','[]','六朝冠蓋俱塵土，到氏今無苗裔存。',32,'全唐诗/poet.song.39000.json','["六朝冠蓋俱塵土，到氏今無苗裔存。", "當時任昉過田舍，野老猶記查林村。"]'),
('541a051d-6446-472e-8c29-b556cb15b5d0','南雄昌樂驛','蔣之奇','宋','宋诗','song-poetry','','[]','城東湞水碧淵洄，楊僕樓船向此來。',32,'全唐诗/poet.song.39000.json','["城東湞水碧淵洄，楊僕樓船向此來。", "我亦編蓬今下瀨，擬尋韶石上崔嵬。"]'),
('ee1f9619-074b-4ca2-8386-3843583ddb9e','續武溪深','蔣之奇','宋','宋诗','song-poetry','','[]','滔滔武溪一何深，鳥飛不渡，獸不能臨。',332,'全唐诗/poet.song.39000.json','["滔滔武溪一何深，鳥飛不渡，獸不能臨。", "嗟哉武溪何毒淫。", "飛湍瀑流瀉雲岑，砰激百兩雷車音。", "吾聞神漢之初始開斸，史君姓周其各煜。", "至今廟在樂昌西，苔蘚殘碑僅填讀。", "武水之源自何出，郴州武縣鸕鷀石。", "南入桂陽三百里，峻瀨洪濤互淙射。", "其誰寫此入新聲，一曲馬援門人笛。", "南方耆舊傳此水，樂昌之瀧茲乃是。", "退之昔日泛潮陽，曾到瀧頭問瀧吏。", "我今以選來番禺，事與昌黎殊不類。", "未嘗神色輒戃慌，何至形容遽憔悴。", "但憐歲晚毛鬢侵，故園一別至於今。", "溪光罨畫清且淺，朱藤覆水成春陰。", "何爲在此嬰朝簪，翩然走馬馳駸駸。", "南踰瘴嶺窮崎崟，梅花初開雪成林。", "韶石仿佛聞舜琴，曹源一滴清人心。", "遠民安堵年穀稔，百蠻航海來獻琛。", "嗟余才薄力不任，報君夙夜輸誠忱。", "布宣條教勤官箴，有佳山水亦出尋。", "樂平吾樂何有極，不信弦歌武溪深。"]'),
('40cd66b9-a73f-4fb6-b6ef-022e6fb75a32','望韶石','蔣之奇','宋','宋诗','song-poetry','','[]','當日昌黎繫纜初，曾瞻雙闕整冠裾。',32,'全唐诗/poet.song.39000.json','["當日昌黎繫纜初，曾瞻雙闕整冠裾。", "致君堯舜今誰是，想像聞韶更起予。"]'),
('a9d415e1-4316-4a6c-8d49-388539236d5b','石門山  其一','蔣之奇','宋','宋诗','song-poetry','','[]','呂嘉妄欲抗中原，積石江心尚巋然。',32,'全唐诗/poet.song.39000.json','["呂嘉妄欲抗中原，積石江心尚巋然。", "豈料王師到尋狹，挫鋒困粟遂無前。"]'),
('cb20efcd-eb23-4caa-9036-d53aaf69fff2','石門山  其二','蔣之奇','宋','宋诗','song-poetry','','[]','樓船伏波安在哉，會兵曾破石門來。',32,'全唐诗/poet.song.39000.json','["樓船伏波安在哉，會兵曾破石門來。", "昔年已過獲嘉縣，今日更登朝漢臺。"]'),
('3d07df69-77b0-481f-be9b-99522e49201e','峽山','蔣之奇','宋','宋诗','song-poetry','','[]','昨從湞陽來，暮過峽山寺。',288,'全唐诗/poet.song.39000.json','["昨從湞陽來，暮過峽山寺。", "適聞新昌寇，道路傳者沸。", "余時不敢留，一葦翻然逝。", "雖經絕妙境，已負清幽意。", "捲簾坐船，船極目望蒼翠。", "有如逢珍寶，不暇貯篋笥。", "又如過屠門，大嚼涎垂喙。", "每欲問其詳，曾莫得圖志。", "道人山中來，爲我譚一二。", "犀去金鎖沈，猿歸玉環墜。", "趙胡垂釣石，巋然出江際。", "穆王雙車轍，想像常按轡。", "漢晉五仙人，曾騎五羊至。", "俊靄二禪師，神力與迎馭。", "岧嶢五岳塔，初自崑崙施。", "三祖石堪奇，僧粲嘗所憩。", "上方獅子臺，下視見雲氣。", "異花成帳幄，紅紫嫣然媚。", "蒙茸綠崖草，莖葉相覆被。", "或黄如金釵，或白如珠珥。", "造化窮天巧，肖像名殊異。", "梁間許渾詩，壁上李翱記。", "但知攷事蹟，何暇評文字。", "清遠中古宿，俯壓南海澨。"]'),
('9aec3c50-576f-479d-8247-37c5f4f1888e','浮丘山','蔣之奇','宋','宋诗','song-poetry','','[]','此山從古號浮丘，攜手城西是舊游。',64,'全唐诗/poet.song.39000.json','["此山從古號浮丘，攜手城西是舊游。", "法從未容穿豹尾，守藩聊得步鼇頭。", "傍連玳瑁遺亭近，下有珊瑚廢井留。", "得道丈人如可遇，秋風挹袖上瀛洲。"]'),
('ab35492f-8d9d-42ee-bbc3-0edbcaefd489','過蕪湖','蔣之奇','宋','宋诗','song-poetry','','[]','除地誅茅懸左偏，三山一碧正當前。',64,'全唐诗/poet.song.39000.json','["除地誅茅懸左偏，三山一碧正當前。", "舍人爲寫湖陰曲，禪伯請題城上篇。", "帳下勁兵纏象魏，櫪中飛騎控巴滇。", "至今庭竹根延蔓，尚想當時七寶鞭。"]'),
('b75b3678-9911-41e9-9961-59ee7fc0bdcd','遊狼山','蔣之奇','宋','宋诗','song-poetry','','[]','一線橫大江，千螺簇層巒。',24,'全唐诗/poet.song.39000.json','["一線橫大江，千螺簇層巒。", "空外飛鳥沒，煙中片帆還。"]'),
('36d1f950-2c84-4b54-b52d-df2b4e3a0679','鸚鵡洲','蔣之奇','宋','宋诗','song-poetry','','[]','落日漢陽孤閣對，秋風鄂渚數舟橫。',32,'全唐诗/poet.song.39000.json','["落日漢陽孤閣對，秋風鄂渚數舟橫。", "偶吟萬里飄流句，獨倚滄洲憶禰生。"]'),
('d63d3767-bb97-4787-afe3-9870a1bd98be','朝漢臺','蔣之奇','宋','宋诗','song-poetry','','[]','不終強屈蠻夷上，稍復低回禮義中。',32,'全唐诗/poet.song.39000.json','["不終強屈蠻夷上，稍復低回禮義中。", "自昔一時成霸業，至今千載仰英風。"]'),
('5bbda99e-1910-4ade-b352-d0e1090026fc','菖蒲澗','蔣之奇','宋','宋诗','song-poetry','','[]','撥破紅塵入紫煙，五羊壇上訪神仙。',32,'全唐诗/poet.song.39000.json','["撥破紅塵入紫煙，五羊壇上訪神仙。", "人間自覺無閑地，城裏誰知有洞天。"]'),
('d7a13a1a-3170-4d74-a409-deba7b6be054','泊武昌','蔣之奇','宋','宋诗','song-poetry','','[]','圓壇展祀日，樊山開宴時。',24,'全唐诗/poet.song.39000.json','["圓壇展祀日，樊山開宴時。", "釣台高嶪嵲，離殿鬰參差。"]'),
('2b09d460-6016-4364-b965-004d9549d5b9','休休亭','蔣之奇','宋','宋诗','song-poetry','','[]','勢利煎人漫白頭，休休休去是良謀。',32,'全唐诗/poet.song.39000.json','["勢利煎人漫白頭，休休休去是良謀。", "應須買取堪騎鶴，跨入芝田閬苑游。"]'),
('51765b4c-a45f-45ea-9440-b55d4a0a404b','題慧山寺','蔣之奇','宋','宋诗','song-poetry','','[]','釋子幽居遠俗紛，停橈登覽日將曛。',64,'全唐诗/poet.song.39000.json','["釋子幽居遠俗紛，停橈登覽日將曛。", "湖光已嘆千年變，山勢猶驚九隴分。", "迸溜冷噴雙沼雪，煮茶香透一杯雲。", "偶因流落尋佳致，何意聲名世外聞。"]'),
('cdd91a5b-b03c-4d6f-9408-d18f1c9e36ce','遊慧山','蔣之奇','宋','宋诗','song-poetry','','[]','還家豈不樂，生事未應閑。',48,'全唐诗/poet.song.39000.json','["還家豈不樂，生事未應閑。", "朝日已復去，征鞍方更攀。", "傷心百道水，閱目萬重山。", "何以忘羈旅，翛翛醉夢間。"]'),
('789c2e9a-87b3-4297-9381-fc83f84c5605','萍鄉','蔣之奇','宋','宋诗','song-poetry','','[]','人家白雪中，鳥道青雲裏。',60,'全唐诗/poet.song.39000.json','["人家白雪中，鳥道青雲裏。", "耕斸競畬田，魚樵喧會市。", "秀出羅霄山，倒流楊岐水。", "三真不可尋，寥寥忽千祀。", "更想用兵時，徘徊甘卓壘。"]'),
('c2f4fdd9-c724-4b54-9879-98faa3066739','愛山堂  其一','蔣之奇','宋','宋诗','song-poetry','','[]','我愛通羊好，民居山作城。',24,'全唐诗/poet.song.39000.json','["我愛通羊好，民居山作城。", "眼前無俗事，枕畔有灘聲。"]'),
