('ecf84430-2911-4067-abf8-9e4a80f9c673','飛雲峰','蔣之奇','宋','宋诗','song-poetry','','[]','翠巘蘢蔥瑞色分，嵐光遙映縷絲棼。',32,'全唐诗/poet.song.39000.json','["翠巘蘢蔥瑞色分，嵐光遙映縷絲棼。", "無心謾作奇峰勢，何礙金烏出海門。"]'),
('1f8bf786-6902-4ff2-8227-8b1041094ce7','香爐峰','蔣之奇','宋','宋诗','song-poetry','','[]','天風飄飄浮紫煙，誰把雪山香草然。',32,'全唐诗/poet.song.39000.json','["天風飄飄浮紫煙，誰把雪山香草然。", "氣息不教落人世，直上紫皇青案前。"]'),
('4d1a1b16-9f85-4aa1-b515-a570a5f18612','翠霞峰','蔣之奇','宋','宋诗','song-poetry','','[]','軟金赬玉翠流輝，天嬪新開雲錦機。',32,'全唐诗/poet.song.39000.json','["軟金赬玉翠流輝，天嬪新開雲錦機。", "西望赤城標起處，宦情欲逐野雲飛。"]'),
('fb9b9f63-3fad-48ac-8b5b-518edbedc177','蒼玉峰','蔣之奇','宋','宋诗','song-poetry','','[]','翠滴溪橋水沍澄，更深斜月映寒星。',32,'全唐诗/poet.song.39000.json','["翠滴溪橋水沍澄，更深斜月映寒星。", "巉巖何代點頭石，臥聽高人夜讀經。"]'),
('aeccff7d-5521-41d6-9d87-f3dc6c73e6ee','芙蓉峰','蔣之奇','宋','宋诗','song-poetry','','[]','擎天一柱萬山低，九朵奇葩秀一枝。',32,'全唐诗/poet.song.39000.json','["擎天一柱萬山低，九朵奇葩秀一枝。", "多少好山僧占住，空王曾會範圍基。"]'),
('f93f2fad-1ec7-45de-81b0-42edaea923c5','流清峰','蔣之奇','宋','宋诗','song-poetry','','[]','飛泉練白地無塵，欻起千波湛寂身。',32,'全唐诗/poet.song.39000.json','["飛泉練白地無塵，欻起千波湛寂身。", "靜挾飛仙忘世慮，卻嗤塵世夢中人。"]'),
('aee226b5-1675-4b71-b89c-40113e12a35f','峨眉峰','蔣之奇','宋','宋诗','song-poetry','','[]','翠黛輕拖促曉妝，雲歸鬟岫鬢蒼蒼。',32,'全唐诗/poet.song.39000.json','["翠黛輕拖促曉妝，雲歸鬟岫鬢蒼蒼。", "道人欲識普賢面，西蜀重燒十願香。"]'),
('a1fa9dc3-ab63-4e28-88e8-106356e46d73','天竺峰','蔣之奇','宋','宋诗','song-poetry','','[]','藜杖芒鞋興不窮，萬山螺簇碧蘢蔥。',32,'全唐诗/poet.song.39000.json','["藜杖芒鞋興不窮，萬山螺簇碧蘢蔥。", "青天一餉開圖畫，瀲灧收歸慘淡中。"]'),
('4a28006d-c94f-4e5e-a238-3934e80b8d8d','生雲石','蔣之奇','宋','宋诗','song-poetry','','[]','藤陰稜石煜金科，磊砢常將風雨磨。',32,'全唐诗/poet.song.39000.json','["藤陰稜石煜金科，磊砢常將風雨磨。", "剛被閑雲生罅隙，禪僧迷失舊盤陀。"]'),
('d3e91d8b-1840-4db4-9f44-54d34196ac55','燕窩石','蔣之奇','宋','宋诗','song-poetry','','[]','墨窩化石鎖煙苔，巖上茅空煙又開。',32,'全唐诗/poet.song.39000.json','["墨窩化石鎖煙苔，巖上茅空煙又開。", "塵劫一聲清磬裏，至今猶有燕飛來。"]'),
('351e75f7-d48e-48ab-9dfa-cc6af60c7923','萬年妙蓮閣','蔣之奇','宋','宋诗','song-poetry','','[]','佛隴遺芳鮮儷蹤，王張三觀揭禪叢。',64,'全唐诗/poet.song.39000.json','["佛隴遺芳鮮儷蹤，王張三觀揭禪叢。", "圓明珠繫衣襦裏，凈妙蓮生濕淤中。", "再現石橋真法界，重興銀地舊家風。", "未應賦述誇孫綽，序倡稱揚復有公。"]'),
('58d6bdd0-9094-4e85-a9aa-de3485eebf4f','松石峰','蔣之奇','宋','宋诗','song-poetry','','[]','晚向津亭泊畫船，忽聞佳處在雲煙。',64,'全唐诗/poet.song.39000.json','["晚向津亭泊畫船，忽聞佳處在雲煙。", "松根化作千年石，山寺蒸爲一澗泉。", "祖意供看亭下柏，禪交同結社中蓮。", "明朝輿筍還躋嶺，聊借僧房一覺眠。"]'),
('5e29116c-08af-40a4-a6dd-d1ecd65a7250','望海歌','蔣之奇','宋','宋诗','song-poetry','','[]','我來靈峰□滄海，夜半起坐望海亭。',305,'全唐诗/poet.song.39000.json','["我來靈峰□滄海，夜半起坐望海亭。", "沈沈水面正陰黑，六龍銜日□未平。", "□更陽谷光氣發，五色變怪不可名。", "洪濤洶涌□鼎沸，蛟蜃伏匿魚龍驚。", "金鴉騰署若木末，煙消霧散□下明。", "狂風喧豗簸巨浪，猶似百面雷鼓鳴。", "崩騰蕩沃□五岳，鱗鬣磨有效地鯨與鵬。", "嘈峨忽駭陵谷變，雪山千仞□際橫。", "飄飄番船隨上下，出沒僅若水□萍。", "忽然風霽□籟息，金斗熨帖一練平。", "碧波湛湛千萬頃，參錯島嶼□杯罌。", "三江五湖亦甚大，視此乃類蹄中泓。", "琉球佛齊日本國，隱隱微見煙林青。", "三山歷歷亦可數，突兀下有□頭撐。", "惜哉秦王不此，勞心徒欲求長生。", "我雖流落□海上，獨此寄寓亦可矜。", "行當結茅鍊金液，以待九轉□丹成。", "仙飛羽化會有日，直跨三島梯青冥。", "他年故人或相問，請來訪我於蓬瀛。"]'),
('210d37f6-3457-4a25-a3dc-4da3625caabb','潄玉泉','蔣之奇','宋','宋诗','song-poetry','','[]','斷崖天削成，半腰爲坳窊。',132,'全唐诗/poet.song.39000.json','["斷崖天削成，半腰爲坳窊。", "殿閣在其中，乃是釋子家。", "初疑無路通，去必淩紫霞。", "屈曲轉山足，雲蘿可攀拏。", "忽然至其上，金碧藏谽谺。", "卻見巖下路，目睛眩生花。", "僧有定慧者，來自蜀道賒。", "五代方亂離，相此山水佳。", "卜居不復出，焚香擁袈裟。", "嗟余但企仰，涉世空喧嘩。", "安得寄遁此，可以忘幽遐。"]'),
('753eb831-b7df-44ae-938c-4606d46391ba','寄題三瑞堂','蔣之奇','宋','宋诗','song-poetry','','[]','好在廬陵守，年來强健無。',48,'全唐诗/poet.song.39000.json','["好在廬陵守，年來强健無。", "一麾新佩印，三瑞更爲圖。", "善政傳江右，飛書到海隅。", "緬懷烏府舊，何日笑談俱。"]'),
('5ec8fb1d-96f2-42d6-96ba-5758f929f718','琴高臺懷古  其一','蔣之奇','宋','宋诗','song-poetry','','[]','高士遺臺曲澗東，俯臨百丈之飛虹。',64,'全唐诗/poet.song.39000.json','["高士遺臺曲澗東，俯臨百丈之飛虹。", "雲卷雲舒絕壁下，花開花落空潭中。", "丹砂鍊去山俱寂，赤鯉騎歸路不通。", "嘆息往來車馬客，幾人忙處問琴公。"]'),
('087f2b3a-2628-457e-a09b-b7edea50927d','琴高臺懷古  其二','蔣之奇','宋','宋诗','song-poetry','','[]','來至涇川十里餘，嶄然怪石翠凌虛。',32,'全唐诗/poet.song.39000.json','["來至涇川十里餘，嶄然怪石翠凌虛。", "自慚不是神仙骨，空羨琴高控鯉魚。"]'),
('6986e696-b402-4eae-8dcf-e5d01e555a58','白面山','蔣之奇','宋','宋诗','song-poetry','','[]','白面峰巒碧玉堆，故人卜築在巖隈。',64,'全唐诗/poet.song.39000.json','["白面峰巒碧玉堆，故人卜築在巖隈。", "難尋荀鶴舊遊宅，尚有昭明古釣臺。", "滿檻名花紅勝錦，一溪流水綠如苔。", "七閩千里倦遊客，兩眼眵昏向此開。"]'),
('daaea2de-d8a2-4925-a705-c91ac3230746','遊化城寺','蔣之奇','宋','宋诗','song-poetry','','[]','級級躋攀險，肩輿若上天。',48,'全唐诗/poet.song.39000.json','["級級躋攀險，肩輿若上天。", "雲端開净刹，峰頂見平田。", "水石清無價，烟霞翠滿前。", "高僧卜居此，意欲斷塵緣。"]'),
('25f83c60-6934-4d41-bf18-ff5aef9b46e5','六和寺金魚池','蔣之奇','宋','宋诗','song-poetry','','[]','全體若金銀，深藏如自珍。',24,'全唐诗/poet.song.39000.json','["全體若金銀，深藏如自珍。", "應知貪餌者，畢竟是凡人。"]'),
('09c76bb0-6c8d-4f94-b695-6252ff51ec20','隱居南莊','蔣之奇','宋','宋诗','song-poetry','','[]','耕春煙一壟，釣月水千尋。',24,'全唐诗/poet.song.39000.json','["耕春煙一壟，釣月水千尋。", "未荒三徑菊，不負此生心。"]'),
('872c13ec-7a02-451c-8ba8-fb613f6078b9','蒼玉洞','蔣之奇','宋','宋诗','song-poetry','','[]','蒼玉門徑濶，白雲庭院深。',24,'全唐诗/poet.song.39000.json','["蒼玉門徑濶，白雲庭院深。", "鄞江一丈水，清可照人心。"]'),
('033de48d-0a95-4a39-a270-39dfd5bc67ca','鷲峰院','蔣之奇','宋','宋诗','song-poetry','','[]','山前十里入青蒼，猿鳥聲中建道場。',32,'全唐诗/poet.song.39000.json','["山前十里入青蒼，猿鳥聲中建道場。", "日轉竹陰侵閣冷，水流花片過門香。"]'),
('29a3529c-0d48-4b85-98e1-e3a240356322','涇溪','蔣之奇','宋','宋诗','song-poetry','','[]','蕩漾溪沙深淺間，羣山回抱翠連環。',32,'全唐诗/poet.song.39000.json','["蕩漾溪沙深淺間，羣山回抱翠連環。", "扁舟便欲乘流去，直下山門六刺灘。"]'),
('cc62e9ee-b84b-41e3-bf13-f212719b4378','過幙溪憶左難當','蔣之奇','宋','宋诗','song-poetry','','[]','幙山孤秀幙溪清，玉鑑光寒映翠屏。',32,'全唐诗/poet.song.39000.json','["幙山孤秀幙溪清，玉鑑光寒映翠屏。", "今古寥寥何可問，難當遺事在圖經。"]'),
('16709b0f-679a-4de1-a41d-21f32745ac4b','劉遺民釣臺','蔣之奇','宋','宋诗','song-poetry','','[]','最愛仙人卧白雲，一竿來此釣紅鱗。',32,'全唐诗/poet.song.39000.json','["最愛仙人卧白雲，一竿來此釣紅鱗。", "我今不學磻溪叟，行作宗雷社裏人。"]'),
('2413ed8a-7632-4f85-94fe-3d95248029f7','嘉禾驛','蔣之奇','宋','宋诗','song-poetry','','[]','盱江清淺見游鱗，百尺飛橋跨碧津。',32,'全唐诗/poet.song.39000.json','["盱江清淺見游鱗，百尺飛橋跨碧津。", "行過水南看更好，風光駘蕩百花春。"]'),
('4f45ea89-0427-4ee5-bbe9-13f9e0846f12','梅花','蔣之奇','宋','宋诗','song-poetry','','[]','昨夜雪初霽，寒梅破蕾新。',24,'全唐诗/poet.song.39000.json','["昨夜雪初霽，寒梅破蕾新。", "滿頭雖白髪，聊插一枝春。"]'),
('9f2f868e-fa67-48b5-896b-d9391b29fe8f','詩一首','蔣之奇','宋','宋诗','song-poetry','','[]','凌風泛浪白於雲，野牧湖中曉至昏。',32,'全唐诗/poet.song.39000.json','["凌風泛浪白於雲，野牧湖中曉至昏。", "一舉招旗畢來集，至今人號養鵝墩。"]'),
('a0f93cf5-ef1d-4e29-ba1f-5197324124de','左伯桃墓羊角哀墓','蔣之奇','宋','宋诗','song-poetry','','[]','結交有羊左，是惟一時才。',240,'全唐诗/poet.song.39000.json','["結交有羊左，是惟一時才。", "爲聞楚王賢，翩然自燕來。", "一日食欲盡，俱往空雙埋。", "伯桃乃獨留，餓死梁山隈。", "角哀仕既達，感舊肝膽摧。", "念此併糧惠，告還葬遺骸。", "至今溧陽旁，突兀穴土堆。", "何人致薦奠，千花飛酒杯。", "精靈今在否，古木以生雷。", "魯公昔過之，駐車久徘徊。", "感嘆發篇詠，灑翰鑱瓊瑰。", "惜哉今不存，散落隨塵埃。", "空餘鄭薰記，片石昏蒼苔。", "末世友道絕，雅歌□□頹。", "草木尚萎死，小怨何足懷。", "我思有所矯，巨燄明寒灰。", "茲事雖過中，義烈亦壯哉。", "幸逢太丘長，揭表旌泉臺。", "寥寥千載間，下激清風迴。", "還顧勢利交，市道良可哀。"]'),
('5ff3e5e2-0a0b-4f34-9e24-139df47db53b','墨妙亭','蔣之奇','宋','宋诗','song-poetry','','[]','蘭亭搨本得遺法，字體變化人莫窺。',48,'全唐诗/poet.song.39000.json','["蘭亭搨本得遺法，字體變化人莫窺。", "梭飛壁間勢屈矯，劍出獄底光陸離。", "可憐闕齧侵點畫，鐵網買斷珊瑚枝。"]'),
('027b2783-397b-4b1f-8979-b6493024faf6','排衙石','蔣之奇','宋','宋诗','song-poetry','','[]','怪石如排衙，羅列亭兩畔。',24,'全唐诗/poet.song.39000.json','["怪石如排衙，羅列亭兩畔。", "森森整旌纛，岌岌峨冠弁。"]'),
('332d1aa8-8c3f-4ab1-b29c-c4fbbde4fff2','磨劍池','蔣之奇','宋','宋诗','song-poetry','','[]','聞說旌陽舊築壇，故浮修水一來看。',32,'全唐诗/poet.song.39000.json','["聞說旌陽舊築壇，故浮修水一來看。", "至今磨劍池猶在，冷浸一天星斗寒。"]'),
('184c9279-7b36-45b2-86da-eefd614bc8cf','鹿鳴宴','蔣之奇','宋','宋诗','song-poetry','','[]','公輔產日南，九齡起韶陽。',24,'全唐诗/poet.song.39000.json','["公輔產日南，九齡起韶陽。", "早知朱泚反，預識胡雛狂。"]'),
('9ae4d914-a12b-4314-a7db-395fd58b655d','越王臺','蔣之奇','宋','宋诗','song-poetry','','[]','近城故有武王臺，拂雲千尺高崔嵬。',32,'全唐诗/poet.song.39000.json','["近城故有武王臺，拂雲千尺高崔嵬。", "謂之朝漢乃非是，歲時嘉會傾尊罍。"]'),
('1b95f263-c6f3-4b16-8c7d-aa04c4bdf6a0','奉陪穆父尚書仲至侍郎德和吏部至啟聖院','蔣之奇','宋','宋诗','song-poetry','','[]','惟此休祥地，相傳慶育時。',48,'全唐诗/poet.song.39000.json','["惟此休祥地，相傳慶育時。", "繞樞飛電轉，流渚彩虹垂。", "鬰鬰餘佳氣，綿綿嗣慶基。", "九龍曾灑濯，三聖共扶持。"]'),
('0196d9fc-ace7-42c5-bfef-5a1ca2be9cec','上清儲祥宮','蔣之奇','宋','宋诗','song-poetry','','[]','萬計損珠寶，千章列棟楹。',48,'全唐诗/poet.song.39000.json','["萬計損珠寶，千章列棟楹。", "秋毫思頰挫，不日慶釐成。", "青簡流芳遠，丹書霈澤傾。", "袖人罔恫怨，道路沸歡聲。"]'),
('ec0dd403-37b0-4de1-bf62-80d14361e76f','寄題梅壇','蔣之奇','宋','宋诗','song-poetry','','[]','昔我承乏江西官，豫章聖跡無不觀。',240,'全唐诗/poet.song.39000.json','["昔我承乏江西官，豫章聖跡無不觀。", "如何復有此遺恨，獨我不到梅仙壇。", "梅仙壇在豐城界，真風爽氣埃塵外。", "當年補尉向南昌，才譽雖高官未大。", "漢成帝時綱紀壞，先生諫書至於再。", "前擢王章矯曲朝，戮及妻子讎黨快。", "群臣知非不敢爭，遂令天下言爲誡。", "烏乎此語誠甚危，譏切權強何慷慨。", "借令觸突倖臣牙，嗜一羈單未爲害。", "公卿大臣噤不吐，彼爲私謀安足怪。", "正人在下吁可悲，變名吳市復誰知。", "元豐敕書爲旌表，故故丹井存遺基。", "壽春真人錫顯號，稱其高蹈與俗遺。", "先生雖不遇於昔，而遇於今蒙獎飭。", "令丞作書譽忠直，潛德幽光輝無極。"]'),
('78fc15a1-bbf8-43bc-bd61-5196364b2cef','上高寶嚴寺','蔣之奇','宋','宋诗','song-poetry','','[]','嘉節長岐路，區區夢幻身。',24,'全唐诗/poet.song.39000.json','["嘉節長岐路，區區夢幻身。", "何年一舉腋，仙去逐敖君。"]'),
('144b1445-b140-439e-88d7-8cd9fd7987d4','青草湖','蔣之奇','宋','宋诗','song-poetry','','[]','地無一勺水，安得有湖名。',24,'全唐诗/poet.song.39000.json','["地無一勺水，安得有湖名。", "世事果如此，風波平地生。"]'),
('ed126374-a89a-4b3b-b5b0-f83f6b0d8615','龍池巖','蔣之奇','宋','宋诗','song-poetry','','[]','蒼龍蛻骨去已久，山根一穴如天開。',32,'全唐诗/poet.song.39000.json','["蒼龍蛻骨去已久，山根一穴如天開。", "寄言俗客不可入，往往白晝生風雷。"]'),
('5f74aed1-a53c-469e-9330-d4209788f7f5','蒼玉洞','蔣之奇','宋','宋诗','song-poetry','','[]','全閩形勢屬臨汀，贛嶺連疆似井陘。',32,'全唐诗/poet.song.39000.json','["全閩形勢屬臨汀，贛嶺連疆似井陘。", "江匯里淵銷地脈，山橫華蓋應天星。"]'),
('ec309ec5-674e-4909-9678-4eb3afe77b5a','石巖','蔣之奇','宋','宋诗','song-poetry','','[]','紫翠望雲嵐，山前一逕杉。',24,'全唐诗/poet.song.39000.json','["紫翠望雲嵐，山前一逕杉。", "冥冥煙雨裏，枉道訪仙巖。"]'),
('295ebd91-1b84-4a3c-9203-a50404a36f7b','廣州州學記繫詩','蔣之奇','宋','宋诗','song-poetry','','[]','諸侯之學，是謂泮水。',240,'全唐诗/poet.song.39000.json','["諸侯之學，是謂泮水。", "詩人所頌，魯侯戾止。", "獻馘於是，獻囚於是。", "釆芹則美，飲酒維旨。", "淮夷來服，觩弓搜矢。", "其摯維何，元龜象齒。", "區區魯邦，陋無足紀。", "維泮之興，功烈如彼。", "下逮鄭國，學校不修。", "青青子衿，莫肯來遊。", "誰欲毀之，僑吉厥猶。", "視其所召，藥之則瘳。", "我得吾師，實獲所求。", "首善于京，其速置郵。", "矧在守長，宣化承流。", "德音不昭，維職之憂。", "番禺之學，莫原所作。", "歲月其綿，棟楹腐惡。", "藩級板夷，屋垣圮剝。", "圖像之威，弗丹弗雘。", "聖經不談，束置高閣。", "講席其虛，維塵漠漠。", "譬彼弗殖，萎其將落。", "于嗟斯民，誰啟誰覺。"]'),
('174b368e-df87-4783-8c00-6e686347f067','按行分宜','蔣之奇','宋','宋诗','song-poetry','','[]','分得宜春地，東偏一畫屏。',48,'全唐诗/poet.song.39000.json','["分得宜春地，東偏一畫屏。", "洪陽仙洞古，龍姥舊祠靈。", "雨過溪痕長，春回草徑青。", "道傍聊下馬，揩蘚讀碑銘。"]'),
('b2d56fea-1b79-4793-9a41-0c7ad7d43d83','旴水詩','蔣之奇','宋','宋诗','song-poetry','','[]','旴江一带碧漣漪，來憑闌干把酒時。',32,'全唐诗/poet.song.39000.json','["旴江一带碧漣漪，來憑闌干把酒時。", "吏役不知春色晚，緋桃花發兩三枝。"]'),
('d37be3eb-5dcc-481a-a33e-6c2e7bf419cf','麻源詩','蔣之奇','宋','宋诗','song-poetry','','[]','泉飛石磴尚微紅，澗出銅陵碧數重。',32,'全唐诗/poet.song.39000.json','["泉飛石磴尚微紅，澗出銅陵碧數重。", "遙想謝公臨郡日，幾回屐齒印苔封。"]'),
('0db08e72-9689-4ece-9273-807d6847ae24','章山永壽禪寺','蔣之奇','宋','宋诗','song-poetry','','[]','老僧七十九，自說少遊方。',24,'全唐诗/poet.song.39000.json','["老僧七十九，自說少遊方。", "試問章山景，爐添一炷香。"]'),
('e7c20fb4-ff05-42ab-ae8f-cfc8b98d6533','遊狼山寺','蔣之奇','宋','宋诗','song-poetry','','[]','不到狼山已十春，舊題猶覆碧紗塵。',32,'全唐诗/poet.song.39000.json','["不到狼山已十春，舊題猶覆碧紗塵。", "重來風物皆依舊，嬴得衰殘老病身。"]'),
('92e18a1a-6630-499a-b8ab-bae909a9ebc3','沖寂觀','蔣之奇','宋','宋诗','song-poetry','','[]','樓閣鬰穹窿，清都幸此逢。',144,'全唐诗/poet.song.39000.json','["樓閣鬰穹窿，清都幸此逢。", "兔藏賢令井，鯨吼貳卿鍾。", "花覆瑤臺暗，香飄寶鼎濃。", "仙居赤城洞，人住玉霄峰。", "棋響風敲竹，琴棲月在松。", "雲霞隨步武，猿鶴伴從容。", "湖漲銷千尺，山浮黛色重。", "人間真福地，物外是靈蹤。", "鷲嶺標香剎，蛟溪接近封。", "枌榆偏在念，桑梓更惟恭。", "學道功成就，沖霄願必從。", "他年隨羽化，橫跨葛坡龍。"]'),
('32858926-7a43-4122-8f10-a3d9c71160aa','句  其一','蔣之奇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','橘熟洞庭曉，臚肥笠澤秋。',12,'全唐诗/poet.song.39000.json','["橘熟洞庭曉，臚肥笠澤秋。"]'),
('8cb92097-ce88-4068-ab1e-cdb1712a1a48','句  其二','蔣之奇','宋','宋诗','song-poetry','','[]','古寺當江湄，歸舟昔嘗往。',12,'全唐诗/poet.song.39000.json','["古寺當江湄，歸舟昔嘗往。"]'),
