('f865df0a-ddf2-462a-95d5-87758d7b1548','句  其二三','蔣之奇','宋','宋诗','song-poetry','','[]','野徑得閑行。',6,'全唐诗/poet.song.39000.json','["野徑得閑行。"]'),
('b978b89a-0d8c-40bb-9b08-c8b8233ecbc8','句  其二四','蔣之奇','宋','宋诗','song-poetry','','[]','玉盃舊學無施設，空有新詩滿錦囊。',16,'全唐诗/poet.song.39000.json','["玉盃舊學無施設，空有新詩滿錦囊。"]'),
('f5f876b8-d69c-4756-b1ca-c8ab1f244756','送中濟侍郎帥慶得行字','范純禮','宋','宋诗','song-poetry','','[]','爲國雖以德，御戎難去兵。',120,'全唐诗/poet.song.39000.json','["爲國雖以德，御戎難去兵。", "夏人久犯順，邊氓常廢耕。", "遣師楊我武，謀帥直非輕。", "輟自金穀寄，倚以關塞行。", "壯懷吞猖狂，沈機足經營。", "新傷乃民力，未振亦軍聲。", "既膺閫外寄，當思千里清。", "吾家世此官，所得蕃漢情。", "未嘗任殺戮，接以信與誠。", "方略固多在，惟公守其成。"]'),
('6d52ce8d-8928-46bd-88af-363258ce5c4f','幸太學倡和','范純禮','宋','宋诗','song-poetry','','[]','四十餘年舊典章，聖君今復幸虞庠。',64,'全唐诗/poet.song.39000.json','["四十餘年舊典章，聖君今復幸虞庠。", "虎賁萬騎森羅列，雁序諸生儼綴行。", "已見重准同舜帝，不須無逸戒成王。", "祖宗基構隆三代，統業相承是肯堂。"]'),
('258d3d38-50dc-4565-b311-fc4e5e6818c2','梵安寺內浣溪四老唱和詩','楊咸章','宋','宋诗','song-poetry','','[]','聞說懸車三老儒，約爲繪像訪僧居。',64,'全唐诗/poet.song.39000.json','["聞說懸車三老儒，約爲繪像訪僧居。", "蟹螯杯酒歡無極，鼎足韜襲樂有餘。", "暑簟共觀岷嶺雪，春盤同膾蜀江魚。", "歸來一榻如相許，須信逍遙倍二疏。"]'),
('2d7e6cc1-4d83-45dd-86a3-4861bcdfcdb2','甘露巖','楊咸章','宋','宋诗','song-poetry','','[]','屈曲山腰一逕通，亂雲芳草思無窮。',32,'全唐诗/poet.song.39000.json','["屈曲山腰一逕通，亂雲芳草思無窮。", "塵埃從此去人遠，我欲誅茅寄一峰。"]'),
('67f9dc92-30b5-4689-b13d-2b33c0a2d04a','宗弟晦之通直有詩陳武信歸簉三老之後損之喜繼元韻以勉之','楊損之','宋','宋诗','song-poetry','','[]','未拋名利尚區區，方卜榮遷武信居。',64,'全唐诗/poet.song.39000.json','["未拋名利尚區區，方卜榮遷武信居。", "思簉林泉三老後，已經年紀七旬餘。", "且來在野同游鹿，莫學臨淵卻羨魚。", "子美堂鄰願爲約，免教朋友舊情疏。"]'),
('8cb46777-50da-40d7-a2ef-a5331c8ef2fc','謹次元韻呈嚴鈞給事','楊損之','宋','宋诗','song-poetry','','[]','萬里歸陪老叟遊，燦然雅什遺朋儔。',64,'全唐诗/poet.song.39000.json','["萬里歸陪老叟遊，燦然雅什遺朋儔。", "雲咸響亮清盈耳，霜雪繽紛白滿頭。", "三益畫開裨古意，千鍾酒飲破春愁。", "勸君莫倦桑榆景，未得爲霖志未酬。"]'),
('5b734abd-8488-4e2d-85b4-d18217a159f2','傑衰朽無取辱益之見招同諸友爲四老會晦之承議有詩傑謹次元韻','任傑','宋','宋诗','song-poetry','','[]','夫子關西出眾儒，肯來尋我蔔幽居。',64,'全唐诗/poet.song.39000.json','["夫子關西出眾儒，肯來尋我蔔幽居。", "忘憂棋局真佳趣，投老詩篇是緒餘。", "故舊已家吟伐木，太平只恐罩嘉魚。", "主人醉指前溪路，松菊清涼月影疏。"]'),
('a0ba55fe-babc-474e-af98-2e4a4ec85b95','傑伏蒙知府給事寵示佳章謹次元韻和呈','任傑','宋','宋诗','song-poetry','','[]','險阻艱難自徧遊，歸來尋訪老交儔。',64,'全唐诗/poet.song.39000.json','["險阻艱難自徧遊，歸來尋訪老交儔。", "七年弦頃嗟分袂，二月鶯花喜聚頭。", "美酒十分須共醉，勞生一夢更何愁。", "況君富貴功名在，從此男兒志可酬。"]'),
('68ebd683-0fc0-41b1-b689-eea9f39a5c2e','武仲伏承益之奉議轉示晦之佳什謹依元韻次和','楊武仲','宋','宋诗','song-poetry','','[]','素發龐眉一陋儒，常陪龍友到禪居。',64,'全唐诗/poet.song.39000.json','["素發龐眉一陋儒，常陪龍友到禪居。", "我隨益者誠多幸，人歎賢哉愧有餘。", "坐上共飛純玉斝，腰間齊佩白銀魚。", "高吟清論常終日，會數朋交信不疏。"]'),
('a0502721-cd4b-46ab-99b4-e79172690d4c','承漠公承議頒示佳章謹次元韻','楊武仲','宋','宋诗','song-poetry','','[]','當年臺閣仰英遊，此日還鄉接舊儔。',64,'全唐诗/poet.song.39000.json','["當年臺閣仰英遊，此日還鄉接舊儔。", "共喜故人攀鳳翼，佇膺新詔覲螭頭。", "清歡且盡三春樂，閑飲能消五載愁。", "夸聽郢中歌白雪，敢將巴曲強論酬。"]'),
('f099b72b-8a1f-493d-a5f1-d03b194ab602','送程給事知越州','呂嘉問','宋','宋诗','song-poetry','','[]','朱方藩牧寄非輕，故輟中朝近侍行。',64,'全唐诗/poet.song.39000.json','["朱方藩牧寄非輕，故輟中朝近侍行。", "黼帳暫違簪筆對，錦衣初喜遇家榮。", "前臨使宅千山秀，俯視隄封一水橫。", "第恐急賢嚴召節，不容選勝遍江城。"]'),
('fdc050cc-a7fc-492d-895a-23f048c4ef5a','題張公洞','單鍔','宋','宋诗','song-poetry','','[]','松菊投荒山水間，阿誰指點到仙寰。',64,'全唐诗/poet.song.39000.json','["松菊投荒山水間，阿誰指點到仙寰。", "洞門龍出雲猶濕，石至丹成火欲寒。", "百越樓臺摩詰畫，三吳煙水季鷹閑。", "陶然醉臥花間酒，細納余香滿袖還。"]'),
('2618fdc2-eca3-471a-8aae-349ae37a0435','巾山廣軒','徐億','宋','宋诗','song-poetry','','[]','勝景更新數步間，北山遊得對巑岏。',64,'全唐诗/poet.song.39000.json','["勝景更新數步間，北山遊得對巑岏。", "憑闌愈覺雙峰峻，極目無涯六幙寬。", "特出喧卑資曠達，所臨高遠壯遊盤。", "炎蒸此地爲清暑，莫厭攀躋磴道難。"]'),
('0200d724-8106-433a-b408-6fafc745e856','涼軒','郎几','宋','宋诗','song-poetry','','[]','偉哉言偃室，室外構涼軒。',48,'全唐诗/poet.song.39000.json','["偉哉言偃室，室外構涼軒。", "到覺一襟爽，坐祛三伏暄。", "植筠憐節操，引水愛潺湲。", "公暇無餘事，逍遙此釋煩。"]'),
('efed5aad-e51d-4249-b65c-e6a2209d2de5','涼軒','呂希彥','宋','宋诗','song-poetry','','[]','酷暑如何避，虛軒落始成。',48,'全唐诗/poet.song.39000.json','["酷暑如何避，虛軒落始成。", "地閑氣易爽，境勝目須清。", "月上簾色靜，風來竹塢嗚。", "公餘亦自適，山水入琴聲。"]'),
('5cc13076-9574-40ae-9021-df0100946795','遊嵩山聯句','王辟疆','宋','宋诗','song-poetry','','[]','靈境中天秀，雄名古到今。',288,'全唐诗/poet.song.39000.json','["靈境中天秀，雄名古到今。", "位尊朝列嶽，勢重壓千岑。", "靜鎖神仙宅，高盤宇宙心。", "孤棱標日月，絕仞倚戈壇。", "彩楝靈柯邃，層壇淨刹深。", "民祈傳覡語，國祀致君比。", "碑古宇生字，堂虛畫蠹金。", "山呼曾薦壽，神降即爲霖。", "事怪塗山石，形端玉女砧。", "峰巒排翠玉，灘瀨漱嗚琴。", "蕙帳人誰繼，金泥跡可尋。", "唐經藏寶妙，魏殿想鑾音。", "雲作他方雨，松連別院陰。", "谷泉長浸斗，頂路欲捫參。", "探穴魂潛動，捫蘿力不禁。", "箕熊分蟻垤，伊洛認蹄涔。", "鳥道樵夫去，龍潭驛使臨。", "眾仙停羽駕，昔帝儼宸襟。", "選勝先看記，乘危可作箴。", "天門開四極，樹品冠雙林。", "靈藥看苗斸，香醪挈榼斟。", "道宮庭不掃，學館突無黔。", "壟麥風搖浪，溪淙石聳簪。", "雜花春爛漫，老木夜蕭森。"]'),
('c65bbf3a-0fe1-4cc0-b498-29cd18595ccc','涼軒','王辟疆','宋','宋诗','song-poetry','','[]','谿山環繞古城深，賢尹開軒日醉吟。',64,'全唐诗/poet.song.39000.json','["谿山環繞古城深，賢尹開軒日醉吟。", "大抵清虛雖得地，從來安靜本由心。", "朝揮玉麈風生座，夜撫瑤琴月滿襟。", "應笑陶潛種楊柳，五株門外不成陰。"]'),
('43ee887d-f3c7-4e22-83a1-8f1d100d913e','留題淡山巖','王辟疆','宋','宋诗','song-poetry','','[]','洞府深沉別有天，石門相貫碧孱顔。',64,'全唐诗/poet.song.39000.json','["洞府深沉別有天，石門相貫碧孱顔。", "鑿開混沌千年竅，坼破蓬萊一朵山。", "日玩嵌空僧不厭，時探幽怪客忘還。", "若教元子當初到，肯使朝陽播世間。"]'),
('5093f35e-8788-40be-ad70-5c05ef49172d','涼軒','樊宗簡','宋','宋诗','song-poetry','','[]','邑署開軒檻，景閒宜快襟。',48,'全唐诗/poet.song.39000.json','["邑署開軒檻，景閒宜快襟。", "簷虛月先上，地僻暑寧侵。", "夕照亂山遠，風清群水深。", "政成足優逸，好自撫鳴琴。"]'),
('79eaad37-c9c8-4bf4-a9d7-d3210c7eee26','涼軒','趙某','宋','宋诗','song-poetry','','[]','古邑逢賢宰，構軒涼景生。',48,'全唐诗/poet.song.39000.json','["古邑逢賢宰，構軒涼景生。", "塵埃不復到，泉石有餘清。", "詩得幽奇句，琴多雅淡聲。", "居民陶美化，應此放高情。"]'),
('346d0613-1f82-44a7-9bf4-7c9faa807ff6','涼軒','杜叔獻','宋','宋诗','song-poetry','','[]','縣僻少逢迎，閑軒得創營。',48,'全唐诗/poet.song.39000.json','["縣僻少逢迎，閑軒得創營。", "先秋嵐氣肅，涉夏竹風清。", "待月詩中趣，分泉枕畔聲。", "憑君植春柳，高節繼淵明。"]'),
('66de5c1b-03d3-4b39-a49e-6577d9bb44be','涼軒','張鍔','宋','宋诗','song-poetry','','[]','瀟灑吳夫子，搆軒山縣中。',48,'全唐诗/poet.song.39000.json','["瀟灑吳夫子，搆軒山縣中。", "何曾知大暑，每到便清風。", "林影亂不定，泉聲咽復通。", "微吟傾白酒，日月任西東。"]'),
('35aa36ef-4526-4cc1-9fa6-6dc06b3bbb72','涼軒','李鵬','宋','宋诗','song-poetry','','[]','盛夏暑已極，此軒涼復生。',48,'全唐诗/poet.song.39000.json','["盛夏暑已極，此軒涼復生。", "天除前吏酷，地借長官清。", "種竹風乾樹，敲棋月一枰。", "方知北窗傲，不獨是淵明。"]'),
('dde6f9b3-35eb-4c1b-996c-05298ae3869e','涼軒','江泳','宋','宋诗','song-poetry','','[]','一軒新創足清涼，岸幘披襟暇日長。',64,'全唐诗/poet.song.39000.json','["一軒新創足清涼，岸幘披襟暇日長。", "極目閑田虞輿芮，凝神虛室老兼莊。", "簷牙高揭啄山色，簟角平舒約水光。", "料得北窗風更細，何妨笑傲比羲皇。"]'),
('452cc7e5-3822-4fe0-9096-b64fc30c9608','涼軒','趙中逵','宋','宋诗','song-poetry','','[]','虛涼奪炎暑，因此得佳名。',48,'全唐诗/poet.song.39000.json','["虛涼奪炎暑，因此得佳名。", "終日琴棋樂，四時風月清。", "捲簾對山色，欹枕聽泉聲。", "桃李新栽植，花開政已成。"]'),
('15aa1beb-b467-4922-a277-8c617371d854','涼軒','張允','宋','宋诗','song-poetry','','[]','涼軒無限景，茂宰樂清閑。',48,'全唐诗/poet.song.39000.json','["涼軒無限景，茂宰樂清閑。", "拂榻夜延月，捲簾時對山。", "泉聲來檻曲，野色入簷間。", "遙憶琴樽會，吟游路險難。"]'),
('eb1cfed3-6f95-41ad-b7da-1ede47862cde','游王官谷','毌沆','宋','宋诗','song-poetry','','[]','不汙唐家亂，蕭然表聖居。',24,'全唐诗/poet.song.39000.json','["不汙唐家亂，蕭然表聖居。", "泉聲輿山色，相得共清虛。"]'),
('403b2e7c-11f1-436a-a837-a45a8c36581e','題招提院靜照堂','俞希旦','宋','宋诗','song-poetry','','[]','槜李招提好，新堂向靜開。',48,'全唐诗/poet.song.39000.json','["槜李招提好，新堂向靜開。", "因名求定慧，對鏡悟西來。", "夜席常留月，寒階暗落梅。", "師歸得真趣，無復顧塵埃。"]'),
('478965ce-9357-4919-bdc9-36c0b12cde5a','送張君宰吳江','王介','宋','宋诗','song-poetry','','[]','乍被軒綏寵，新辭計省繁。',48,'全唐诗/poet.song.39000.json','["乍被軒綏寵，新辭計省繁。", "三江吳故國，百里漢郎官。", "煙水蓴芽紫，霜天橘顆丹。", "優遊民政外，風月即清歡。"]'),
('52b7827f-dc36-4075-a7af-ea6bdbb50aa3','出知湖州','王介','宋','宋诗','song-poetry','','[]','吳興太守美如何，太守從來惡祝蛇。',32,'全唐诗/poet.song.39000.json','["吳興太守美如何，太守從來惡祝蛇。", "生若不爲上柱國，死時猶合替閻羅。"]'),
('9c4de998-12dd-4731-b6c9-12ff03de3b41','句  其一','王介','宋','宋诗','song-poetry','','[]','上林春色好，攜手去來兮。',12,'全唐诗/poet.song.39000.json','["上林春色好，攜手去來兮。"]'),
('43733a6c-9a90-473d-890a-4aca4f5ad3a0','句  其二','王介','宋','宋诗','song-poetry','','[]','命也豈終否，時乎不暫留。',24,'全唐诗/poet.song.39000.json','["命也豈終否，時乎不暫留。", "勉哉藏素業，以待歲之秋。"]'),
('b44abe60-915b-4f69-91c9-f7081cdd0672','句  其三','王介','宋','宋诗','song-poetry','','[]','草廬三顧動幽蟄，蕙帳一空生曉寒。',16,'全唐诗/poet.song.39000.json','["草廬三顧動幽蟄，蕙帳一空生曉寒。"]'),
('1d574746-61d1-42e2-bbc9-12c14cf87c31','句  其四','王介','宋','宋诗','song-poetry','','[]','金陵村裏王夫子，可是能吟富貴詩。',16,'全唐诗/poet.song.39000.json','["金陵村裏王夫子，可是能吟富貴詩。"]'),
('773b332f-1892-4638-9580-648e93a18a40','題碧落洞','高鎛','宋','宋诗','song-poetry','','[]','豁見仙源啟翠巖，曾無鏁鑰易躋攀。',32,'全唐诗/poet.song.39000.json','["豁見仙源啟翠巖，曾無鏁鑰易躋攀。", "臨流便解塵纓濯，不信區區仕路難。"]'),
('4bf0b4c2-859c-4770-9254-16e27b870d7d','佘山月軒','朱伯虎','宋','宋诗','song-poetry','','[]','愛月開軒絕頂間，屹然危創壓層巒。',64,'全唐诗/poet.song.39000.json','["愛月開軒絕頂間，屹然危創壓層巒。", "剪除群卉當簷盡，添得清光滿檻看。", "亂石雲堆秋色冷，老松風入夜聲寒。", "十年夢寐江鄉景，杖屨終期日倚欄。"]'),
('264b87ba-396d-449b-8be8-8767e0be230f','紫微山','朱伯虎','宋','宋诗','song-poetry','','[]','鑿石開山已幾年，半天臺殿聳危巒。',64,'全唐诗/poet.song.39000.json','["鑿石開山已幾年，半天臺殿聳危巒。", "曉鐘聲向雲邊落，夜月光從檻底看。", "野色難藏千里秀，松風長占一軒寒。", "老僧此處真佳隱，應笑塵勞效小官。"]'),
('ac43fb80-f2ab-4f55-b11d-b1bc2e26b15c','詩一首','朱伯虎','宋','宋诗','song-poetry','','[]','松竹蕭森水石閑，亭臺高下聳層巒。',64,'全唐诗/poet.song.39000.json','["松竹蕭森水石閑，亭臺高下聳層巒。", "環觀疊嶂千重碧，俯瞰澄江萬頃寒。", "佳景真宜南國詫，畫圖堪與北人看。", "使君賢雅能行樂，肯向東山羨謝安。"]'),
('f4899f46-be5b-484b-8204-392dee33eac9','和陳倩曾公巖韻','齊諶','宋','宋诗','song-poetry','','[]','天作地藏知幾年，公來因得茂林間。',64,'全唐诗/poet.song.39000.json','["天作地藏知幾年，公來因得茂林間。", "誰言物外真仙境，祇接人居近郭山。", "石乳望中蒼玉墜，泉源深處臥龍閑。", "行看再爲蒼生起，乘興從容重返還。"]'),
('3cb3df86-0a8c-464e-941b-023c0bdea536','和劉誼老君巖韻  其一','齊諶','宋','宋诗','song-poetry','','[]','巨石何年此結成，老君肖像亦強名。',32,'全唐诗/poet.song.39000.json','["巨石何年此結成，老君肖像亦強名。", "以身爲患言猶在，謾使時人分重輕。"]'),
('0781b0af-35f9-4111-b5a3-39b99fe68ce6','和劉誼老君巖韻  其二','齊諶','宋','宋诗','song-poetry','','[]','巖前流水碧潺潺，鶴馭翩翩去弗還。',32,'全唐诗/poet.song.39000.json','["巖前流水碧潺潺，鶴馭翩翩去弗還。", "堪笑世人求不死，豈知道在有無間。"]'),
('ad55c2d0-1c63-4af4-a7ce-c7a43a763ce5','春日醉中作','徐璹','宋','宋诗','song-poetry','','[]','驚雷殷殷南山曲，一夜山前春雨足。',64,'全唐诗/poet.song.39000.json','["驚雷殷殷南山曲，一夜山前春雨足。", "美人睡起怯輕寒，衣褪香綃紅減玉。", "朝雲靄靄弄晴態，野柳狂花無管束。", "東風也自足春情，吹皺兩溪煙水綠。"]'),
('2051e4c8-7cab-4294-a49c-df151e45a4bf','崇教院','徐璹','宋','宋诗','song-poetry','','[]','巖僧結棟何勤勤，殿合岧峣勢欲奔。',64,'全唐诗/poet.song.39000.json','["巖僧結棟何勤勤，殿合岧峣勢欲奔。", "秋洗江光浮紺瓦，山盤樹影入青軒。", "相逢未免同塵眼，何日安禪慰病魂。", "欲借上方留一枕，夢隨寒磬過天門。"]'),
('e3da173f-e2fa-4cd8-bda7-f20365e187db','句','徐璹','宋','宋诗','song-poetry','','[]','滿城風物來春色，萬里江山入酒杯。',16,'全唐诗/poet.song.39000.json','["滿城風物來春色，萬里江山入酒杯。"]'),
('2989b50f-bf5a-4fc1-a15e-4ee8d835b242','和孔司封題蓬萊閣','江衍','宋','宋诗','song-poetry','','[]','巍據龍蟠最勝山，神仙琳館落人間。',64,'全唐诗/poet.song.39000.json','["巍據龍蟠最勝山，神仙琳館落人間。", "差差萬井庭闌布，矗矗群峰屏障環。", "入座湖光浮蕩漾，俯簷雲影遇斕諞。", "登臨自有飄然思，便覺身同白日閑。"]'),
('addf4cde-4d13-4617-a8d9-6e45b3837a87','和劉景文登介亭','袁轂','宋','宋诗','song-poetry','','[]','東南富山水，所病在卑溽。',240,'全唐诗/poet.song.39000.json','["東南富山水，所病在卑溽。", "陰晴變朝暮，梅雨大田足。", "翰苑宴高堂，金斝浮蟻淥。", "詩泠四座耳，醉飽五經腹。", "亭午登介亭，縈紆俯山麓。", "行路愁暍死，是月丁初伏。", "乘高瞰群峰，剛後浪奔逐。", "三吳在指掌，百粵入雙目。", "漢憂分朱蟠，堯意注黄屋。", "下輿曾未幾，傳命甚郵速。", "霸遂伏下風，元白仰高躅。", "倡予而和汝，談笑唾珠玉。", "所恨繼者貧，囊箱無寸幅。", "劉侯世良將，文史三冬讀。", "坐嘯胡騎卻，行歌燕旦哭。", "儒將久寂寥，斷弦今日績。", "所得最在詩，銛利鋒莫觸。", "唱酬黄卷上，如響答深谷。", "王侯富方丈，熊掌我所欲。", "獨餒不得飽，中心但誠服。"]'),
('4ed421ed-0fd0-44f5-ab97-dc61ccbed608','句  其一','袁轂','宋','宋诗','song-poetry','','[]','本是林泉客，來居山水州。',12,'全唐诗/poet.song.39000.json','["本是林泉客，來居山水州。"]'),
('8b3502b3-bcd8-4edb-9dc1-73b4f5cb508e','句  其二','袁轂','宋','宋诗','song-poetry','','[]','滄浪不須濯，纓上本無塵。',12,'全唐诗/poet.song.39000.json','["滄浪不須濯，纓上本無塵。"]'),
('a1a47f40-4c7c-4f19-9832-89759eccb36b','句  其三','袁轂','宋','宋诗','song-poetry','','[]','邦人遊冶處，盡在月輪中。',12,'全唐诗/poet.song.39000.json','["邦人遊冶處，盡在月輪中。"]'),
('3d8108c1-0be2-4714-be34-b62c45b5f745','句  其四','袁轂','宋','宋诗','song-poetry','','[]','曉瘴萬重煙漠漠，舂臺四顧俗熙熙。',32,'全唐诗/poet.song.39000.json','["曉瘴萬重煙漠漠，舂臺四顧俗熙熙。", "天鍾秀氣魁文陛，池湧仙源接武夷。"]'),
('2ccb8af7-27d2-4cf3-9b4b-15a85066165f','句  其五','袁轂','宋','宋诗','song-poetry','','[]','手掬樵溪塵可濯，恨無雄筆繼蘇爲。',16,'全唐诗/poet.song.39000.json','["手掬樵溪塵可濯，恨無雄筆繼蘇爲。"]'),
('f8c31180-5026-4afe-8a9e-ee3c07dadf07','句  其六','袁轂','宋','宋诗','song-poetry','','[]','營古杳難尋白石，山靈慚未識烏君。',16,'全唐诗/poet.song.39000.json','["營古杳難尋白石，山靈慚未識烏君。"]'),
('d16a6918-6618-4b3d-9643-226bb1886c3d','句  其七','袁轂','宋','宋诗','song-poetry','','[]','筍供四宇庖相繼，酒釀多年飲易醺。',16,'全唐诗/poet.song.39000.json','["筍供四宇庖相繼，酒釀多年飲易醺。"]'),
('a2810e77-3b71-4e8e-b4cf-c6f44a7bcb07','句  其八','袁轂','宋','宋诗','song-poetry','','[]','白日青天沛然下，皂蓋青旗猶未歸。',16,'全唐诗/poet.song.39000.json','["白日青天沛然下，皂蓋青旗猶未歸。"]'),
('7000ee64-84ce-4303-a930-b88c6786d513','梁山瀑布','蔡瑗','宋','宋诗','song-poetry','','[]','會稽之南羅浮北，中有大梁神仙宅。',32,'全唐诗/poet.song.39000.json','["會稽之南羅浮北，中有大梁神仙宅。", "瀑流今占掛長虹，瀉下銀河數千尺。"]'),
('22fc3bd4-ec57-479e-bd8a-24c4374e4cd5','雉山院','蔡瑗','宋','宋诗','song-poetry','','[]','白雉聞經向此山，轉身來伴老僧閑。',32,'全唐诗/poet.song.39000.json','["白雉聞經向此山，轉身來伴老僧閑。", "大都見善能開悟，天上人間任往還。"]'),
('2b7a6ebd-adc9-4a17-8eb1-ccb0566186cf','新建雙門奉呈知府郎中','蔡瑗','宋','宋诗','song-poetry','','[]','巍雉雲叢十萬家，臺門新築更豪華。',64,'全唐诗/poet.song.39000.json','["巍雉雲叢十萬家，臺門新築更豪華。", "春籠碧瓦浮佳氣，日上朱欄奪絳霞。", "眾水回環來衛府，千峰朝挹自排衙。", "吾州形勝今如此，文物彬彬正可嘉。"]'),
('496a8ba8-6a27-4122-849c-9b9cadfcf1ca','巾山廣軒','胡宗哲','宋','宋诗','song-poetry','','[]','昔人亭榭久荒殘，今復高軒峙翠巒。',64,'全唐诗/poet.song.39000.json','["昔人亭榭久荒殘，今復高軒峙翠巒。", "眺望可周千里景，宴游非止一時歡。", "樓臺遠近看如畫，日月高低轉似丸。", "最好使君登覽罷，夕陽群騎簇雕鞍。"]'),
('ae8bf590-a101-4fdf-b394-cb8537c63173','臨海淨土院','周弁','宋','宋诗','song-poetry','','[]','一徑森森入翠微，翠微深處見禪扉。',64,'全唐诗/poet.song.39000.json','["一徑森森入翠微，翠微深處見禪扉。", "倚雲殿閣光相照，蔽日松杉碧四圍。", "竹引澗泉寒遶屋，雨蒸山靄潤侵衣。", "十年遊宦今重到，景物依前舊識稀。"]'),
('4054bd40-c936-46cf-a612-5b921dba7511','送程給事知越州','王陟臣','宋','宋诗','song-poetry','','[]','出疆直欲請長纓，絕域皆知鄭眾名。',64,'全唐诗/poet.song.39000.json','["出疆直欲請長纓，絕域皆知鄭眾名。", "擁節初聞歸禁闥，懷章非是厭承明。", "淩虛觀閣仙鼇曉，倒景湖山鑑水清。", "遙想蘭亭多勝集，早傳佳句到都城。"]'),
('1399eef7-b96f-4f08-b951-c0eb57901e55','永明寺四香亭  其一','盛次仲','宋','宋诗','song-poetry','','[]','擾擾紅塵爲底忙，僧家白日自舒長。',32,'全唐诗/poet.song.39000.json','["擾擾紅塵爲底忙，僧家白日自舒長。", "朱簾著地寂無事，百刻青春一炷香。"]'),
('c48da42b-1e63-4cac-8d16-23509aef4139','永明寺四香亭  其二','盛次仲','宋','宋诗','song-poetry','','[]','四圍老綠夏陰涼，一枕南風睡思長。',32,'全唐诗/poet.song.39000.json','["四圍老綠夏陰涼，一枕南風睡思長。", "夢裏不知身是蝶，等閑飛入白蓮香。"]'),
('c3c556aa-e761-4e29-8686-babae931392d','永明寺四香亭  其三','盛次仲','宋','宋诗','song-poetry','','[]','霜晴卻見湖山好，境靜方知日月長。',32,'全唐诗/poet.song.39000.json','["霜晴卻見湖山好，境靜方知日月長。", "陶令醉多難入社，時來采菊飲秋香。"]'),
('a9388286-a8e4-44e6-9d87-9cffc2012537','永明寺四香亭  其四','盛次仲','宋','宋诗','song-poetry','','[]','趁雪看山坐小床，白雲影襄玉虹長。',32,'全唐诗/poet.song.39000.json','["趁雪看山坐小床，白雲影襄玉虹長。", "不知砌下梅花發，只怪開簾有暗香。"]'),
('628ecaa4-a768-407b-b0f7-3c4fd3c46fba','題東寺松石小軒呈同游關彥長明府','盛次仲','宋','宋诗','song-poetry','','[]','一松偃蹇蒼龍蟠，一石巉巖怒虎踞。',32,'全唐诗/poet.song.39000.json','["一松偃蹇蒼龍蟠，一石巉巖怒虎踞。", "我來題作龍虎軒，便恐風雲卷將去。"]'),
('fe67d39d-1ae7-437d-82e6-27e82a14ccf1','句','盛次仲','宋','宋诗','song-poetry','','[]','看來天地不知夜，飛入園林總是春。',16,'全唐诗/poet.song.39000.json','["看來天地不知夜，飛入園林總是春。"]'),
('b68d794f-816e-4166-8368-c86ba465f52d','句','任貫','宋','宋诗','song-poetry','','[]','一巖冷落高宗雨，滿洞清涼吉甫風。',16,'全唐诗/poet.song.39000.json','["一巖冷落高宗雨，滿洞清涼吉甫風。"]'),
('a13b7149-9bcc-4999-be4b-79b8ec573ef7','題雙流保國觀古柏','胡宗師','宋','宋诗','song-poetry','','[]','孔明廟前古柏奇，此木氣象猶過之。',64,'全唐诗/poet.song.39000.json','["孔明廟前古柏奇，此木氣象猶過之。", "幹東彷佛煙焰起，鐵龍空駕焚一枝。", "真人丹誠何所適，世傳乘鶴沖天飛。", "求詩道士心彌堅，試聽一誦工曹詩。"]'),
('64cc91a6-a062-4b41-90b1-658c100ee9e4','和王公覿望日與諸公會於大慈同賞山茶梅花','胡宗師','宋','宋诗','song-poetry','','[]','錦水黄金密印開，東南時望滯鹽梅。',64,'全唐诗/poet.song.39000.json','["錦水黄金密印開，東南時望滯鹽梅。", "得隨劍外同爲客，幸逐花前醉倒杯。", "白玉蘂高枝瘦碧，臙脂萼嫩葉低徊。", "綺羅不識清詩骨，須趁春風摸石來。"]'),
('b48a25f7-1483-4f02-838f-b24ea211c547','謹次君倚舍人寄題惠山翠麓亭韻','焦千之','宋','宋诗','song-poetry','','[]','余愛茲山昔屢遊，回環氣象冷清幽。',192,'全唐诗/poet.song.39000.json','["余愛茲山昔屢遊，回環氣象冷清幽。", "茂林滃鬱疊蒼翠，宴坐瀟灑風颼飀。", "密甃積蘚迸泉眼，飛翬比翼參雲頭。", "逕邊誰開青步障，客來共泛紫玉甌。", "每思乘興可獨往，塵纓未濯莫我留。", "勝處盡至心未厭，健步歷覽勢挾輈。", "平生趣向與時背，泉石夙志略已酬。", "茲山獨以泉品貴，乃得嘉名傳九州。", "譬人其中貴有物，源深混混難窮搜。", "支公此去久愈愛，自我佳句忘百憂。", "忽蒙遠寄煮巖壑，而我方欲千里求。", "願公早見疑蛇解，急詔當應易剡丹。"]'),
('85deafd0-e307-48e1-9094-732d71a15230','秀峰軒','焦千之','宋','宋诗','song-poetry','','[]','可憐均是山中寺，惟有幽軒對此山。',64,'全唐诗/poet.song.39000.json','["可憐均是山中寺，惟有幽軒對此山。", "雲擁秀峰來戶外，煙和濃翠入窗間。", "迴環似覺天形曲，登眺應疑地勢慳。", "他景縱能窮目力，爭如疏靜養疏閑。"]'),
('4b682a46-79da-440a-b075-4acb2a416831','聽松軒','焦千之','宋','宋诗','song-poetry','','[]','山頭未吐三更月，枕上惟間萬竅風。',32,'全唐诗/poet.song.39000.json','["山頭未吐三更月，枕上惟間萬竅風。", "疑是怒濤聲不敢，夜深飛雨過寒空。"]'),
('7f6f9df0-e22a-4a02-bc3d-ea008cfdf3db','偃松','焦千之','宋','宋诗','song-poetry','','[]','得地久蟠踞，參天多晦冥。',48,'全唐诗/poet.song.39000.json','["得地久蟠踞，參天多晦冥。", "月通深夜白，雪壓歲寒青。", "獨擁虯腰大，疑聞雨甲腥。", "深根勁坤軸，蕭瑟掛疏星。"]'),
('70e69d23-8739-4fb8-8c1b-afca98551b19','硯池','焦千之','宋','宋诗','song-poetry','','[]','蕭公事跡久塵泥，獨有當年洗硯池。',64,'全唐诗/poet.song.39000.json','["蕭公事跡久塵泥，獨有當年洗硯池。", "世俗所傳應彷佛，僧人獨得耿頹隳。", "小亭新構藏幽趣，一水中分疊舊基。", "遺澤泯然無處問，清風緬邈竹陰垂。"]'),
('844874a4-df11-4615-9405-a9d6c900c3dc','文君宅','焦千之','宋','宋诗','song-poetry','','[]','曾是文君宅，幽深鎮翠岑。',48,'全唐诗/poet.song.39000.json','["曾是文君宅，幽深鎮翠岑。", "澗松迷白鶴，溪石隱黄金。", "丹竈今猶在，簫台尚可尋。", "予來不能厭，誰共聽泉音。"]'),
('b825b18d-3077-4a1c-ae85-b953ad8a1b90','題兌溪驛','鮑娘','宋','宋诗','song-poetry','','[]','谿驛舊名彡，煙光滿翠嵐。',24,'全唐诗/poet.song.39000.json','["谿驛舊名彡，煙光滿翠嵐。", "須知今夜好，宿處是江南。"]'),
('6495574d-c50b-4aad-a2f2-c4d41fc4eda0','晚泊鳳凰驛次韻蔣穎叔','李孝伯','宋','宋诗','song-poetry','','[]','維舟亭下號三灣，萬疊青山一水間。',32,'全唐诗/poet.song.39000.json','["維舟亭下號三灣，萬疊青山一水間。", "偏愛澄江照天碧，飛來幾片白雲閑。"]'),
('e9da9fbf-9279-4eae-9a1d-c56ff1dda650','別韓魏公','石蒼舒','宋','宋诗','song-poetry','','[]','□□□□□□□，簾前二聖擁千官。',32,'全唐诗/poet.song.39000.json','["□□□□□□□，簾前二聖擁千官。", "唯有掃門霜鬢客，卻隨社燕入長安。"]'),
('1e2d1b94-838e-434a-9669-021368a58aa4','送程給事知越州','王珫','宋','宋诗','song-poetry','','["\u592a\u6e56"]','公住吳門枕太湖，風波不到十年餘。',64,'全唐诗/poet.song.39000.json','["公住吳門枕太湖，風波不到十年餘。", "過家乞得蓬萊郡，去國初拋麗正廬。", "闕下舊容乘駟馬，江頭急趁鱠鱸魚。", "都門送客今何盛，百首詩輕百兩車。"]'),
('a6607032-4a62-4554-8b94-5ef338511da6','遊西湖','劉庭式','宋','宋诗','song-poetry','','["\u897f\u6e56"]','勝地留連久，西湖得再遊。',48,'全唐诗/poet.song.39000.json','["勝地留連久，西湖得再遊。", "芰荷圍畫舫，楊柳護紅樓。", "風月蘇堤夜，煙雲葛嶺秋。", "買鮮沽美酒，且莫計觥籌。"]'),
('a1446482-4fb1-4732-b10f-f82a7465fbb9','題松下老人圖','劉庭式','宋','宋诗','song-poetry','','[]','古松蒼髯枝屈繳，失笑相驚在巖穴。',64,'全唐诗/poet.song.39000.json','["古松蒼髯枝屈繳，失笑相驚在巖穴。", "老翁手持綠玉杖，獨立西風雙鬢雪。", "修然野服山家容，平生我亦懷高風。", "彭澤歸來入圖畫，真有人間靖節翁。"]'),
('a6ab98c1-6407-40af-8a2e-c13bd31f8fc2','倚楹操  其一','王令','宋','宋诗','song-poetry','','[]','馬則食葵，而余則饑。',73,'全唐诗/poet.song.39000.json','["馬則食葵，而余則饑。", "盜則得羊，而余無兄。", "知誰爲此，兮余不聊生，誰余哀兮余思深。", "中忽忽兮外不知其嘯吟，野哉鄰妻兮曾謂余淫。", "以己逆人兮，余不知其何心。"]'),
('0bd7dd44-b27f-4cdc-9b18-ccc8a607d9f5','倚楹操  其二','王令','宋','宋诗','song-poetry','','[]','亡羊奔奔，豈不有鄰。',74,'全唐诗/poet.song.39000.json','["亡羊奔奔，豈不有鄰。", "子可閉門，亡羊不復。", "去何自逐，身則非牧。", "霧濛濛兮水漰漰，謂兄無行兮兄行。", "不忍一失於鄰而忍失厥身，雖然殞子之身兮，其亦如亡羊之鄰。"]'),
('3dd74cf5-13df-42ea-8e7c-f4198358faf9','鼷鼠操','王令','宋','宋诗','song-poetry','','[]','鼷鼠鼷鼠，實食其牛，牛則不知。',30,'全唐诗/poet.song.39000.json','["鼷鼠鼷鼠，實食其牛，牛則不知。", "彼牛彼牛，既卜以郊，傷則免之。"]'),
('77a11269-a6d7-4fa5-be4f-cb8aa1caf986','噫田操四章章六句寄呈王介甫  其一','王令','宋','宋诗','song-poetry','','[]','田彼黍矣，則食於秋。',30,'全唐诗/poet.song.39000.json','["田彼黍矣，則食於秋。", "我人之耕，載芟載薅。", "豈不憚勞，將食無攸。"]'),
('1c794c7e-ee8e-42a6-b242-76e1f6325bf8','噫田操四章章六句寄呈王介甫  其二','王令','宋','宋诗','song-poetry','','[]','田彼黍矣，幾不螽蝝。',33,'全唐诗/poet.song.39000.json','["田彼黍矣，幾不螽蝝。", "我人之耕，而不謀年。", "唯其不謀年，是用卒食于田。"]'),
('a4c2b1da-8d90-4ed6-a3e5-b70ccc2fb890','噫田操四章章六句寄呈王介甫  其三','王令','宋','宋诗','song-poetry','','[]','伐木伐木，無廢於勤。',30,'全唐诗/poet.song.39000.json','["伐木伐木，無廢於勤。", "不足柱榱，猶用以薪。", "豈弟君子，無易於人。"]'),
('40d2cfcc-88a8-4671-96c7-6effd78cd495','噫田操四章章六句寄呈王介甫  其四','王令','宋','宋诗','song-poetry','','[]','誰能采芹，不適有獲。',30,'全唐诗/poet.song.39000.json','["誰能采芹，不適有獲。", "果蓏樹之，則食其實。", "豈弟君子，孔敬且力。"]'),
('d4ae87f9-e99c-4e5a-818e-216a5aa4b1f6','終雌操','王令','宋','宋诗','song-poetry','','[]','林鳩之雌兮，不有巢而子兮，而有巢以止兮。',50,'全唐诗/poet.song.39000.json','["林鳩之雌兮，不有巢而子兮，而有巢以止兮。", "吁嗟乎已兮，終巢之從兮，吁嗟乎雄兮。", "終巢之樂兮，吁嗟乎鵲兮。"]'),
('7dc60840-f8f7-436e-98b9-c0ae4318de51','終風操','王令','宋','宋诗','song-poetry','','[]','雲之揚揚，油油其蒙。',140,'全唐诗/poet.song.39000.json','["雲之揚揚，油油其蒙。", "望我以雨，卒從以風。", "雲之油油，揚揚其去。", "我挽不可，泣立以佇。", "終風不休，終雲不留。", "不雨我田，不穀我收。", "巖巖南山，有川其下。", "徒能必雲，不能必雨。", "蓁蓁者林，有越而樛。", "人伐以歸，我徂安休。", "嗟今之人，顧己是求。", "有顧者木，曷爲而材。", "大折以薪，小生何哉。", "嗟今之人，誰同我哀。"]'),
('04d2e61f-cd15-42ba-b1c3-851910e2c961','夕日操  其一','王令','宋','宋诗','song-poetry','','[]','煜煜夕日，逝何忽兮。',43,'全唐诗/poet.song.39000.json','["煜煜夕日，逝何忽兮。", "有輝而星，爾留曷其。", "我視而冥，我適不行。", "我盡日乃傾，獨何求於爾星。"]'),
('b1f6bedc-2ff7-4e99-98b8-35996176e919','夕日操  其二','王令','宋','宋诗','song-poetry','','[]','煜煜夕日，不尚有朝。',30,'全唐诗/poet.song.39000.json','["煜煜夕日，不尚有朝。", "皦皦君子，去誰繇招。", "死如可從，生百不聊。"]'),
('72147676-6160-4671-b016-a341178efcaf','夕日操  其三','王令','宋','宋诗','song-poetry','','[]','繹繹道周，伊誰之園。',31,'全唐诗/poet.song.39000.json','["繹繹道周，伊誰之園。", "夙不築自垣，今安以樊。", "人各有心，亦不思旃。"]'),
('c6ed3898-950c-4a10-b7a0-63c14d12d6ba','於忽操  其一','王令','宋','宋诗','song-poetry','','[]','於忽乎，不可以爲，其又奚爲。',94,'全唐诗/poet.song.39000.json','["於忽乎，不可以爲，其又奚爲。", "離婁之精，夜何有於明。", "瞽曠之耳，聾者亦有爾。", "束王良之手兮，後車載之。", "前行險以既覆兮，後逐逐其猶來。", "雖目盼而心駭兮，顧其能之安施。", "委墨繩以聽人兮，雖班輸亦奚以爲。"]'),
('c12f8317-60f6-462a-8efa-6297367e16c3','於忽操  其二','王令','宋','宋诗','song-poetry','','[]','於忽乎，不可以爲，其又奚爲。',63,'全唐诗/poet.song.39000.json','["於忽乎，不可以爲，其又奚爲。", "椽櫨桷榱之累重，顧柱小之奈何。", "方風雨之晦陰，行者艱而莫休，居者坐以笑歌。", "不知壓之忽然兮，其謂安何。"]'),
('d2bd65a5-0135-482f-a8dc-8065addb40f0','於忽操  其三','王令','宋','宋诗','song-poetry','','[]','於忽乎，不可以爲，其又奚爲。',58,'全唐诗/poet.song.39000.json','["於忽乎，不可以爲，其又奚爲。", "謂雞斯飛，誰得而覊。", "謂豕斯突，何取於縛。", "是皆以食而得之，吾方饑而噫。", "雞兮豕兮，死以是兮。"]'),
('718e1f1a-3ded-4ed5-af1f-76ec74d3b16a','辭粟操','王令','宋','宋诗','song-poetry','','[]','食人之粟，飽復何爲。',48,'全唐诗/poet.song.39000.json','["食人之粟，飽復何爲。", "當人之賜，罪亦何辭。", "有以我爲是兮，豈無以我爲非。", "已兮已兮，吾何以勝人之言兮。"]'),
('f9e1e3bc-3fd7-4054-b1e2-e97f9c50419a','陬操','王令','宋','宋诗','song-poetry','','[]','行曷爲兮天下，老吾身而不歸。',88,'全唐诗/poet.song.39000.json','["行曷爲兮天下，老吾身而不歸。", "人固舍吾而弗從，吾安得狥人而從之。", "昔所聞其是兮，今也見之則非。", "嗟若人之弗類，尚何足以與爲。", "彼天下之皆然，嗟予去此而從誰。", "信亦命已矣夫，固行兮而曷疑。"]'),
('9d8d73b2-16b6-4799-931e-80be488e893a','樗髙操','王令','宋','宋诗','song-poetry','','[]','崇崇北丘，其上有樗。',46,'全唐诗/poet.song.39000.json','["崇崇北丘，其上有樗。", "遠者以爲梁，或者爭以柱。", "就而睨之，曾無事於欂櫨。", "嗚呼木乎，期我於遠者歟。"]'),
('556c72b2-f7be-4873-a4ab-75d6d86e291d','松休操','王令','宋','宋诗','song-poetry','','[]','蔚彼南山，有松其猗。',55,'全唐诗/poet.song.39000.json','["蔚彼南山，有松其猗。", "孰堂而基，孰壞不支。", "遠莫與識，其斬以狙猿之杙。", "是近是度，謂家之無桷。", "嗚呼松乎，余歸此休乎。"]'),
('4dd297dc-50e1-4245-88b6-e28320121ebb','南山之田贈王介甫','王令','宋','宋诗','song-poetry','','[]','南山之田兮，誰爲而蕪。',141,'全唐诗/poet.song.39000.json','["南山之田兮，誰爲而蕪。", "南山之人兮，誰教墮且。", "來者何爲，而往者誰趾。", "草漫靡兮，不種何自。", "始吾往兮無耜，吾將歸兮客吾止。", "要以田兮寄我治，我耕淺兮穀不遂。", "耕之深兮石撓吾耒，吾耒撓兮耕嗟難。", "雨專水兮日專旱，借不然兮穎以秀。", "螟懸心兮螣開口，我雖力兮功何有。", "雖然不可以已兮，時寧我違而我無時負。"]'),
('1bf65fef-2be8-49e0-b0b4-c99e141216ea','送黄莘任道赴揚州主學','王令','宋','宋诗','song-poetry','','[]','子之來兮東之舟，暮不至兮誰牽以留。',171,'全唐诗/poet.song.39000.json','["子之來兮東之舟，暮不至兮誰牽以留。", "子之去兮西之馬，朝何亟兮不秣而駕。", "駕胡適兮徂揚，揚之郊兮泮之央。", "泮之冰兮春之水，泮之莪兮芽茁於涘。", "泮之鷺兮潔白以止，泮之土兮除掃不滓。", "泮之人兮立以望子，久不可待兮足併以跂。", "子未至兮謂奚，子之至兮何以慰之。", "招其來而挽其去，納以寛而不嚴以恕。", "增其長而救厥玷失，培其根而使華以實。", "泮之人兮子喜，子先何適兮不夙吾治。"]'),
('b11e0171-ffc4-418f-ba4b-ac4ee78377b6','送黄任道歌  其一','王令','宋','宋诗','song-poetry','','[]','吾門之達兮，爾可款以入兮。',64,'全唐诗/poet.song.39000.json','["吾門之達兮，爾可款以入兮。", "進之不時兮，吾豈不爾待兮。", "何後未至兮，前已過之。", "來猶有望兮，去何勝追。", "俯吾著而即兮况堂若室兮，又歌曰。"]'),
('a184bccc-5e9e-4e84-b9f5-b2ef46c0235f','送黄任道歌  其二','王令','宋','宋诗','song-poetry','','[]','敖耶學耶，爲來往耶。',47,'全唐诗/poet.song.39000.json','["敖耶學耶，爲來往耶。", "衣之荼荼，冠膝膝耶。", "何進趨之舒，不若退走之速耶。", "雖終不吾聽兮，猶無貽我嗟。"]'),
('79e8c942-66c5-49e5-8e1a-9cfe47442093','翩翩弓之張兮詩三章寄王介甫  其一','王令','宋','宋诗','song-poetry','','[]','翩翩弓之張兮，其亦弛則藏兮。',34,'全唐诗/poet.song.39000.json','["翩翩弓之張兮，其亦弛則藏兮。", "惟此乘馬，不秣而駕。", "維彼乘駒，不駕以芻。"]'),
('7b7c8d13-1321-45c2-a6c8-d958d36eede9','翩翩弓之張兮詩三章寄王介甫  其二','王令','宋','宋诗','song-poetry','','[]','翩翩弓之觩兮，其亦弛則櫜兮。',34,'全唐诗/poet.song.39000.json','["翩翩弓之觩兮，其亦弛則櫜兮。", "廐我乘馬，不適以駕。", "同彼乘駒，亦食以芻。"]'),
('484126ef-e26c-41f7-b6e3-f490feb3d36e','翩翩弓之張兮詩三章寄王介甫  其三','王令','宋','宋诗','song-poetry','','[]','瞻彼車兮，既徴其輻。',30,'全唐诗/poet.song.39000.json','["瞻彼車兮，既徴其輻。", "有駒斯服，有馬斯牧。", "心之憂矣，聊以反覆。"]'),
('e7f1d25f-636c-4132-900c-514eae9af34f','我策我馬寄王介甫  其一','王令','宋','宋诗','song-poetry','','[]','我策我馬將安從，人之冲冲誰適逢，言歸於東。',21,'全唐诗/poet.song.39000.json','["我策我馬將安從，人之冲冲誰適逢，言歸於東。"]'),
('53d2d4d6-d673-4a20-9af8-bc5b0c81e590','我策我馬寄王介甫  其二','王令','宋','宋诗','song-poetry','','[]','我策我馬將安求，人之悠悠誰適謀，言東之遊。',21,'全唐诗/poet.song.39000.json','["我策我馬將安求，人之悠悠誰適謀，言東之遊。"]'),
('0a2d309e-1179-42f1-94ab-7cd2ec7f334b','我策我馬寄王介甫  其三','王令','宋','宋诗','song-poetry','','[]','井則有泉，渇者俯之。',30,'全唐诗/poet.song.39000.json','["井則有泉，渇者俯之。", "燎之陽陽，寒者附之。", "君子則髙，吾則仰之。"]'),
('70c39d6e-9e15-4f3d-b451-7d8a547aa5cc','無衣一首招黄任道歸','王令','宋','宋诗','song-poetry','','[]','豈曰無衣，不能素裳。',201,'全唐诗/poet.song.39000.json','["豈曰無衣，不能素裳。", "縫齊有鏘，直韍以方。", "豈曰無衣，不能素履。", "絇以爲戒，夙夜以無怠。", "素裳戔戔，誰涉不褰。", "素履几几，誰涉不止。", "始也何所爲，我推我宗。", "惡余之無從，睢盱以爲恭。", "今也既宣我力，羣心慝慝。", "毁予以自德，曾莫肯己直。", "爾我目矣，何爲而眊聰亦云聽，曾莫有告。", "謀及於道，佛且訕以笑。", "謂白蓋黑，或者亦以赤。", "行何必有足，巧言以成迹。", "以我有常，從爾罔極。", "翩翩者舟，在河之涘。", "人待不至，亦以自濟。", "嗟爾君子，歸歟予遲。"]'),
('76150147-72d1-4919-b742-58249568bf1c','效醉翁吟','王令','宋','宋诗','song-poetry','','[]','山巖巖兮谷幽幽，水無人兮自流。',219,'全唐诗/poet.song.39000.json','["山巖巖兮谷幽幽，水無人兮自流。", "始與誰兮樂此，昔之遊者兮今非是。", "清吾樽兮潔吾斝，欲御以酒兮誰宜壽者。", "山蘼春兮野鹿遊，亭無人兮飛鳥下。", "喜公有遺兮樂相道語，從人以遊兮告以其處。", "髙公所望兮卑公所遊，公爲廬兮燕笑以休。", "摭山果以侑酒，登溪魚而供羞。", "仰春木以搴華，俯秋泉而潄流。", "公朝來兮暮去，肩乘輿兮馬兩御。", "來與我民兮不間以處，誰不此留兮公則去遽。", "花垂實兮樹生枝，我公之去兮今忽幾時。", "知來之不可望兮，悔去而莫追。", "人皆可來兮公何不歸，青山宛宛兮誰爲公思。"]'),
('0cfa7fc4-627d-4fe2-a8ca-9e41b279443e','桃源行送張頡仲舉歸武陵','王令','宋','宋诗','song-poetry','','[]','山環環兮相圍，溪亂亂兮漣漪。',368,'全唐诗/poet.song.39000.json','["山環環兮相圍，溪亂亂兮漣漪。", "花漫漫兮不極，路繚繚兮安之。", "棄舟步岸兮欲進復疑，山平阜斷兮忽得平原巨澤，莽不知其東西。", "桑麻言言兮田野孔治，風回地近兮將亦聞乎犬雞。", "信有居者兮，盍亦往而從之。", "語何爲乎獨秦，服何爲乎異時。", "見何驚兮遌錯，貌何野而棲遲。", "問何迂兮古昔，聽何感而喑噫。", "秦崩晉代兮河覆山移，天顛地陷兮何有不知。", "上無君兮孰主，下無令兮孰隨。", "身羣居而孰法，子娶嫁而孰媒。", "既棄此而不用，何久保而弗離。", "豈畏伏於亂世兮，猶魚潛而鳥棲。", "寧知君之爲擾兮，不知上之可依。", "豈懲薄而過厚兮，遂篤信而忘欺。", "將久習以成俗兮，亦耳目之無知。", "眷叙言之綢繆，與歡意之依稀。", "及情終而禮闋，忽回腸而念歸。", "更酸顔而慘頞，嘆異世之從容。", "惜暫遇之偶然，嗟永離而莫同。", "舟招招而去岸，帆冉冉以行風。", "豁山靄之披袪，赫曉日之曈曨。", "驚迴舟而返盼，忽逕斷而溪窮。", "目恍惚兮圖畫，心輈張兮夢中。"]'),
('2db7104c-5ac1-4695-9328-026d43f65cfb','我思古人答焦千之伯强','王令','宋','宋诗','song-poetry','','[]','我思古人兮，不古今之異時。',124,'全唐诗/poet.song.39000.json','["我思古人兮，不古今之異時。", "生兹世之誰期，欲勿思而奈何。", "獨斯人之不見，聊永懷而自歌。", "樂吾行之舒舒，忘兹世之汲汲。", "睇萬里以自驚兮，豈寧俯以効拾。", "載重道遠兮，予欲行而誰與。", "累九鼎以自重兮，顧尪羸之弗舉。", "矯身以爲衡兮，權世之重輕。", "廣道以爲路兮，聽人之來去。"]'),
('e9a5ff4c-fd43-45ae-b919-cb8d3e6e4003','魯仲連辭趙歌','王令','宋','宋诗','song-poetry','','[]','秋風起兮天寒，壯士醉酒兮歌解顔。',103,'全唐诗/poet.song.39000.json','["秋風起兮天寒，壯士醉酒兮歌解顔。", "螳螂何怒兮轍下，蟻何鬬兮穴間，紛擾擾兮誰者則賢。", "井方崩兮治隧，屋且壓兮雕椽。", "生則役兮弗繫念此，禍至而知悔兮，身忽焉其已死。", "陶唐虞夏兮，今則古矣。", "彼秦且帝兮，連有蹈東海而死耳。"]'),
('62532e5b-b11e-45e5-9bbc-bb9d0ef9b0c0','山中詞','王令','宋','宋诗','song-poetry','','[]','山中兮何游，登彼山兮樂天髙。',159,'全唐诗/poet.song.39000.json','["山中兮何游，登彼山兮樂天髙。", "棄吾馬以取步，降吾車兮足兩履。", "石當道兮行旁，木礙上兮下俯。", "曾蹈險之非艱，聊憑髙兮下顧。", "何所視之乃牛，而獨見之如鼠。", "彼促促者出其下兮，曾其身之非傴。", "吁嗟徂兮，離婁之死則已。", "古之不較其爲短長兮，何獨計其髙下。", "山髙兮崔嵬，山之路兮百折而千回。", "趨前行而就挽，笑顧後使推之。", "彼游者誰兮，何以子之車來。"]'),
('959388f5-a121-4726-9410-5ffb3bf8b49a','江上詞  其一','王令','宋','宋诗','song-poetry','','[]','江之水兮東流，泝湍流兮寄人舟。',79,'全唐诗/poet.song.39000.json','["江之水兮東流，泝湍流兮寄人舟。", "舟無袽兮載函重，風乘波兮棹人用。", "濟不濟兮奈何，横中流兮涕滂沱。", "來何爲兮不待，今雖嗟兮安悔。", "舟方乘兮人不吾以，覆且溺兮我則同人死。"]'),
('c99aa76b-5ea0-4fe3-b549-f8afc90231d2','江上詞  其二','王令','宋','宋诗','song-poetry','','[]','江之水兮東流，濟欲濟兮何由。',87,'全唐诗/poet.song.39000.json','["江之水兮東流，濟欲濟兮何由。", "水浸浸兮灘露，暮濤下兮夜潦收。", "舟不行兮推之於陸，力不足兮汗顔，行無由兮塗足。", "時不逝兮奈何，歸日暮兮塗遠，去風髙兮水波。", "行躊躇兮佇望，聊逍遥兮永歌。"]'),
('3eb7df4d-044a-4e8b-87de-88040be93dbc','江上詞  其三','王令','宋','宋诗','song-poetry','','[]','江之水兮東流，沿湍流兮望歸舟。',50,'全唐诗/poet.song.39000.json','["江之水兮東流，沿湍流兮望歸舟。", "舟來歸兮何時，步芳洲兮濯足，陟南山兮采薇。", "江風波兮日暮，望夫人兮未來。"]'),
('cb6fe57b-6768-41b3-934f-2bd42780af97','江上詞  其四','王令','宋','宋诗','song-poetry','','[]','江之水兮東流，沿湍流兮望歸舟。',67,'全唐诗/poet.song.39000.json','["江之水兮東流，沿湍流兮望歸舟。", "風滔滔兮浪波苦，嗟往者兮未還，惜行人兮將去。", "去何適兮歸何時，執子手兮牽子衣。", "行何如兮來復，濟豈無兮他時。"]'),
('c87deeea-a631-4165-b547-919d2765c84a','寒林石屏','王令','宋','宋诗','song-poetry','','[]','虢山之遠數千里，虢石之重難將持。',384,'全唐诗/poet.song.39000.json','["虢山之遠數千里，虢石之重難將持。", "舟車虢來每苦重，釜盎尚棄不肯携。", "苟非世尚且奇怪，孰肯甚遠載以來。", "何况虢人自珍秘，得一不換千瓊瑰。", "流傳中州盛稱賞，主以詫客客見祈。", "世人賤真珍貴假，見者喜色留膚皮。", "强材美幹立修蔭，羅列滿野誰復窺。", "我嘗客坐例一見，實亦可愛小且奇。", "初疑秋波瑩明凈，魚子變怪成蛟螭。", "鱗鬚爪角尚小碎，但見蜿蜒相參差。", "又如開張一尺素，醉筆倒畫胡髯髭。", "如何石上非自然，猶是軟弱從風枝。", "髙樓曉憑秋色老，烟容雨氣相蒙垂。", "喬林隱約出天際，醉目遠暝分茫微。", "不然誰家老圖畫，破碎偶此一片遺。", "借令人手弄點畫，尚恐巧拙成瑕疵。", "如何石理自生長，安得當世無猜疑。", "髙堆黄金募辯說，萬口利鋭如磨錐。", "或云南山產巨怪，意欲手把乾坤移。", "先偷日月送巖底，次取草木陰栽培。", "天公怒恐浸成就，六丁桃斧摩雲揮。", "世人乘此得分裂，鍛琢片段貿財貲。", "至今風雨虢山夜，樹石號作鬼神悲。", "又云春氣入山骨，欲自石裏生蒿藜。"]'),
('54ed0d26-2bb4-4b3c-a5c8-6a702c880c21','贈慎東美伯筠','王令','宋','宋诗','song-poetry','','[]','世網掛士如蛛絲，大不及取小綴之。',224,'全唐诗/poet.song.39000.json','["世網掛士如蛛絲，大不及取小綴之。", "宜乎倜儻不低斂，醉脚倒踏青雲歸。", "前日才能始誰播，一口驚張萬誇和。", "雷公訴帝喘似吹，盛恐聲名塞天破。", "文章喜以怪自娛，不肯裁縮要有餘。", "多爲峭句不姿媚，天骨老硬無皮膚。", "人傳書槧莫對當，破卵驚出鸞鳳翔。", "間或老筆不肯屈，鐵索縳急蛟龍僵。", "少年倚氣狂不覊，虎脇插翼赤日飛。", "欲將獨立跨萬世，笑誚李白爲痴兒。", "四天無壁財可家，醉膽憤痒遣酒拏。", "欲偷北斗酌竭海，力拔太華鏖鯨牙。", "世儒口軟聲如蠅，好於壯士爲忌憎。", "我獨久仰願得見，浩歌不敢兒女聲。"]'),
('be18c45d-01ae-4e78-b85d-89749df7e522','吕氏假山','王令','宋','宋诗','song-poetry','','[]','鯨牙鯤鬛相摩捽，巨靈戯撮天凹突。',64,'全唐诗/poet.song.39000.json','["鯨牙鯤鬛相摩捽，巨靈戯撮天凹突。", "舊山風老狂雲根，重湖凍脱秋波骨。", "我來謂怪非得真，醉掲碧海瞰蛟窟。", "不然禹鼎魑魅形，神顛鬼脇相撐挾。"]'),
('cd20a488-eb55-4be4-8087-52d6a9824a82','偶聞有感','王令','宋','宋诗','song-poetry','','[]','鯨豗海翻飛陸塵，鐡房孤劍枯紫鱗。',64,'全唐诗/poet.song.39000.json','["鯨豗海翻飛陸塵，鐡房孤劍枯紫鱗。", "擠排壯士仆不起，天公始自誇爲神。", "誰令夷路牙枿横，不拔不鋤安得平。", "長星作彗倘可假，出手爲掃中原清。"]'),
('166b1b54-d2e9-4c5d-b6c0-adf6a959a6cc','寄題韓丞相定州閲古堂','王令','宋','宋诗','song-poetry','','[]','始聞定作閲古堂，又聞定有閲古詩。',384,'全唐诗/poet.song.39000.json','["始聞定作閲古堂，又聞定有閲古詩。", "揚之遠定五千里，思得兩翅擘以飛。", "偶聞人來說堂事，初敝兩壁無塵疵。", "間時公來命繪匠，親以玉指交畫揮。", "教令某載若某狀，匠拜奉命唯不辭。", "左圖守相父母吏，右狀將帥熊羆姿。", "長冠峩峩偉笏佩，鬬以玄白爲裳衣。", "屹如丁寧立以議，遜若避讓行而隨。", "圖成儼毅色可讋，過吏不敢竊目窺。", "仍令大筆署行事，寫出黑膽朱肝脾。", "死者有靈如不冺，合有英氣來附兹。", "故公之謀不知出，宜有神鬼陰助其。", "茫茫九泉謂巳朽，豈意一旦存形儀。", "請留中壁素莫繪，待千歲後公以歸。", "當搜國匠第一手，狀寫公像存依稀。", "要知文完武繩備，遺與萬世瞻思資。", "我知觀者定墮淚，不復峴首羊公碑。", "又聞當世大手筆，磊砢詩句相撐支。", "手搏蛟龍拔解角，爪擘虎豹全脱皮。", "鄆州溪堂遂寂寞，韓詩塵蔽人不吹。", "想應從此傳萬世，粹玉貫串珠縈纍。", "小戎何爲而縮伏，久滯公斧血不滋。", "何時功成事業就，兩手一掃清三垂。", "歸來天子喜以頷，泰階輝煥平無欺。"]'),
('353043ce-117f-4c72-b8fb-3d6164e7e9ad','龍興雙樹','王令','宋','宋诗','song-poetry','','[]','春城花草窮朱殷，俗兒趁走脚欲穿。',224,'全唐诗/poet.song.39000.json','["春城花草窮朱殷，俗兒趁走脚欲穿。", "閑來無悰喜自適，時到雙樹爲奇觀。", "莊如天官植幢蓋，毅若壯士蒼衣冠。", "老枝又芽忽並出，似欲併力擎青天。", "靈根深盤不可究，疑與地軸相拘攣。", "不知培栽竟誰手，而又始植爲何年。", "行捫步遶不可問，但見茂色連雲烟。", "東風牽人少游此，佛屋日日重門關。", "雖有大蔭人不及，於此尤得志士憐。", "束蒿爲楹樗爲柱，居者略不憂其顛。", "乃令遺材抱美植，不得總載桷與椽。", "髙堂傾欹未支柱，匠者日亦經其邊。", "不思大幹有强用，反以斧鈍難其堅。", "吁今誰是愛材者，定知惜此雙樹篇。"]'),
('971a90b9-b0f3-4358-94b2-f390ced7bb5f','原蝗','王令','宋','宋诗','song-poetry','','[]','蝗生於野誰所爲，秋一母死遺百兒。',384,'全唐诗/poet.song.39000.json','["蝗生於野誰所爲，秋一母死遺百兒。", "埋藏地下不腐爛，疑有鬼黨相收持。", "寒禽冬饑啄地食，拾掇穀種無餘遺。", "吻惟掠卵不加破，意似留與人爲饑。", "去年冬温臘雪少，土脉不凍無冰凘。", "春氣蒸炊出地面，戢戢密若在釡糜。", "老農頑愚不識事，小不撲滅大莫追。", "遂令相聚成氣勢，來若大水無垠涯。", "蓬蒿滿眼幸無用，爾縱嚼盡誰爾譏。", "而何存留不咀嚼，反向禾黍加傷夷。", "鴟鴉啄啣各取飽，充實腸腹如撐支。", "兒童跳躍仰面笑，却愛甚密嫌疏稀。", "吾思萬物造作始，一一盡可天理推。", "四其行蹄翼不假，上既載角齒乃虧。", "夫何此獨出羣類，既使躍跳仍令飛。", "麒麟千載或一見，仁足不忍踏草萎。", "鳳凰偶出即爲瑞，亦曰竹食梧桐棲。", "彼何甚少此何衆，况又口腹害不訾。", "遂令思慮不可及，萬目仰面號天私。", "天公被誣莫自辨，慘慘白日陰無輝。", "而余昏狂不自度，欲盡物理窮毫絲。", "要袪衆惑運獨見，中夜力爲窮研思。", "如知在人不在天，譬之蚤虱生裳衣。", "捫搜剔撥要歸盡，是豈人者尚好之。"]'),
('5b85c59a-88e9-4432-974e-42443ae4b5ff','别老者王元之二','王令','宋','宋诗','song-poetry','','[]','二夷之來始何自，乘我中國方迷昏。',192,'全唐诗/poet.song.39000.json','["二夷之來始何自，乘我中國方迷昏。", "各投陰誣張誕妄，尋附罅隙爲株根。", "例誇難能壓甚畏，釣博天下要推尊。", "其流汗漫已不制，尚自冲蕩洪其源。", "一戎中侵欲內侮，猶遣萬甲疆場屯。", "何哉二戎日內壞，不思刷去仍資存。", "嘗聞古人第氣類，皆以夷敵禽獸論。", "惜乎無倫弗禮義，幾希不得人相捫。", "吾觀世之陷此者，不啻火立足向燔。", "豈期之子既自悟，不思跳出乃欲𨀛。", "余方往就西北食，聞子亦整東南轅。", "雖然去就固在子，安忍惜手不試援。"]'),
('a1c40cb8-ec88-45df-adcc-20a87ef9964a','答李公安','王令','宋','宋诗','song-poetry','','[]','自古名士紛如毛，多見博带裳衣褒。',224,'全唐诗/poet.song.39000.json','["自古名士紛如毛，多見博带裳衣褒。", "如其可學不可逮，三滿夫子皆儒豪。", "其文淵源尤可愛，江海駕蕩相吞滔。", "方吾少時未識愧，引領日望聲齊髙。", "窮吭折吻氣力絕，始盡退伏非所曹。", "近來筆硯思置去，新詩苟有亦自韜。", "閑時屢索不肯出，若欲獻貴賤厥操。", "李君南來久有日，我始得見試捾搯。", "忽逢詩挑欲我接，快句鋭利磨矛刀。", "要令口獻近章句，若急敵迫不可逃。", "顔頳舌澀不可吐，滯若亂緒强抽搔。", "惟其自陳尚訥怍，况又聽者寧不聱。", "退歸自與敗者比，誓欲棄甲弓矢櫜。", "新詩見投又須和，咄哉自守何不牢。"]'),
('47538f45-785e-47c5-a04d-5594f1ec9c3d','廣王醇正叔二思詩','王令','宋','宋诗','song-poetry','','[]','木落不去根，水流常背源。',120,'全唐诗/poet.song.39000.json','["木落不去根，水流常背源。", "木落方病寒，尚覆本根温。", "水流忘由來，散亂卑濕牽。", "讀子二思詩，起予二者言。", "木實類君子，老有孝感存。", "水亦人迹然，動由名利牽。", "使我父母感，一夕身百翻。", "人世但可悲，小官何足言。", "情義有相奪，心迹固此分。", "勉之多自寛，行見西歸轅。"]'),
('6ed898f0-dda7-4afb-936e-e6f02e963962','晝睡  其一','王令','宋','宋诗','song-poetry','','[]','太古一去浩萬世，百智競起紛修治。',144,'全唐诗/poet.song.39000.json','["太古一去浩萬世，百智競起紛修治。", "交將砭刀潰瘡痏，縱得平好無完皮。", "傾山竭河論麯水，都投大海爲酒池。", "中間秫稻不滿掬，日益醖釀成澆漓。", "不知淳風竟何適，萬手齊舉招不回。", "北窗清疏鳥聲好，晝榻自穩間支龜。", "塵埃不到日影薄，枕簟拂拂生凉颸。", "四支舒安百慮廢，彷彿認得太古遺。", "散魂怡愉不旁適，心肺正靜無邪思。"]'),
('3eee06e0-8b79-4f8c-9956-59a2499098c0','晝睡  其二','王令','宋','宋诗','song-poetry','','[]','因能不有世俗夢，獨與淳氣相盤嬉。',304,'全唐诗/poet.song.39000.json','["因能不有世俗夢，獨與淳氣相盤嬉。", "伏羲持刀刻爻畫，古意蕩盡無銖釐。", "睡無吉凶無得失，縱欲强卦安能爲。", "故能獨存至今日，人各已有反不知。", "須知睡義大亦盛，豈獨床第誇昏迷。", "君子勞心事業暇，得時休息安天倪。", "小人一心包萬險，迨退就枕皆平夷。", "使其睡心大充擴，去與君子何毫絲。", "當年嘗聞曲肱樂，曾及至聖宜無非。", "何况於夢更有得，不見公旦因嗟衰。", "後來紛紛不知樂，舍去大路趨邪歧。", "竹林猖狂事飲鍛，捫撥蚤虱無留衣。", "好惡紙上浩萬端，竟不及此亦可嗤。", "蚊虻紛然始誰造，一一口吻如針錐。", "食人肌膚得腹飽，不解默去猶鳴飛。", "攘拳揮臂不可却，聒耳不異笙匏吹。", "雖然今尚爾無奈，當有獵獵秋風時。", "爾軀糜潰爾口壞，我床安穩我枕欹。", "平時多賢貴不及，會日偃瞑休恬怡。"]'),
('b110c306-b457-47b1-9125-c6408d5fb777','哭辭','王令','宋','宋诗','song-poetry','','[]','一哭摧心肝，屢哭彫朱顔。',48,'全唐诗/poet.song.39000.json','["一哭摧心肝，屢哭彫朱顔。", "心肝摧日痛，朱顔彫日乾。", "二十人未壯，我衰已毛斑。", "古人不得見，今人誠可嘆。"]'),
('34303523-80c9-41c2-abf6-d6f16da071b7','古興','王令','宋','宋诗','song-poetry','','[]','出門將何從，與物隨紛紛。',48,'全唐诗/poet.song.39000.json','["出門將何從，與物隨紛紛。", "不得所欲爲，還與俗人羣。", "外跡久已非，獨嗟心所存。", "自信有可羞，彼人何足論。"]'),
('02e7e901-c73b-4c4f-8a94-fcfd9d9eb398','秋居','王令','宋','宋诗','song-poetry','','[]','秋居寒蕭疏，秋意愁交并。',48,'全唐诗/poet.song.39000.json','["秋居寒蕭疏，秋意愁交并。", "飽犬無吠志，饑烏有凶聲。", "庭空鳥交下，墻穴鼠更爭。", "浩歎欲出門，日暮不可行。"]'),
('a1dcf802-81e5-45bf-b0e9-fbac90ad363e','雪中聞鳩','王令','宋','宋诗','song-poetry','','[]','孰謂拙者鳩，已厭不可彈。',84,'全唐诗/poet.song.39000.json','["孰謂拙者鳩，已厭不可彈。", "吾寒方病雪，爾何雪自喚。", "寒城千萬家，什伍赤兩骭。", "通衢結沮冰，走指堕或半。", "門閉市無人，竈冷煙不爨。", "俗以雪爲賀，我獨雪之歎。", "富貴宜爲憂，不憂亦何患。"]'),
('0fb09a23-9e23-4c79-a62a-c3053b96e1c3','吳江長橋','王令','宋','宋诗','song-poetry','','[]','老匠鐵手風運斤，一挾刃入千山髠。',188,'全唐诗/poet.song.39000.json','["老匠鐵手風運斤，一挾刃入千山髠。", "明堂有在不見用，此爲失地猶濟人。", "西潴巨澤江海通，獰風撼地波撐空。", "當道獨能支地險，更東安得與天窮。", "莫比垂天紳，莫比跨地带。", "渇龍枯死乾無鱗，絕海失舟踏鯨背。", "秦帝東遊逐仙跡，累重肉多飛未得。", "三洲水隔不到山，借得紫虹千萬尺。", "平時塵土埋英雄，吾亦棄劍來遊東。", "欲觀水盡朝宗海，安得身乘破浪風。", "爲約他年可歸處，頻倚欄干不思去。", "季鷹范蠡不足奇，待我爲名千古歸。"]'),
('b249382d-7688-4183-bf1c-fa3407771096','題滿氏申申亭','王令','宋','宋诗','song-poetry','','[]','申申亭者名自誰，河東丈人身銘之。',320,'全唐诗/poet.song.39000.json','["申申亭者名自誰，河東丈人身銘之。", "方其作亭自休息，固欲申暢名其題。", "雖然自奉頗幽樂，豈敢兼忽當世爲。", "若日所憂非所及，因以遯世無悶辭。", "丈人疏髙喜自適，去不限約來無時。", "門無賓僚車馬絕，室有几杖衣冠欹。", "夜徑行招海月伴，晝榻坐與天雲期。", "春林喧和鳥聲好，勝聽俗論相啞吚。", "塵埃縱爾得風力，卒不到此徒自飛。", "亭前朱朱有冶態，亭下白白無俗姿。", "好木留存竟見實，惡草鋤拔無容茨。", "嘗聞景勝未易敵，須有大句相參差。", "故吾經年不敢往，日望詩老力可支。", "偶來爲游適已晚，花梢尚有春餘遺。", "髙哦遶樹惜時節，拾嚼紅庁行逶遲。", "回看北林竹萬顆，寒氣欲起凌人威。", "清風時來助氣勢，寒甲夜聚言語私。", "方將投間日來此，脚踏樹下成交蹊。", "無端塵土又爲隔，明日跨馬西北馳。", "心思夢好定頻到，不必直俟歸風吹。"]'),
('33cb15c5-fbe5-45be-b5c4-41c0c2430888','晚歲','王令','宋','宋诗','song-poetry','','[]','晚歲意不適，新詩老無情。',48,'全唐诗/poet.song.39000.json','["晚歲意不適，新詩老無情。", "萬古共一嘆，百年行半生。", "貧憂世累重，賤喜身責輕。", "義有不可嗟，非吾不能平。"]'),
('06b30586-2d79-4369-ad53-f00fce531174','聞太學議','王令','宋','宋诗','song-poetry','','[]','白日流上天，牛蝨無遁形。',96,'全唐诗/poet.song.39000.json','["白日流上天，牛蝨無遁形。", "萬目盡爲用，而不駭日明。", "穴鼠夜值螢，嗾嗾相聚驚。", "鼠穴不日通，鼠足不日行。", "已矣不自識，乃此螢爝矜。", "鮞鰕陷井坎，莫與江海爭。", "籠禽不失飛，詎識雲漢冥。", "咄哉浮薄兒，勉爲髙大營。"]'),
('891d5e12-f659-4953-b940-afff274290d1','贈别晏成績懋父太祝','王令','宋','宋诗','song-poetry','','[]','懋甫相門兒，家世踏纓紞。',240,'全唐诗/poet.song.39000.json','["懋甫相門兒，家世踏纓紞。", "早年綴官簿，青衫蔚於菼。", "本宜多驕矜，不謂鋭意敢。", "意貪英雄交，一手欲四攬。", "偶來濫予會，臂搦首已頷。", "酒獰誇胸襟，頂踵都一膽。", "壯心羞摧藏，義內喜葅歜。", "要言相死從，顧豈苟難斬。", "聽其自陳論，峭拔不平漸。", "要之當一切，固令不黤黯。", "憶予少年時，亦自喜黠㶒。", "於今老而悔，壯意日凋减。", "惜夫相遇遲，君放我已檢。", "驟聞强大語，若虎餓得啗。", "已無相髙心，徒有志氣感。", "春風吹天昏，醉目睨愁慘。", "念當相别去，兩懷不無黪。", "何時重來過，慰我涸轍噞。", "唯其去後懷，猶一飽復歉。", "幸有西南風，時作寄我槧。"]'),
('0acf844e-b29f-435b-9e90-538bae2e3166','别張粤南夫温子堅元白滿執中子權黄冀端微','王令','宋','宋诗','song-poetry','','[]','始吾得三滿，自謂得過人。',204,'全唐诗/poet.song.39000.json','["始吾得三滿，自謂得過人。", "一日不見之，已恐愚賤濱。", "憂思叢中來，腹腸生毛鱗。", "輕舟刺而南，久結願解伸。", "入門顧我笑，喜氣沃以新。", "徐徐相抽尋，軋軋聽引陳。", "先生固大賢，擬議何可鄰。", "諸君人相得，熱炙香相熏。", "而我拱其間，貪喜乃失神。", "鳯凰朝百鳥，鴟鴉亦來羣。", "然其氣類同，終獨鳳鶴親。", "發爲鳴聲和，上下相鏗純。", "苟非治平世，不得此類馴。", "故其聞之者，舞蹈相揺振。", "輕風促回舠，後會无涯根。", "作詩謝幸甚，顛倒迷歡欣。", "如將銘自賀，又欲書諸紳。"]'),
('c58650bc-2196-4448-a8a5-1e239c36625f','寄李常伯滿粹翁','王令','宋','宋诗','song-poetry','','[]','我思古人不可見，獨以兩眼紙上求。',320,'全唐诗/poet.song.39000.json','["我思古人不可見，獨以兩眼紙上求。", "苦讀才疲即伏枕，亦冀夢寐從之遊。", "每疑賢聖世間有，豈獨古出今則不。", "心之所藏弗面見，常恨世腹不可搜。", "雖然其中充美者，間或外發文章彪。", "揚淮而南誰名聲，盛說李滿乾萬喉。", "青天白日所同見，衆亦不敢加瑕疵。", "而余零丁始就學，獨矯衆棄先拈收。", "要其所學與必至，不止顔孟須孔周。", "决將健走獨取到，顧我不肯少待留。", "新詩惠見薦自讋，若遇重壓併見投。", "星機織成付地錦，神冶鑄出舂天矛。", "輝光交華目反眩，噍咀過美涎并流。", "退歸畏愛復願學，恍若見富潛謀偷。", "顧其才力非當對，猶以一髪紖十牛。", "使我苦勉不少得，搦筆欲下先慚羞。", "有如姣惡各具體，肉骨不可强彫鎪。", "或云才華乃天與，何寡不益多仍裒。", "幾時髙車得會合，預期蹈抃呼旁陬。", "臨風呻哦欲有寄，自恨拙繭無長抽。"]'),
('c85bd301-40fe-4a80-93a6-4715d8cd0e7e','寒林石','王令','宋','宋诗','song-poetry','','[]','嘗聞千歲松爲石，豈意今逢林出屏。',64,'全唐诗/poet.song.39000.json','["嘗聞千歲松爲石，豈意今逢林出屏。", "苟非木根久自化，豈此石理能有靈。", "世間萬怪浩莫問，枉哉山海徒有經。", "舒山虢水固險異，疑有神手藏幽冥。"]'),
('423526d0-5e4b-4470-8c2d-b93f616ded16','謝束丈見贈','王令','宋','宋诗','song-poetry','','[]','賤生不自辰，親没身孤零。',288,'全唐诗/poet.song.39000.json','["賤生不自辰，親没身孤零。", "家無一稜田，不得農以耕。", "巧智不迨人，工賈難自名。", "妄來覷文字，朱墨紛縱横。", "合窮心狂髙，不肯束世程。", "掲欲望孔孟，今昔相招迎。", "去古遠莫到，復今難回行。", "窮步匍匐歸，失虎犬不成。", "顛倒塵土中，甚若魚噞羮。", "祖死不反骨，姊寡歸携甥。", "蒼黄無爲謀，嘆慨私失聲。", "叩頭屋厦借，解衣鍋蓋賡。", "甔石固莫致，升掬猶時營。", "學左世共笑，身賤人交輕。", "父戒子勿効，妻引夫無朋。", "妄承西來招，喜色轉以騂。", "非惟迹脱死，始有心期生。", "兒童相回環，朋友推弟兄。", "有問多無對，新聞多慚驚。", "自羞陋淺人，偷竊幸未黥。", "風窗敞清虚，飽腹摩膨脝。", "睡足起有書，案几交堆盈。", "自喜主人仁，不我賢而惸。", "新詩重來貺，褒揚借光榮。"]'),
('c75965cb-d5df-4350-9c1d-db7d609d3174','夢蝗','王令','宋','宋诗','song-poetry','','[]','至和改元之一年，有蝗不知自何來。',348,'全唐诗/poet.song.39000.json','["至和改元之一年，有蝗不知自何來。", "朝飛蔽天不見日，若以萬布篩塵灰。", "暮行嚙地赤千頃，積疊數尺交相埋。", "樹皮竹顛盡剥枯，况又草穀之根荄。", "一蝗百兒月兩孕，漸恐髙厚塞九垓。", "嘉禾美草不敢惜，却恐壓地陷入海。", "萬生未死饑餓間，支骸遂轉蛟龍醢。", "羣農聚哭天，血滴地爛皮。", "蒼蒼冥冥遠復遠，天聞不聞不可知。", "我時心知悲，墮淚注兩目。", "發爲疾蝗詩，憤掃百筆秃。", "一吟青天白日昏，兩誦九原萬鬼哭。", "私心直冀天耳聞，半夜起立三千讀。", "上天未聞間，忽作遇蝗夢。", "夢蝗千萬來我前，口似嚅囁色似冤。", "初時吻角猶唧嗾，終遂大論如人間。", "問我子何愚，乃有疾我詩。", "我爾各生不相預，子何詩我盍陳之。", "我時憤且驚，噪舌生條枝。", "謂此腐穢餘，敢來爲人譏。", "爾雖族黨多，我謀久已就。", "方將訴天公，借我巨靈手。", "盡拔東南竹柏松，屈鐵纒縛都爲箒。", "掃爾納海壓以山，使爾萬噍同一朽。"]'),
('2ddd2f5b-0e4a-4334-bb18-6b1c31a32b49','寄滿子權','王令','宋','宋诗','song-poetry','','[]','吾愛子權詩，苦嚼味不盡。',264,'全唐诗/poet.song.39000.json','["吾愛子權詩，苦嚼味不盡。", "窮思欲名狀，百比無一近。", "初如貪追兵，屢請忽許進。", "旗旄左右幢，戟劍後先刃。", "方爭奮拏先，忽覩斬亂狥。", "徐驅得平郊，萬甲合一陣。", "偏裨走起頗，中間坐吳臏。", "喊呀鬭志酣，彷彿窮敵訒。", "前軍奔交兵，後馬走斷紖。", "須臾聲金收，萬噪快一儁。", "羣降挑戈矛，叩拜乞用釁。", "蒼黄請命間，竊視不敢瞬。", "玄雲壓空虚，半夜暴霆震。", "睡耳起欲掩，驚仆失肝腎。", "壯者固已然，况余乃齠齔。", "及其久詳味，欲吐復自恡。", "有如羅百珍，次第嘬嚼順。", "貪豐不辭多，愛美忘餘餕。", "故其留人口，雖久咽喉潤。", "何時匹馬來，畏愛氣兩振。", "唯其未合間，如不獲謝藺。", "望風爲此詩，顛倒猶合燼。"]'),
('eb2d2d16-1f1c-4115-a490-b299875e273d','再寄滿子權二首  其一','王令','宋','宋诗','song-poetry','','[]','秋盡啼衰蟲，君思云奈何。',180,'全唐诗/poet.song.39000.json','["秋盡啼衰蟲，君思云奈何。", "我愚得君思合少，君賢勞我心則多。", "非獨辭源長，瀉海爲江河。", "平生未始有點缺，玉日拂拭金燒磨。", "尋常貙與貍，見一足已蹉。", "又况一地卧三虎，狗彘雖勇何敢過。", "揚州我何思，青山無一螺。", "午市不畜寶，米鹽財如他。", "而吾三夫子，一身各丘軻。", "瓊林自生寒，結露成冰柯。", "文章日組緯，玉機飛金梭。", "誰有真珠繩，結作張麟羅。", "拔爲當世祥，聲爲太廟歌。", "我願叅衆民，手足揺婆娑。"]'),
('9a49dbf2-55a3-4b05-8555-1bf844462ebe','再寄滿子權二首  其二','王令','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','有錢莫買金，多買江東紙。',174,'全唐诗/poet.song.39000.json','["有錢莫買金，多買江東紙。", "江東紙白如春雲，獨君詩華宜相親。", "綴連卷大十牛腹，要盡寄我無寄人。", "我將携之東，脚踏海水洗齒唇。", "轉來清澈飲百斛，蕩滌腸肺無纖塵。", "嘗聞泰山髙，髙處天爲鄰。", "借如無梯不得上，亦欲大叫呼天神。", "鋪陳君所詩，噪口雷鼓震。", "世多俗耳固莫告，當冀上帝依稀聞。", "正聲定不感凡類，舞躍百鳳千龍麟。", "安能學俗兒，一卷不復呻。", "天公聞否尚未快，安得纖翼穿秋旻。"]'),
('5d485eff-114e-4ce1-a5dd-5707c9655676','答束徽之索詩','王令','宋','宋诗','song-poetry','','[]','世味久已諳，多惡竟少好。',288,'全唐诗/poet.song.39000.json','["世味久已諳，多惡竟少好。", "惟詩素所嗜，决切欲深造。", "人安已不休，衆恥我獨冒。", "有如獺行跡，欲改復自蹈。", "肝腸困尋搜，吻舌倦搏造。", "心靈無餘多，爲此日有耗。", "已勤尚無成，既苦每自勞。", "自笑如秋蟬，饑極不止噪。", "努力排韓門，屈拜媚孟竈。", "惟此二公才，百牛飽懷抱。", "我如餓旁者，盻盻不得犒。", "不知去幾多，窮行究未到。", "無門隔籓籬，發罅窺堂奥。", "愛之不可入，抵觸發狂譟。", "借使苟有成，不知竟何要。", "孤名非所求，弊俗詎足傲。", "况乃非所及，窮海未爲浩。", "不知何時休，定訖死與耄。", "因疑今世人，恐有我同操。", "徽之才超髙，竿幢出標纛。", "爲學尚淹藴，富櫜不肯暴。", "文章內朱豹，外襲一以皂。", "大論尤堅强，推舟出行奡。", "珉砆不施功，徑欲制珪瑁。"]'),
('fa5d684d-4404-48c1-b5b8-1a16b118f56e','寄滿居中衡父','王令','宋','宋诗','song-poetry','','[]','前會去莫追，後見來無期。',276,'全唐诗/poet.song.39000.json','["前會去莫追，後見來無期。", "别嘆後見難，悔恨前會稀。", "惟吾衡父兄，金純玉光輝。", "裁磨殺圭角，不與瓦礫齊。", "大匠陶百窑，不問履下泥。", "一衡舉十鈞，何棄毫與釐。", "余獨何爲人，乃不忍使遺。", "有如横道芻，萬足踏不疑。", "子何嗜好殊，獨俯掇以歸。", "整束使不茨，欲令襍蘭芝。", "蘭芝有天香，芻賤雜則非。", "然其厠置間，適與薫染資。", "文章每借觀，罅隙窺晴曦。", "議論使坐聽，穴瞶聞英池。", "春園或承招，遊騎亦許隨。", "劇雲愛風枝，爇火圍夜棋。", "縱談心開張，倒笑冠欹披。", "匹馬載以來，東首頸脰疲。", "夜夢不厭勞，百里夕一馳。", "想見目與眉，百障千藩籬。", "不虞自投置，遂若鳥遭黐。", "何時獲因緣，連箠促馬蹄。", "誓當盡晨昏，不復起退辭。"]'),
('8899f099-8874-4631-8863-ecf076e9204b','自訟答束熙之','王令','宋','宋诗','song-poetry','','[]','洞洞之室或者穿，巖巖之墻或者緣。',112,'全唐诗/poet.song.39000.json','["洞洞之室或者穿，巖巖之墻或者緣。", "墻緣室穿來何哉，中有玉萬黄金千。", "金玉固非盗所有，盗者或得之伺候。", "得金買衣出人前，意氣遂若富者然。", "衆人不知謂爾富，不知爾自何心顔。", "盗財固爲小人戮，盗名自是君子奸。", "咄哉自訟毋自欺，幾希不在穿緣間。"]'),
('73caef3e-c335-4ff6-b355-0b6f17b3cdc7','謝李常伯','王令','宋','宋诗','song-poetry','','[]','人從東南來，忽得連紙詩。',288,'全唐诗/poet.song.39000.json','["人從東南來，忽得連紙詩。", "行義不赫曄，名聲無萎蕤。", "雖嘗誤見辱，旋則拜席歸。", "别久謂已忘，不圖猶記之。", "長封大書字，顧我已忸怩。", "開縢把之讀，推與果失宜。", "剥虎蒙羊猪，借使出類奇。", "見豺先自奔，遇豢還羣隨。", "是故古之人，爲己賤若斯。", "有聞未之行，季路終不嬉。", "名浮過所實，孟氏恥以非。", "今而承所賜，乃此亦可噫。", "賢者寧過哉，當是我有欺。", "忍愧讀終篇，喜驚改肝脾。", "嚀嚀教誨言，舉舉仁義辭。", "初令探本根，喻以海與池。", "乾坤老六經，遺編爛孔姬。", "尚恐惑異說，教之無遷移。", "强聞終日乾，仁不三月違。", "卒以二者終，要我勉不疑。", "百誦百再拜，下淚如掛糜。", "交朋百愚諛，此語聞之誰。", "憶初從粹翁，睡耳忽得提。", "震驚破百昏，寐覺悼前迷。"]'),
('c9d8af34-5ce2-49e2-a383-e576526d8456','對月憶滿子權','王令','宋','宋诗','song-poetry','','[]','長風掠海來，吹月散百鍊。',288,'全唐诗/poet.song.39000.json','["長風掠海來，吹月散百鍊。", "青天豁四碧，雲靄不容緣。", "窗軒颯先秋，露氣入簟扇。", "寛庭生夜凉，蚊口不得擅。", "人靜暮客去，坐偃適自便。", "清牽睡思醒，明發醉膽健。", "披風睨白月，瞪視不爲眩。", "未甘景獨勝，思出大句衒。", "狂搜得無奇，猛吐復自吮。", "篇成若奴婢，氣骨終凡賤。", "棄置不復收，嘆感退自旋。", "起探君寄詩，兀坐諷百遍。", "駮哉劇雄勁，百札洞一箭。", "間逢騁新奇，春雲弄晴霰。", "古鏡終重厚，九鼎掛一鉉。", "吾嘗笑夫人，語富則自願。", "及嬰愛君念，始自信惓惓。", "閲女當求嬙，慕士在獲彦。", "鄙哉尋常者，何用目識徧。", "得逢誠幸多，既别遂堪喭。", "乖離時况久，會合卜未先。", "思之不可見，飛魂不身戀。", "秋城崔嵬髙，圍我屹若圈。", "安得擘風翅，飛出不自殿。"]'),
('dd0c70a1-67c2-4b77-b18d-64fae2063e79','八檜圖','王令','宋','宋诗','song-poetry','','[]','客有要我八檜吟，手携八檜圖來懸。',384,'全唐诗/poet.song.39000.json','["客有要我八檜吟，手携八檜圖來懸。", "掛張滿壁惕可駭，盼顧左右同嗟嘆。", "旁摹石刻署名狀，各有憑附相夤緣。", "或髙相扶互倚礙，或斷欲蹷猶支顛。", "强枝抝回信有力，髙幹復俯蛟虯拳。", "尋根及枝逮條蘖，例不拔直皆旁偏。", "雷疲風休雲雨去，蛇龍鬭死猶鈎纒。", "安分爪角與尾鬛，徒見上下相蜿蜒。", "不知生時竟何謂，略不參類常木然。", "宜乎今古惑昧者，揺擺舌吻歸之仙。", "一龍盤拳老髙大，傳云聃者由飛躚。", "當時駕鹿蹋以上，跡有町疃遺相連。", "多應蝎殘鳥喙啄，不爾誕者强鑱鐫。", "聃能惑人已自幸，豈此上去能欺天。", "借如聃功可升躍，鹿亦何幸飛相連。", "於中一木特甚異，膚華逆理紐左旋。", "傳云聃人所自栽，我知此語定鑿穿。", "苟令實爲聃者植，推以天意猶可言。", "當年曷不紐向右，若曰世爲左道牽。", "如何衆輙不省究，反重神怪令聃專。", "乾坤中含萬品彚，此獨自異誰令旃。", "窮思竟慮莫可索，欲世不惑誰能搴。", "仙書虛荒喜誕妄，推說事理尤綿延。", "世人一讀即化變，日望飛奮相迷癲。"]'),
('c2a05f39-f718-49d0-9003-166252624780','秋夜','王令','宋','宋诗','song-poetry','','[]','秋夕不自曉，百蟲齊一鳴。',48,'全唐诗/poet.song.39000.json','["秋夕不自曉，百蟲齊一鳴。", "時節適使然，鼓脇亦有聲。", "爭喧鼠公盗，窸窣蛇陰行。", "獨有東家雞，苦心爲昏明。"]'),
('3daf23b2-e0e6-4bed-957d-d132e054f04e','答束孝先','王令','宋','宋诗','song-poetry','','[]','純金出鎔鑪，烜赫掩熾火。',276,'全唐诗/poet.song.39000.json','["純金出鎔鑪，烜赫掩熾火。", "錦成洗春江，衆目炫莫奈。", "魚鹽物誠微，誤用幸不涴。", "君家兄弟賢，我見始驚夥。", "文章露光芒，藏藴包叢脞。", "關門當自足，何暇更待我。", "固知仁人心，姑欲恤窮餓。", "苟論才不才，自合棄如唾。", "憶昨西來初，戚惕侍客坐。", "交持駕說口，張闔不可鏁。", "間發辨經義，鐵舌莫摩挫。", "髙文忽下投，白日駭天墮。", "眩怖欲前掩，布帛不可裹。", "初視固宜驚，獨獲亦堪賀。", "又如遇貴人，繡錦飾婀娜。", "回眸忽自鑑，惡面復窶裸。", "屈降心巳甘，嘆憤志亦頗。", "雄髙豈復爭，愛恤亦加荷。", "大詩又來及，推與太浮過。", "自無賢可稱，以是惡甚播。", "譬如享尫人，豆食止則可。", "苟强擔石負，蹉跌適足禍。", "何以論報心，結草効鬼顆。"]'),
('8b521d67-7ad4-4c85-acf6-79b0f40d30d0','戯食雀','王令','宋','宋诗','song-poetry','','[]','秋風雲氣寒，秋雨晝夜兼。',132,'全唐诗/poet.song.39000.json','["秋風雲氣寒，秋雨晝夜兼。", "饑禽濕不飛，左右煩顧瞻。", "有雀獨飛下，施徐入吾簷。", "毛羽刷參差，嘴距交鈎銛。", "跳乘新舂箕，取飽公不嫌。", "而吾本有意，聽之取微纖。", "忽驚自飛去，窗聿不少淹。", "反就髙髙枝，啁哳氣不恬。", "嗟乎此微類，豈不無以厭。", "來既冐彈射，固難責其亷。", "然余乃無罪，見怒何過嚴。"]'),
('95c2095b-1305-4c1a-9be9-3a9cc9752e7c','金繩掛空虚自勉兼示束孝先','王令','宋','宋诗','song-poetry','','[]','金繩掛空虚，日月繫兩垂。',108,'全唐诗/poet.song.39000.json','["金繩掛空虚，日月繫兩垂。", "天童坐戯弄，縱掣成東西。", "百年未死間，晝夜無窮期。", "短短固可惜，舒舒定非宜。", "有聞未之行，有學未及知。", "白髮已班疏，朱顔亦童黎。", "智慮昏晚年，聰明退前時。", "縱欲加自修，去日何勝追。", "奈何少自廢，老則成空悲。"]'),
('58c63c0e-a4d9-45ae-8b3e-71e41e346baf','寄洪與權','王令','宋','宋诗','song-poetry','','[]','與權江南來，適自滿門會。',288,'全唐诗/poet.song.39000.json','["與權江南來，適自滿門會。", "初無合我志，財以客面待。", "時時相鈎探，稍稍互酬對。", "根源豁披張，扄鐍失分解。", "君然頷還嗟，我恐敬若戴。", "相逢時既多，相待兩交快。", "予初請子交，子曰何可外。", "中又謝不德，卒曰吾而愛。", "既而苐以年，子合我兄拜。", "揚雖士云多，往往事冠带。", "中間滿夫子，崛出百萬最。", "更以子從之，而吾米則稗。", "朋從偶許攀，會合日與在。", "春晨巧誇招，月夕因論話。", "書狂逸飛蛇，棋毒甚含蠆。", "相謀務奇勝，聚口笑拙敗。", "貪驩不知歲，冬律忽移再。", "余饑奔先西，餓色面留菜。", "子待去亦恨，書以問我奈。", "别來君何如，思子我心痗。", "朋分無舊歡，世險有新態。", "髙言足瑕疵，俗學牽細碎。", "貧知身貴重，病覺學力怠。", "壯心已無多，况去日有退。"]'),
('43b4629c-b065-4921-ac0e-723fae187085','寄滿子權','王令','宋','宋诗','song-poetry','','[]','子權今謂何，久不治簡書。',132,'全唐诗/poet.song.39000.json','["子權今謂何，久不治簡書。", "子素賜我多，豈以此遂疏。", "予亦如常時，病與貧相俱。", "冉冉草没階，客脚不踏廬。", "貴者事名位，崖岸誇異殊。", "賢者縱肯來，顧我欲取無。", "惟餘齪齪徒，吾亦羞與居。", "潭潭一室空，編帙環三隅。", "暴陽不憂償，偷飽幸未誅。", "且可延朝昏，憂思老頑愚。", "獨有思子懷，涕下時喑嗚。"]'),
('49fff9c8-d4e9-4813-af29-d3ccf9cab059','冬陰寄滿子權','王令','宋','宋诗','song-poetry','','[]','玄雲載雨惜不下，北風吹急水相黏。',192,'全唐诗/poet.song.39000.json','["玄雲載雨惜不下，北風吹急水相黏。", "周遮覆蓋不通透，錮結巳厚難披燖。", "微陽未復老陰壯，計去暖律時猶淹。", "青天何可一日失，漸恐此去無由瞻。", "日馭自懼不得脱，略出急入地下潛。", "憑陰托寒恣凌爍，風伯得意欣沾沾。", "但幸天公不省悟，誰顧地下人嗟讒。", "隔絕霜露曠不下，帝有潤澤何由霑。", "非惟勾芽凍天折，亦恐萬類由兹殱。", "九龍銜火互相暖，稱有日職借不甘。", "羣兒鋭奮不量度，欲仰吐氣吁以炎。", "惟有壯士抱劍卧，思得美酒聊自酣。"]'),
('5116c6ca-cd0e-46ee-961d-bd8430512088','弱弱誰氏子','王令','宋','宋诗','song-poetry','','[]','弱弱誰氏子，鮮鮮一何姝。',180,'全唐诗/poet.song.39000.json','["弱弱誰氏子，鮮鮮一何姝。", "來奔富人家，妻與富人俱。", "嚴粧問夫子，我豈彼室如。", "夫子笑遣之，彼寧與汝都。", "升堂由阼階，德色溢以舒。", "親賓不敢笑，退語相嚱吁。", "髙堂聚羣婢，唯諾相咨睢。", "家事忽不圖，顧指取自如。", "朝令拆柱薪，暮遣藩籬除。", "風雨半夜來，百釁生不虞。", "屋壓盗隨至，夫死别嫁夫。", "東鄰有淑子，惟不事鉛朱。", "端居待人求，正色不敷腴。", "清鏡見白髮，行媒不顧閭。", "不知愛妻人，取舍何異歟。"]'),
('adaa23ee-cf99-4169-b649-7d25e73723c4','贈黄任道','王令','宋','宋诗','song-poetry','','[]','長河之流幾萬里，駭若瀉自天上來。',160,'全唐诗/poet.song.39000.json','["長河之流幾萬里，駭若瀉自天上來。", "奔湍衝山拔地走，直有到海無邪回。", "人之所觀乃流沬，猶以激射憂天摧。", "想其根源發聲勢，如縱烈火燒千雷。", "古來走死萬萬脚，竟莫識自何來哉。", "我疑鴻荒混沌日，冲破天地之元胎。", "夸娥揺頭巨靈走，避不敢道曾疏開。", "鋤耰之成乃畎澮，欲計議此誠可咍。", "長帆大艦不敢絕，尚恐飄去無垠涯。", "愚兒脚慣踏潢潦，安敢逆此加泝洄。"]'),
('89df063d-35ee-41da-b9ba-57ac0ebd96ee','答黄藪富道','王令','宋','宋诗','song-poetry','','[]','角角適時足，力走猶或遲。',288,'全唐诗/poet.song.39000.json','["角角適時足，力走猶或遲。", "從而不逮人，不若坐視之。", "而予始用此，已無先人思。", "間自念斯世，固亦未易爲。", "以其得而慚，曷若退自宜。", "老身可孔顔，餓死猶夷齊。", "予心最樂此，尤喜用自持。", "豈將六尺軀，賤易五羖皮。", "但無百畝田，得抱剛氣歸。", "年來事窮蹙，露暴無自依。", "姊寡不能嫁，兒孤牽我啼。", "平生事文字，無路活寒饑。", "勉從進士科，束若縛襁兒。", "時時忽自笑，往往窮加悲。", "有如髙飛鳥，中路饑自低。", "鋭知從食來，不意身投黐。", "神龍拏白日，挾雨萬里飛。", "使其口有銜，安得無馴隨。", "雖然平生志，固未忍相遺。", "閑時自散開，縱吟助嘘嚱。", "財將舒己私，豈敢偷人知。", "黄君道德者，術業何頎頎。", "手提九黄鐘，旁取折籥吹。", "懸知失氣類，誤以唱和期。"]'),
('51c8be1a-371b-4fc0-b565-8cabddcd91ff','春風','王令','宋','宋诗','song-poetry','','[]','春風東來暖如嘘，過拂我面撩我裾。',160,'全唐诗/poet.song.39000.json','["春風東來暖如嘘，過拂我面撩我裾。", "不知我心老有異，亦欲調我兒女如。", "庭前花枝笑自愛，風裏草力更相扶。", "旁林曲樹足飛鳥，不問燕雀鴟鳶烏。", "求雌要雄各有意，豈但鬬競爭春呼。", "春巢成多夏卵衆，明年計此更有餘。", "非唯喧呼亂人耳，漸恐巢穴妨人居。", "收殘射中豈無道，我亦力可彎長弧。", "林深枝曲矢不入，况弓待借家所無。", "行吁坐盻不可奈，安得靜默投身俱。"]'),
('2e5c6371-d073-4627-9e35-bd788b3d1751','長風','王令','宋','宋诗','song-poetry','','[]','長風吹百草，勢力亦隨靡。',48,'全唐诗/poet.song.39000.json','["長風吹百草，勢力亦隨靡。", "地長風易休，草力復隨起。", "長風隨令歸，風去何時來。", "百草安正繁，蘭生爾何哉。"]'),
('077a4150-d967-4cc2-abaf-d29429a1dc58','東風','王令','宋','宋诗','song-poetry','','[]','東風來幾日，窮巷不見春。',48,'全唐诗/poet.song.39000.json','["東風來幾日，窮巷不見春。", "不知得花由，只見插花人。", "東風能幾時，聽爾多歡欣。", "徒恐春風歸，汝我同悲辛。"]'),
('a79f3c20-192d-48d6-8ae6-ea69e2f38241','哭詩六章  其一','王令','宋','宋诗','song-poetry','','[]','死者徒已死，思之恨無涯。',48,'全唐诗/poet.song.39000.json','["死者徒已死，思之恨無涯。", "生者非素心，還作死者嗟。", "今古悲略同，斯道竟奈何。", "哀絃直易絕，哭詞曲難歌。"]'),
('bcc00f38-d497-46c2-8911-5d3de5a8099e','哭詩六章  其二','王令','宋','宋诗','song-poetry','','[]','朝哭聲吁吁，暮哭聲轉無。',48,'全唐诗/poet.song.39000.json','["朝哭聲吁吁，暮哭聲轉無。", "聲無血隨盡，安得目不枯。", "目枯不足嘆，無目心自安。", "目存多所見，不若無目完。"]'),
('e7ea81dd-77ae-413d-b9cd-dbe515a9dcc6','哭詩六章  其三','王令','宋','宋诗','song-poetry','','[]','切切復切切，淚盡琴絃絕。',48,'全唐诗/poet.song.39000.json','["切切復切切，淚盡琴絃絕。", "憤氣吐不出，內作心肝熱。", "朝漿渇不勝，暮潦濁不清。", "何以慰我懷，安得滄海冰。"]'),
('14f49411-9611-4611-8e77-f6a3a9545fad','哭詩六章  其四','王令','宋','宋诗','song-poetry','','[]','哭莫傍滄海，淚落長海流。',48,'全唐诗/poet.song.39000.json','["哭莫傍滄海，淚落長海流。", "流深風濤多，駕蕩覆我舟。", "不若灑春草，荆榛蕪蔓莖。", "怨氣觸草死，猶得香蘭生。"]'),
('b4d1843b-6021-4cd5-829b-f0abaaac5b54','哭詩六章  其五','王令','宋','宋诗','song-poetry','','[]','朝歌憂思多，暮歌無奈何。',48,'全唐诗/poet.song.39000.json','["朝歌憂思多，暮歌無奈何。", "偶嘆氣亦絕，未慟血先沱。", "淚落入口少，不如出眼多。", "安得常病軀，不爲瘠且瘥。"]'),
('6dddaea1-5d1b-492b-a083-9094cfdb0893','哭詩六章  其六','王令','宋','宋诗','song-poetry','','[]','目雖淚所出，由來心乃源。',48,'全唐诗/poet.song.39000.json','["目雖淚所出，由來心乃源。", "白日照我面，意欲乾汍瀾。", "而不照我心，我淚何由乾。", "况在重雲遮，使我何自安。"]'),
('0b941531-19b0-4627-981f-8dcdd86ababa','張巡','王令','宋','宋诗','song-poetry','','[]','禄兒射火燒九天，鬼手不撲神聽旃。',208,'全唐诗/poet.song.39000.json','["禄兒射火燒九天，鬼手不撲神聽旃。", "羣庸仰口不肯唾，反出長喙嘘之燃。", "睢陽城窮縮死鼈，危繫一髮懸九淵。", "巡瞋睨遠兩眥拆，怒嚼齒碎鬚張肩。", "恨身不毛劍無翼，不能飛去殘賊嚥。", "翁軀腥刀子磔爼，日嚼血肉猶經年。", "霽雲東攘兩臂去，西來才有九指還。", "胸中憤氣吐不散，去隨箭入浮屠磚。", "忠窮智索其自効，更臠愛妾嘗饑涎。", "我疑没日賊不食，恐其肉酖死不痊。", "又疑身骨不化土，定作金鐵埋重泉。", "何時山移陵谷變，發出鼓鑄戈或鋋。", "吾如得之顧有用，不誅已然誅未然。"]'),
('ff7faeaa-0e83-479f-8cdf-18c6a844100f','贈李定資深  其一','王令','宋','宋诗','song-poetry','','[]','涉川固有道，造舟不如梁。',48,'全唐诗/poet.song.39000.json','["涉川固有道，造舟不如梁。", "曾聞水覆舟，不聞死乘杠。", "奈何掲厲子，先先勇褰裳。", "豈盡水害人，固亦謀非臧。"]'),
('c17050fa-f917-49a2-a776-e62207667328','贈李定資深  其二','王令','宋','宋诗','song-poetry','','[]','鳳雖謂靈畜，無竹或死饑。',48,'全唐诗/poet.song.39000.json','["鳳雖謂靈畜，無竹或死饑。", "竹今無方無，鳳云非其時。", "使之羣鴟鳶，饑飽爲止飛。", "非惟失所靈，亦與彈射期。"]'),
('cc7ea926-df10-4e27-9e8e-584879908a6f','贈李定資深  其三','王令','宋','宋诗','song-poetry','','[]','坦坦誰之田，施施繳且弋。',48,'全唐诗/poet.song.39000.json','["坦坦誰之田，施施繳且弋。", "烏來玩其機，鵲至喜其食。", "長鴻飛冥冥，志與萬里極。", "豈無啄飲心，寧饑不人得。"]'),
('1152892e-e282-4872-afb4-ce9d1a0042b1','贈李定資深  其四','王令','宋','宋诗','song-poetry','','[]','湍激日蹙蹙，風稜勢漫漫。',48,'全唐诗/poet.song.39000.json','["湍激日蹙蹙，風稜勢漫漫。", "奈何舟上人，試死才一間。", "苟不以利涉，安坐思誠艱。", "客雖懼謀梁，而木嗟在山。"]'),
('a7d73205-53d9-4a0d-a282-3cca3a0e4c86','古廟','王令','宋','宋诗','song-poetry','','[]','古廟隆隆敞庭扉，風雨剥壁黦柱榱。',352,'全唐诗/poet.song.39000.json','["古廟隆隆敞庭扉，風雨剥壁黦柱榱。", "我來安知神所依，穹堂窸窣風旛旂。", "神君龐軀突鬚眉，視我睨睚坐倨箕。", "惕爍觀者駭不怡，羣鬼後先張福威。", "直東之廂步逶迤，目益所見怪可嘘。", "馬牛羊犬雜豕雞，或戴以首旁四支。", "間有人面身亦非，老祝趨前爲衆詞。", "口吻囁嚅言嗢吚，稱别狀類顧東西。", "唱號名字分何誰，空虛冥寞非所期。", "豈亦以此爲人尸，視其膚革巳彪狸。", "寧有中反恬肝脾，又有械器身挈持。", "傳言癘疫此乃資，古之日行歷虚危。", "猶恐盛陰鬼所隨，磔儺於門驅使馳。", "今安取此廟以祠，不念延虐殆尫羸。", "農凶年多苦餓饑，苟幸得飽不擇祈。", "來則拜叩盡敬祗，幸天之澤偷自歸。", "民德且恐報之時，餗肴豊鮮牲魚肥。", "欲奠以獻更濯巵，進謝千語拜百低。", "工鼓於庭巫舞衣，祝傳神醉下福禧。", "農謝神去祝徹之，庭前匕割棄餘遺。", "鵠烏下爭趁不飛，回顧神面如故時。", "意者不爲祭謝移，嗚呼神固非吾知。"]'),
('be8ca82f-8f66-4fb1-8657-dd3a988c7c89','襍詩  其一','王令','宋','宋诗','song-poetry','','[]','方春不種蘭，終歲無自佩。',48,'全唐诗/poet.song.39000.json','["方春不種蘭，終歲無自佩。", "良田弗加芟，徒穉亦無歲。", "空令雨露恩，日夕被蒿艾。", "安坐饑怨天，此理果誰在。"]'),
('f526d2a2-6ebe-4470-83d7-8157df8fda07','襍詩  其二','王令','宋','宋诗','song-poetry','','[]','一日不爲田，百草已有根。',48,'全唐诗/poet.song.39000.json','["一日不爲田，百草已有根。", "况復閑三時，其穢何待論。", "豈不有錢鎛，徒羞慵借勤。", "歲晚憂不耕，何獨議鋤耘。"]'),
('206c50fd-045e-47f8-9219-cf77a78448eb','襍詩  其三','王令','宋','宋诗','song-poetry','','[]','毿毿晚春樹，上下聚百蟲。',48,'全唐诗/poet.song.39000.json','["毿毿晚春樹，上下聚百蟲。", "不有口似躉，則生尾如蜂。", "設不二者然，亦徒生無庸。", "清陰不可居，歲晚還秋風。"]'),
('3ddf75fd-43d2-4568-9620-c6f956aa190c','猛虎','王令','宋','宋诗','song-poetry','','[]','猛虎出白日，其欲未易量。',180,'全唐诗/poet.song.39000.json','["猛虎出白日，其欲未易量。", "人人有怒心，常懼不敢戕。", "壯士獨何者，忿氣裂怒腸。", "脱身拔劍去，奮躍如驚翔。", "雖挟必勝術，豈無邂逅傷。", "虎不食壯士，壯士自虎當。", "意貪衆人完，豈暇爲軀防。", "虎死衆人惠，虎存憂一鄉。", "果哉彼丈夫，賴有一劍將。", "使其無所操，未免伏道旁。", "有劍不刺虎，爲謀信非臧。", "無劍徒虎爭，雖勇適爲狂。", "利劍亦可嗟，人有我獨亡。", "日暮南山阿，直道何可望。", "一虎固已爾，况復千豺狼。"]'),
('123f793a-43ab-4d7a-9498-87c7148bfb04','答問詩十二篇寄呈滿子權 鎛問耒','王令','宋','宋诗','song-poetry','','[]','金堅雖不磨，木曲亦已揉。',48,'全唐诗/poet.song.39000.json','["金堅雖不磨，木曲亦已揉。", "幸蒙主人用，反要主隨後。", "適從慵耕兒，雖功不見取。", "良田常無收，何塞不耕咎。"]'),
('d3e35916-dffa-4061-bb8e-7692bf2c1911','答問詩十二篇寄呈滿子權 耒答鎛 其一','王令','宋','宋诗','song-poetry','','[]','我用常在金，任金適由木。',48,'全唐诗/poet.song.39000.json','["我用常在金，任金適由木。", "苟得金爲用，何惜木微曲。", "幸得主人隨，不恤汗行犢。", "必求隨主人，我用諴不足。"]'),
('72d3dd9d-9b38-44c2-9324-d1a76f4e4604','答問詩十二篇寄呈滿子權 耒答鎛 其二','王令','宋','宋诗','song-poetry','','[]','我用於主人，良田无虛種。',48,'全唐诗/poet.song.39000.json','["我用於主人，良田无虛種。", "主人不我以，我適爲無用。", "不知主人饑，歲卒安自奉。", "由来我求人，孰與求我重。"]'),
('edfcb3e7-75da-46f5-ae86-c216f600a79e','答問詩十二篇寄呈滿子權 耒答鎛 其三','王令','宋','宋诗','song-poetry','','[]','我必爲人用，不必用於人。',24,'全唐诗/poet.song.39000.json','["我必爲人用，不必用於人。", "若也責不耕，君其問諸田。"]'),
('1d83b621-99d6-43b4-b88a-0a784307b76c','答問詩十二篇寄呈滿子權 耒問鎛','王令','宋','宋诗','song-poetry','','[]','一畦失之荒，爾力亦可耨。',24,'全唐诗/poet.song.39000.json','["一畦失之荒，爾力亦可耨。", "天下方漫蕪，爾功亦何有。"]'),
('38434883-7a4d-474e-94da-1bef1ea003a0','答問詩十二篇寄呈滿子權 鎛問耒','王令','宋','宋诗','song-poetry','','[]','天下方漫蕪，顧我適有庸。',36,'全唐诗/poet.song.39000.json','["天下方漫蕪，顧我適有庸。", "使其已除滌，我將何以功。", "我豈大無效，自是用我慵。"]'),
('2d34f0d2-f011-4ea7-a478-680ad7c95b69','答問詩十二篇寄呈滿子權 耒問斧','王令','宋','宋诗','song-poetry','','[]','子斧誰爾爲，黑白大分别。',36,'全唐诗/poet.song.39000.json','["子斧誰爾爲，黑白大分别。", "朝伐一樗死，暮伐千樗蘖。", "爾終不自謀，幾日不缺折。"]'),
('2ae10a59-e29a-4200-b5fe-001eef181ac0','答問詩十二篇寄呈滿子權 斧問耒','王令','宋','宋诗','song-poetry','','[]','大樗吾猶伐，小樗何畏蘖。',24,'全唐诗/poet.song.39000.json','["大樗吾猶伐，小樗何畏蘖。", "吾缺猶俟磨，爾折將奈何。"]'),
('d828fff8-54aa-48dc-8cea-0a64adf0c786','答問詩十二篇寄呈滿子權 水車問龍','王令','宋','宋诗','song-poetry','','[]','来何必召雲，去何必飛天。',24,'全唐诗/poet.song.39000.json','["来何必召雲，去何必飛天。", "我名不爲龍，何能雨爾田。"]'),
('3ed172f7-4d1b-4e8a-9b98-053b70ab41f7','答問詩十二篇寄呈滿子權 龍答水車','王令','宋','宋诗','song-poetry','','[]','神龍謝子車，子能未足多。',24,'全唐诗/poet.song.39000.json','["神龍謝子車，子能未足多。", "上潤雖已然，下竭將奈何。"]'),
('251e8ce1-33c2-4c2d-b792-081ae12752e6','答問詩十二篇寄呈滿子權 水車謝龍','王令','宋','宋诗','song-poetry','','[]','水車謝神龍，下竭固無奈。',24,'全唐诗/poet.song.39000.json','["水車謝神龍，下竭固無奈。", "旱則我爲用，爾龍尚何謂。"]'),
('f2a9406c-628b-436b-983e-fbbdd35b5c35','答問詩十二篇寄呈滿子權 龍謝水車','王令','宋','宋诗','song-poetry','','[]','神龍謝水車，吾語爾来前。',84,'全唐诗/poet.song.39000.json','["神龍謝水車，吾語爾来前。", "爾雖用於人，我亦用於天。", "在物固不同，於用豈殊然。", "水下髙田乾，爾能俯水取。", "假人不爾用，爾受田責否。", "吾身雖爲龍，動亦天所主。", "天猶不有命，我安事爲雨。"]'),
('9ab08da4-b1d7-4ba2-a1dc-1c34a019a86f','秋懷','王令','宋','宋诗','song-poetry','','[]','槭槭庭前樹，朝零非昔稠。',144,'全唐诗/poet.song.39000.json','["槭槭庭前樹，朝零非昔稠。", "呦呦草蟲鳴，暮急曉未休。", "爾雖無不平，豈亦有哀憂。", "胡爲勞吟呻，與士傷感投。", "壮士亦何者，哀哦與蟲酬。", "所抱不列陳，調苦難謡謳。", "髙目有遠見，直懷羞曲求。", "蒿藜襲久安，功名忘前休。", "日月忽未幾，天地今復秋。", "少壮負所懷，老大將安謀。", "生無及人功，死骨埋泉羞。", "胡爲不奮飛，徒與寒餓仇。"]'),
('fc438314-ef9a-4238-941e-a07c713d170b','中夜二首  其一','王令','宋','宋诗','song-poetry','','[]','晝日苦卒卒，忽焉不加思。',60,'全唐诗/poet.song.39000.json','["晝日苦卒卒，忽焉不加思。", "長夜漫不眠，起復日所爲。", "所爲浩多愧，不與初心期。", "虛云聖賢學，實從世俗歸。", "雖恥猶奈何，長歌涕垂頤。"]'),
('5349c644-3308-4b90-9071-71699e9e8d5f','中夜二首  其二','王令','宋','宋诗','song-poetry','','[]','擾擾從俗爲，日與所學戾。',48,'全唐诗/poet.song.39000.json','["擾擾從俗爲，日與所學戾。", "茫茫坐三復，心面自相愧。", "守道惡從人，取俗患髙世。", "誰令二者異，不得一吾致。"]'),
('33e0ed62-d779-4c3c-888f-fee140204e19','士患常不學','王令','宋','宋诗','song-poetry','','[]','士患常不學，不學常罔然。',48,'全唐诗/poet.song.39000.json','["士患常不學，不學常罔然。", "學成安所施，用舍繫諸天。", "孔孟去已久，寥寥泣遺編。", "斯道未易爲，今古如同年。"]'),
('7c87a3b5-7591-4155-ad6d-1cf0d2d32250','舉舉媚學子','王令','宋','宋诗','song-poetry','','[]','舉舉媚學子，居曰不吾知。',48,'全唐诗/poet.song.39000.json','["舉舉媚學子，居曰不吾知。", "知而有不能，無乃失於欺。", "不知未爲患，不欺浩難期。", "咄哉天下懷，何以天下爲。"]'),
('06788021-5a16-4177-a79f-8553367f498b','秋日','王令','宋','宋诗','song-poetry','','[]','秋日不照天，秋雲自明晦。',48,'全唐诗/poet.song.39000.json','["秋日不照天，秋雲自明晦。", "脱葉下衰草，蜩蟬事今退。", "天地功方成，草木猶怨顇。", "志士感所懷，長吁下清淚。"]'),
('167365f3-14e2-4566-92aa-142b6a7094a3','秋興','王令','宋','宋诗','song-poetry','','[]','秋風吹人有髙興，醉懷感物傷盛衰。',64,'全唐诗/poet.song.39000.json','["秋風吹人有髙興，醉懷感物傷盛衰。", "秋来縱得蒿艾死，歲晚已非蘭蕙時。", "哀歌不入俗耳聽，大笑自與萬古期。", "長鴻冥冥爾飛好，雖有繒繳安所施。"]'),
('cb76358c-def1-4f98-a4f5-58121506e9c5','翩翩水中舟','王令','宋','宋诗','song-poetry','','[]','翩翩水中舟，既滿何用載。',48,'全唐诗/poet.song.39000.json','["翩翩水中舟，既滿何用載。", "主舟者誰子，無乃忽於敗。", "兼濟雖期仁，過任適爲害。", "自是人致然，已溺何足怪。"]'),
('089356eb-d407-416d-a3e3-aeba276d092d','書懷寄黄任道滿子權','王令','宋','宋诗','song-poetry','','[]','西風吹雲空，晴日露髙曬。',240,'全唐诗/poet.song.39000.json','["西風吹雲空，晴日露髙曬。", "駑馬無速騁，歸客思遠届。", "長林剥霜紅，遠水漾寒派。", "露蟲悲自咽，風菊老猶介。", "昔予来方春，焰焰樹生態。", "今歸亦未幾，馬踏落葉壞。", "時物固有然，盛衰信難概。", "吁嗟爲生勞，黽勉計無奈。", "伊余有遐致，久此困俗械。", "嘗思擺絕去，自放出世外。", "髙懷樂天寛，遠目斥人礙。", "有田足晨昏，有圃具葅菜。", "父母不待養，妻子固易賴。", "世孰得丘山，亦孰失蔕芥。", "人自能輕重，吾將守所愛。", "六經老誠明，萬古熟成敗。", "得時爲醯鹽，滋味和鼎鼐。", "失猶有萬世，令名自沽賣。", "自視久已明，决不事謀蔡。", "寄詩侑子觴，期子和而再。"]'),
('1457916d-01b9-45d7-b2dc-bbc2866aa56a','令既有髙郵之行而束孝先兄弟索余詩云','王令','宋','宋诗','song-poetry','','[]','擾擾利學者，久不可與謀。',228,'全唐诗/poet.song.39000.json','["擾擾利學者，久不可與謀。", "讀書乃何爲，老不知軻丘。", "弗恤義所在，務期髙爵收。", "嘗聞失則嗟，不聞得之羞。", "知誰洪其源，使世乘其流。", "於今已汗漫，更久將遡游。", "嘗聞古人言，饕餮爲共兜。", "謂惡豈必多，偷飽德弗修。", "不知自思者，舍此何所由。", "故余早知懼，誓將異人求。", "寜爲寒餓嗟，不同富貴謳。", "此行况有獲，師德髙前修。", "因嘗請子行，勉子無逗遛。", "於吾乃何有，同病不獨瘳。", "雖愛謂予然，尚疑子終不。", "惜子有髙材，竿幢揭華旒。", "苟能自擺去，不爲世學囚。", "行將見遠到，强弩射弱菆。", "何必請予詩，自合治子輈。"]'),
('08e27354-c33b-4323-bf50-e321c8bef0c4','酬束丈貺詩兼叙所懷','王令','宋','宋诗','song-poetry','','[]','白日立中路，犬去不形相。',60,'全唐诗/poet.song.39000.json','["白日立中路，犬去不形相。", "夜以盗自来，何敢怨犬傷。", "主人忽加念，謝恕犬無良。", "盗子愧伏前，有言願加詳。", "見賜固已多，恕犬誠未臧。"]'),
('cd04ebf1-efd7-4593-a842-502811e1ba46','惜交詩贈束孝先','王令','宋','宋诗','song-poetry','','[]','千金得寶刀，不若得鍤歸。',108,'全唐诗/poet.song.39000.json','["千金得寶刀，不若得鍤歸。", "寶刀雖云利，邂逅傷瘡痍。", "傷瘡有復日，傷皮無完時。", "不若遠所傷，取鍤安自持。", "一鑿以成井，再鑿以深資。", "清泉冽其中，定德發不移。", "飲可沃吾心，浴能清吾肌。", "此道如必尚，庶幾有常爲。", "既庸銘我前，又書薦余知。"]'),
('53f25ce5-4f3b-4b85-8c0f-6668b2d79cb5','再贈束孝先','王令','宋','宋诗','song-poetry','','[]','玉缺見不撓，劍折知真剛。',72,'全唐诗/poet.song.39000.json','["玉缺見不撓，劍折知真剛。", "張目不見心，人固未易量。", "念我未知子，徒知外觀望。", "安識子所懷，赤日包白光。", "去去終我身，兩兩無相忘。", "縱予道路憂，骨尚付子藏。"]'),
('4fb0027e-e11d-4333-ae78-e6b7dc0fad90','卜居','王令','宋','宋诗','song-poetry','','[]','吾求一屋逮兩月，貧不謀貴何以圖。',384,'全唐诗/poet.song.39000.json','["吾求一屋逮兩月，貧不謀貴何以圖。", "朅来自放就窮巷，幸得之喜何敢吁。", "頹簷斷柱不相締，瓦墮散地梁架虚。", "門無藩闑户不閉，時時犬彘入自居。", "主人憐我莫自致，爲我補葺加垍塗。", "翻翻匠氏乃誰子，頡頏作氣厲叫呼。", "羣庸洶洶助聲勢，睥睨凌我要我酤。", "歸来嘆息無自得，兩日財致酒一壺。", "徴多償少意不惬，棄我忽去如逃逋。", "重来閴寂不可問，依舊四壁編空蘆。", "嗟余雖貧日猶爨，可不善爲盎釡謨。", "外户不閉古則爾，今也盗賊過街衢。", "乞錢買籬作籓固，更學關楗防朝晡。", "鄰翁問我乃何者，得毋亦以名自儒。", "王朝潭潭聚冠盖，幾人不載卿相車。", "子何布被不盖肉，浪自名士實則奴。", "假爲無能守編户，猶可自擇安閻閭。", "胡爲慘戚卒困此，去矣何屋不可徂。", "此居卑漥不待說，四髙中下流無渠。", "夏霖連延久積注，往往竈下秋生魚。", "始来圖此不自擇，終見坐與蚯蚓俱。", "何况梁榱日蛀腐，一仆非爾力可扶。", "苟求暫安急旦夕，反以身就殞壓虞。", "乃知窮則失自愛，死得正命有幾且。"]'),
('254c13a6-f095-4a82-853a-e8c6b01f382d','聞哭','王令','宋','宋诗','song-poetry','','[]','冬温春疫早，死者晨滿街。',72,'全唐诗/poet.song.39000.json','["冬温春疫早，死者晨滿街。", "但聞哭子悲，不聞哭母哀。", "老慈愛益深，壯剛氣則乖。", "嗜欲奪天性，情恩占妻孩。", "詩三百具存，聲已亡南陔。", "人情古不美，况復嗟今哉。"]'),
('9714d659-f656-4b28-bafd-87cb3ef2aaba','養賢','王令','宋','宋诗','song-poetry','','[]','萬鍾豈不多，財得孟子辭。',48,'全唐诗/poet.song.39000.json','["萬鍾豈不多，財得孟子辭。", "千乘友子思，猶曰須我師。", "古賢不易養，養賢則已而。", "今賢養自易，無於古加疑。"]'),
('274e7ee5-abd5-473f-92a0-241f68013da4','送李公安赴舉','王令','宋','宋诗','song-poetry','','[]','行子冠上塵，梁宋道傍土。',204,'全唐诗/poet.song.39000.json','["行子冠上塵，梁宋道傍土。", "塵逐冠敝損，人来還復去。", "馬蹄日月長，踏盡西北路。", "近者何紛紛，姿状頗秀舉。", "傳言天子詔，士得四方赴。", "来如鵲翅翻，去若蠅頭聚。", "市兒屈指計，過百日未暮。", "昔周方盛時，得士纔十數。", "唐虞此爲盛，中復容女婦。", "昔何稱才難，今也寜異趣。", "但恐所取異，今古殊尺度。", "夫君乃髙才，久有及物慮。", "今又奮絕去，挺拔欲自樹。", "余窮非所知，久有山林素。", "但無百畝粟，乃就羣才賦。", "仕道得亦嗟，困窮失爲懼。", "二者各有命，予亦何所與。"]'),
('9924ab8c-d878-429a-b1d9-d5722cc4ecd1','離髙郵答謝朱元弼兼簡崔伯易','王令','宋','宋诗','song-poetry','','[]','昔来何悠悠，今去亦泛泛。',180,'全唐诗/poet.song.39000.json','["昔来何悠悠，今去亦泛泛。", "豈自果進退，姑且便飲啗。", "三代今去遼，士食久已濫。", "徒死不爲義，可無苟石擔。", "平生墮百爲，且就投鈆槧。", "束身入世程，開口就人歎。", "怒喜有失得，眉睫煩窺瞰。", "野鳥或在籠，山猿有終檻。", "能安此爲命，雖失亦何憾。", "予嘗勇自明，磨古得前鑑。", "抱關賢所容，較獵聖或暫。", "庶未負初學，尚爲神所監。", "予行人之嗟，我笑不爲頷。", "子獨辱所厚，以詩繫歸纜。", "命和始自書，狂言庶非儳。"]'),
('869c8a7b-e800-4562-8020-78ea5fbf581f','東園贈周翊','王令','宋','宋诗','song-poetry','','[]','嘗聞東園游觀嘉，晚趁時節亦自到。',304,'全唐诗/poet.song.39000.json','["嘗聞東園游觀嘉，晚趁時節亦自到。", "東風不知来者多，一日芳蹊踏無草。", "山櫻着子寒尚遲，江梅殞蘤香可吊。", "扶疏枝葉未成蔭，偶来正值斜陽照。", "千株紅杏暖自酣，風引髙炬燒晴燥。", "夭桃未老已抽青，略略朱旗冠翠纛。", "雖然素李不爭花，似洗朱丹誇瑩皓。", "其他百種不可名，如列錦繡快晴曝。", "何低何髙何後先，一一盡解承春笑。", "楊花輕佻最得力，飛過青天去何冐。", "弱柳低垂弗辭賤，以力憑風爲春掃。", "黄鸝嘲啁聲語和，似對遊人見情抱。", "蝴蝶填委不知數，飛亂人眼漫顛倒。", "黄蜂雖忙不爲身，以甘遺人竟何道。", "子規終日勸客歸，吾無間然念何報。", "嗟余多病所趨乖，又懶讙呼逐年少。", "經年一春爲嘉時，行過不恤每自譙。", "然雖無酒不解歌，素遊尚少貧交召。", "何時期子早再遊，風雨不可旦夕料。"]'),
('afcaf3c2-f71b-411f-b0c2-e60f0e94a884','龍角歌和崔公度伯易','王令','宋','宋诗','song-poetry','','[]','嘗聞螾出軒轅丘，其長百尋圍十牛。',328,'全唐诗/poet.song.39000.json','["嘗聞螾出軒轅丘，其長百尋圍十牛。", "民驚臣愕爭論詶，帝亦謂應土德修。", "賜螾傍海連十洲，俾朝食壤暮飲流。", "仍命九龍狎其游，視龍有角急起羞。", "亟去訴帝龍有憂，帝憐不呵許爲謀。", "召一龍食繫其喉，揮萬力士乘其頭。", "披肉斷角塞螾求，螾取而冠萬鬼窗。", "雷號電泣竟莫捄，黿擗鼉踊弔蛟虬。", "奮穴出哭勞鱔鰌，八龍怒走乞天仇。", "天賜六丁皆劍矛，取螾拔角磔大幽。", "下龍載帝問何由，臣攀墮髯不可留。", "竟去不知天所尤，龍冤雖復骨不收。", "傳流下古說易浮，我聞其語疑有由。", "以龍易螾理若不，愛不知蔽似有繇。", "人皆傷龍爲歎啾，我獨鄙其與禍投。", "嘗聞龍德神自周，出飛于天入海休。", "棄此不處與螾儔，以養就人理固偷。", "果死以此嗟何仇，我来但愛遺角觩。", "是非欲竟理莫搜，君學窮物功搳掊。", "其說獨挽萬蠒抽，當有實論破衆廋，勉矣投以釣海鈎。"]'),
('5216f3f4-f1b3-4ac8-9594-4c3d60ca1bbd','春人','王令','宋','宋诗','song-poetry','','[]','春人輕飄喜聚散，春筵笑長白日短。',64,'全唐诗/poet.song.39000.json','["春人輕飄喜聚散，春筵笑長白日短。", "柳芽嚼雪噴盡寒，桃花燒風作春暖。", "春衣少年當酒歌，起舞四顧以笑和。", "紅天綠爛狂未足，春更不去將奈何。"]'),
('e380e193-d203-40a5-abc3-83577fbe2958','送贈王平甫','王令','宋','宋诗','song-poetry','','[]','士學何漫漫，近習忘遠紹。',204,'全唐诗/poet.song.39000.json','["士學何漫漫，近習忘遠紹。", "文章多自名，誰出得髙調。", "子才希世珍，拔俗起孤峭。", "如解萬里駿，不以覊縻要。", "篇章綴清新，霞電絢天彯。", "夜歸借之讀，掩紙疑有耀。", "洗手脱世塵，飛身就遐眺。", "舌骨誰謂朽，死魄如可召。", "縮手不願學，神巧謝人妙。", "余材生何偏，日月費吟嘯。", "收奇欲身名，攬古願獨弔。", "平生勇前爭，未始卻自料。", "一日接大敵，說舌忽忘挑。", "如秋九磨鏡，迫我以醜照。", "貪觀朝日明，退失兩目瞭。", "願假斧斤惠，刻形近天肖。", "寄聲誠甚勤，獻璞定逢笑。"]'),
('3340ab90-d3b6-4738-9e41-74a3d82a2130','山陽思歸書寄女兄','王令','宋','宋诗','song-poetry','','[]','淮風情舒舒，楚水日夜流。',288,'全唐诗/poet.song.39000.json','["淮風情舒舒，楚水日夜流。", "風能駕吾帆，水可載我舟。", "余歸知幾時，子望懸百憂。", "念我兄弟寡，商參各殊州。", "十年不一逢，會合何所由。", "幸逢子来歸，與我相慰投。", "甥兒入吾牽，甥女出吾留。", "子吾笑其間，貧不知可愁。", "心如熙春陽，樂若醉酒酬。", "憶我别子日，將行更逗遛。", "泣恐傷子心，淚出仰目收。", "别日才幾時，别思日九秋。", "心隨西北風，目望東南樓。", "主人仁且賢，憐我覊旅遊。", "晨粳玉炊香，暮酒金注甌。", "盤蔬羅春青，豆脯兼夕鱐。", "爲食豈不美，義咽不下喉。", "要當歸子同，半菽飽亦優。", "始予志所學，義當望軻丘。", "朅来與世評，衆口忽起咻。", "嘗觀世金朱，此道久巳偷。", "胡爲不奮去，附世如贅旒。", "而子亦待人，特以貧不謀。", "參差兩如此，偃蹇勢略侔。"]'),
('b0f668db-7421-4c6c-a4b1-6463f552b03b','大舟','王令','宋','宋诗','song-poetry','','[]','大舟無風帆不舉，小舟榜入青冥去。',32,'全唐诗/poet.song.39000.json','["大舟無風帆不舉，小舟榜入青冥去。", "漁子舟中呼且歌，夜半聞魚誰得多。"]'),
('8ea463c5-61f4-4bd5-bf73-1333a00457ba','望花有感','王令','宋','宋诗','song-poetry','','[]','春来幾時余不知，但怪日日柳梢好。',128,'全唐诗/poet.song.39000.json','["春来幾時余不知，但怪日日柳梢好。", "我嗟無地自種花，常恐東風只生草。", "誰家有園不可入，時時縱欲信自到。", "寒梅最香落已闌，桃杏雖遲亦顛倒。", "髙枝飛鳥夜踏空，低樹狂兒日摧抝。", "惟餘零落滿地紅，主人更聽奴頻掃。", "悲来四顧慷慨歌，要且傾酒澆顔酡。", "春歸欲挽誰有力，河濁雖泣行奈何。"]'),
('0c3300dc-4619-4048-915f-01c21c7a0c66','小雨','王令','宋','宋诗','song-poetry','','[]','一夜風聲驚屋破，四鄰叩壁呼我賀。',64,'全唐诗/poet.song.39000.json','["一夜風聲驚屋破，四鄰叩壁呼我賀。", "久知旱勢非所期，果見雨逐浮雲過。", "庭塘流注已有餘，田畝不霑亦何奈。", "雷嗔電笑竟何爲，幽人空廢南軒卧。"]'),
('57705542-f9ad-4b98-b34a-eea6b268fa5c','餓者行','王令','宋','宋诗','song-poetry','','[]','雨雪不止泥路迂，馬倒伏地人下無。',112,'全唐诗/poet.song.39000.json','["雨雪不止泥路迂，馬倒伏地人下無。", "居者不出行者止，午市不合入空衢。", "道中獨行乃誰子，餓者負席緣門呼。", "髙堂食飲豈無棄，願從犬彘求其餘。", "耳聞門閕身就拜，拜伏不起呼羣奴。", "喉乾無聲哭無淚，引杖去此他何如。", "路旁少年無所語，歸視紙上還長吁。"]'),
('713e9467-a765-4b9b-ad4f-96dc77160a1d','世言','王令','宋','宋诗','song-poetry','','[]','紛紛世俗言，病客久厭聽。',48,'全唐诗/poet.song.39000.json','["紛紛世俗言，病客久厭聽。", "聖賢没已遠，是非久無定。", "六經紙上言，黑白欲誰証。", "獨有自信人，中得不外競。"]'),
('25e927de-0a46-4e62-872d-43656b340d8b','暨陽居四首  其一','王令','宋','宋诗','song-poetry','','[]','出無王事牽，入不治居舍。',72,'全唐诗/poet.song.39000.json','["出無王事牽，入不治居舍。", "蒿藜入墻屋，塵垢變几架。", "糟糠苟無憂，智力取自暇。", "逢詩即廢日，得客輙忘夜。", "積懶遂成性，習勤反如詐。", "幾不類怠傲，愧恥將何謝。"]'),
('3f2319a2-14f3-4045-b63d-c72245027051','暨陽居四首  其二','王令','宋','宋诗','song-poetry','','[]','身非爵與官，車馬久不謀。',72,'全唐诗/poet.song.39000.json','["身非爵與官，車馬久不謀。", "家無田倉儲，雀鼠非我仇。", "朝出從人居，詩書講前修。", "暮從兒子嬉，歡笑何所憂。", "間將筋力疲，懶使志慮收。", "斗糈尚煩送，誰謂能無求。"]'),
('9986af40-ebe7-42ef-8e95-5bd36f6e5dfc','暨陽居四首  其三','王令','宋','宋诗','song-poetry','','[]','自吾暨陽居，已見月四周。',48,'全唐诗/poet.song.39000.json','["自吾暨陽居，已見月四周。", "流年不我謀，寒暑忽已遒。", "老来何足嘆，苟死固可羞。", "子今用力薄，暮齒將何收。"]'),
('0570d9e6-eeb8-4888-bfa4-b48f07696387','暨陽居四首  其四','王令','宋','宋诗','song-poetry','','[]','斯道久冺冺，斯人固悠悠。',48,'全唐诗/poet.song.39000.json','["斯道久冺冺，斯人固悠悠。", "歸豚非吾心，在禮惡不酬。", "從人效屈伸，俯仰不自由。", "於命有當然，信矣何足羞。"]'),
('2f529faf-9293-4904-a5a7-b2ba55ed9119','寄題宣州太平縣衆樂亭爲孫莘老作','王令','宋','宋诗','song-poetry','','[]','令君架亭樂荒幽，得地適與萬景投。',288,'全唐诗/poet.song.39000.json','["令君架亭樂荒幽，得地適與萬景投。", "亭成雖名爲衆樂，地僻無客誰與遊。", "訟休民去吏隨散，獨有文字與令留。", "把書開闔坐自笑，回視令職忘卑陬。", "昔聞酒賤喜易醉，今說魚美予何憂。", "彈琴有聲尚近俗，要解弦絕以意求。", "况持髙懷屈下邑，志氣略與彭澤侔。", "身嬰民憂手持版，心愛山水寜非偷。", "景好不見但聞說，使我耳目私相仇。", "亭前行跡不破草，亭下野鳥常喧啾。", "山雲朝嘘翠巘出，海月夜下清溪浮。", "春花夏蔭已有愛，况使風雪回冬秋。", "惜予不得與快意，共上岑崒望九州。", "黄山聞好眼未識，夢想欲到迷無由。", "圖傳粉墨固未好，願假壮筆一攬收。", "果逢来篇騁雄勝，若執造化窮凋鎪。", "一時文工豈不偉，千里寄我何以酬。", "耳昏俗語久欲洗，爲我一謝山前流。"]'),
('3e4adc8e-b331-467d-bb73-fc5dfebb3dba','謝客二首  其一','王令','宋','宋诗','song-poetry','','[]','擾擾車馬客，各以勢利奔。',96,'全唐诗/poet.song.39000.json','["擾擾車馬客，各以勢利奔。", "自問閭巷人，何爲亦紛紛。", "與客成往還，勉就俗所敦。", "禮不經聖人，頗厭後世煩。", "欲問無所得，歸視紙上文。", "非以孔子心，尚拜陽貨豚。", "乃知偪仄間，心跡久已分。", "去矣可奈何，更問来者門。"]'),
('e1b514c6-3aac-4165-bbd8-d77f35704351','謝客二首  其二','王令','宋','宋诗','song-poetry','','[]','躚躚出何爲，奄奄歸就卧。',96,'全唐诗/poet.song.39000.json','["躚躚出何爲，奄奄歸就卧。", "不知身所謀，徒與俗相和。", "本無聲利求，久厭車馬過。", "詩書雖滿前，走奔不暇坐。", "收身衣食餘，抱病歲月破。", "得不勝所忘，進亦何可課。", "前躅杳難躋，下愚旋易墮。", "得勢有然爾，命矣何可奈。"]'),
('30302a0e-2722-4c75-838d-b383c58155bb','春遊','王令','宋','宋诗','song-poetry','','[]','春風誰相呼，鳥語到庭户。',216,'全唐诗/poet.song.39000.json','["春風誰相呼，鳥語到庭户。", "罷書起何遊，繫馬城西樹。", "寜須客衆隨，聊與春相遇。", "髙林美風竹，疏影有清覆。", "可以便行坐，解脱快巾屨。", "日長天地寛，飄戾飛雲度。", "風枝綠未柔，日蕚紅先露。", "芳辰信可尚，嘉興惜無寓。", "舊聞黄公壚，頗枉壯士顧。", "予雖輕數子，自適偶同趣。", "起解身上衣，就貰青旗酤。", "獨酌不待勸，興至還自注。", "對物無所語，似若喧譁惡。", "雖無歌舞歡，幸可篇章賦。", "乾坤本閑暇，人物自紛遽。", "勞苦曷不樂，歲月失已屢。", "酒闌起四望，落日不可駐。", "饑馬自知家，何須問歸路。"]'),
('2352cd1b-48c0-4195-a454-1f9849f6012b','游江陰壽寜寺','王令','宋','宋诗','song-poetry','','[]','寥蕭枝上風，蜩蟄以秋告。',132,'全唐诗/poet.song.39000.json','["寥蕭枝上風，蜩蟄以秋告。", "黯靉道旁樹，蔭綠凉可冐。", "况承積陰餘，急雨蕩晴昊。", "初凉逞新威，宿暑懲舊躁。", "漫漫出門路，踽踽可誰造。", "江聲洶西奔，海遠劇東到。", "中間可行望，洗滌去塵抱。", "况於林阜間，古屋架晴燥。", "蚊蝱稍歛收，軒户可淹傲。", "惜乎余獨游，不可擕所好。", "踟蹰竚歸步，風作冷相勞。"]'),
('873616b3-4431-4863-87eb-19b8c07e1938','賦黄任道韓幹馬','王令','宋','宋诗','song-poetry','','[]','天寶天子盛天廐，吐蕃入馬上天壽。',240,'全唐诗/poet.song.39000.json','["天寶天子盛天廐，吐蕃入馬上天壽。", "紫衣馭吏偏坐前，騎入都門不容驟。", "西極苜蓿得氣肥，六閑飛黄卧嗟瘦。", "千秋殿下誰把筆，當時人無出幹右。", "傳聞三馬同日死，死魄到紙氣方就。", "鐡勒夹口重兩衘，墨絲丱尾合雙紐。", "天門未上人就觀，老胡驚嗟失開口。", "生搜朔野空毛羣，死斷世工無後手。", "當時天子惜不傳，送入御府置官守。", "胡塵勃欎燕薊来，宫闕蕭騷既焚後。", "誰棄千金出手收，足踏萬里避奔走。", "幾經蹂蹀道邊塵，今日寜無紙上垢。", "罇前病客不識畫，但驚馬氣世未有。", "冀北駿骨無時無，生不逢幹死空朽。", "世工無手不肯休，任使氣骨陋如狗。"]'),
('954c253d-7936-4b11-9c2a-584de924d120','甲午雪','王令','宋','宋诗','song-poetry','','[]','平居汩汩喜自墮，萬事過目不省窺。',384,'全唐诗/poet.song.39000.json','["平居汩汩喜自墮，萬事過目不省窺。", "一年南北兩見雪，未始把筆成一詩。", "朝看氣象浩茫昧，夜歸瞑想通幽疑。", "夢乘虛空謁帝所，砆礩象柱承瓊榱。", "坦塗壁堊相照射，鶴扇虧蔽狐腋帷。", "帝旁鮮鮮舞萬女，寶綃雅冶吹裳衣。", "纍蠙貫瑀錯組佩，斥棄朱黛素兩眉。", "撩搔王母戯華髪，袒脱姑射爭膚肌。", "提璫擲珥互投報，顧我塵垢加笑譏。", "其傍臨臨立萬鬼，帝所寵與借色辭。", "密呵細紵賜裘舄，笑齒發露寒差差。", "諸神斂避不敢望，棄唾墮落成珠璣。", "朝懽嚱怡棄烟霞，暮慨吁吸成雲霏。", "互偷天帑購黨與，散布萬玨分千珪。", "紈羅練縠不計數，逆取倒曳交横披。", "鞭驅巨靈刦夸父，揮斧解繫關星機。", "東觀豗頹墮壁角，南顧秃鬝亡斗箕。", "其他雜冗莫分辨，徒見漫亂如籮篩。", "雷公爭前泣訴帝，至此豈可無省知。", "願分羽衛勑天討，助以積雹千山齊。", "金神擁遏按行道，後乘駕以萬玉蜺。", "寶刀聯翻夹鐡盾，玉戟鈎子横珠旗。", "天風蕭蕭吹縞素，貝甲合陣窮天圍。", "磨砮插羽注萬矢，强弩競發相聯飛。"]'),
('77970dcb-eb87-4343-84dc-fd88bb172388','日蝕','王令','宋','宋诗','song-poetry','','[]','錢塘山人大署壁，曰十月朔日且蝕。',178,'全唐诗/poet.song.39000.json','["錢塘山人大署壁，曰十月朔日且蝕。", "坐者跳起行者留，愚聞之驚智爲惑。", "我時過市偶自停，眩兩目視閙耳聽。", "自嗟身賤不有位，安得置此誅四刑。", "惟此丙申日在未，天面黯欎昏不濟。", "舉頭仰日已半虧，羣陰得志雲不披。", "塵函欲開鏡尚掩，誰把白壁塗之泥。", "大哉玄象浩難測，安有庸人以術得。", "天乎反成竪子名，不念吾皇禳以德。", "吾聞日名爲大明，光一自出滅月星。", "今乃爲之成薄蝕，安得君子不爲小人乘。"]'),
('a2af0e10-1920-4af3-8f9b-7f632aaddc02','送曹杜赴試禮部','王令','宋','宋诗','song-poetry','','[]','霜風琅琅鳴鼓鼙，鳥寒夜噪樹折枝。',256,'全唐诗/poet.song.39000.json','["霜風琅琅鳴鼓鼙，鳥寒夜噪樹折枝。", "居者不出行者歸，廐馬解銜車棄脂。", "長河夜冰船就維，百賈晏起朝閉扉。", "爲問當今行者誰，出門千里到何處。", "母送拊背父嘆嘻，兒惜欲去哭挽衣。", "上馬反顧紛涕洟，非所願欲去何爲。", "家雖有田豐歲稀，所得償公不及私。", "况望羶薌事庭闈，結髪從學今十朞。", "始自有志狥孔姫，豈願從世成依違。", "髙堂華髪紆素絲，暮年待子爲光輝。", "望我日久莫報之，苟得一笑辱弗辭。", "况望三釡家無饑，吾於二子久所知。", "怪其才髙所就卑，今乃語此誠可思。", "近聞天子變典彛，欲撥舊况收新奇。", "子行出仕適其期，驊騮得路無啣覊。", "罷酒行矣無自遲，去取天寵酬親慈。"]'),
('2d55081a-0464-4c22-a9e3-e6fe650c8ec7','同孫祖仁王平甫遊蔣山作','王令','宋','宋诗','song-poetry','','[]','山形欎盤陀，石路隨直紆。',288,'全唐诗/poet.song.39000.json','["山形欎盤陀，石路隨直紆。", "蔭松坐興長，飲泉百煩除。", "憶望江上樓，采翠横晴虚。", "愛之不能去，取席卧與俱。", "若逢佳賓客，不暇外禮拘。", "意愛交自然，笑語略可無。", "常思一往遊，杖履窮昏晡。", "忽從賢豪招，氣類喜不殊。", "更以肴酒隨，傾瀉談笑餘。", "仰躋蒼崖巔，下視白日徂。", "夜半身在髙，若騎箕尾居。", "懽餘悲感集，論說追古初。", "在昔天下衰，羣姦起相屠。", "相地視八極，懷險歸此都。", "全吴既臣魏，餘晉仍避胡。", "此山古所瞻，形勢髙四隅。", "游者昔爲誰，名字不見書。", "想當出塵樊，盤礴望八區。", "固宜有髙興，何亦妄滯濡。", "憶在初元年，虎狼出當塗。", "衆豪泣相盟，萬甲聚一呼。", "樓船下三江，千里懸旌旗。", "忠謀屈巨猾，弱力張遠圖。", "乞靈訴明神，至此嘗踟蹰。"]'),
('f290e541-f66a-4f7e-aea7-124c4493d9d2','對竹','王令','宋','宋诗','song-poetry','','[]','竹風何撩蕭，晝靜發寒籟。',120,'全唐诗/poet.song.39000.json','["竹風何撩蕭，晝靜發寒籟。", "修纖諤天官，揚揖縱玉佩。", "豈無俗子遇，自會幽人愛。", "心虚中養恬，節密外御介。", "春萌喜含養，夏籜竟分解。", "無花與物爭，有蔭亦人賴。", "威威南山鳳，爾飛何時届。", "道遠寜不饑，寒枝久虚待。", "豈非繒繳虞，安有羽翮態。", "當奈葉間蟲，蠧爾所食壞。"]'),
('17b90089-91ee-46f2-8d52-099b5714aa68','暮行','王令','宋','宋诗','song-poetry','','[]','晴烟去人髙，暮色上天半。',120,'全唐诗/poet.song.39000.json','["晴烟去人髙，暮色上天半。", "山衘日入深，雲佇星出緩。", "塗昏歸鞍長，林近去翎短。", "悠悠宵偃慵，衍衍暮行欵。", "南城岌髙躋，近野匝四坦。", "来期遐思舒，暮雲所見罕。", "星星颭風燈，歷歷吹月琯。", "靜樂遺世喧，清思破塵懶。", "心通江海浮，氣寒天地滿。", "兹興將誰同，兒輩未宜筭。"]'),
('4444fc9f-0b46-4fcf-8ee9-cd9b390d66b3','野步','王令','宋','宋诗','song-poetry','','[]','久攖末俗喧，脱就綠野靜。',132,'全唐诗/poet.song.39000.json','["久攖末俗喧，脱就綠野靜。", "方隨巾屨便，那暇賓客命。", "林紅落春衰，草綠爭夏盛。", "時從老農語，久佇行子聽。", "謂言勞苦後，各以閑暇慶。", "時逢瓶盎酒，亦有肴核稱。", "喧嘲忽無次，歌唱仍相詠。", "酒闌紛起坐，白髪忽兩凴。", "兒乘旁樹嬉，牛卧前籬瞑。", "予方困俗累，愛此近天性。", "何當從之歸，買舍與相並。"]'),
('8c1ed0bc-50bf-4c3b-a1c9-480d6327d6be','古風','王令','宋','宋诗','song-poetry','','[]','古風何寥疏，世方盛誇慕。',156,'全唐诗/poet.song.39000.json','["古風何寥疏，世方盛誇慕。", "利塗劇先趨，直軌迷曲注。", "渾渾九河翻，仡仡百川注。", "分爭或多岐，斂枕纔一趣。", "睢盱承至歡，讋叠謝絕怒。", "才得升斗多，勉售形骸顧。", "不知萬鍾得，孰與一日裕。", "况承丘山羞，願易頃刻遇。", "誰能脱近役，自放就遐騖。", "航湖足茭魚，拔野厭芼茹。", "行招千古遊，坐與来世語。", "延風敞虛襟，揖月坐嘉樹。", "此意固有然，童兒未堪預。"]'),
('06e90f91-37ca-41ab-9a66-9b5b813bda0a','蘄口道中三首  其一','王令','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','舟行邈棲遲，江流潏排蕩。',48,'全唐诗/poet.song.39000.json','["舟行邈棲遲，江流潏排蕩。", "魚驚躍或出，鷺下飛何颺。", "交游偶相舍，偃息聊自放。", "回首失匡廬，雲霏暮方上。"]'),
('b448094f-14a0-417b-9cda-f8806ed0f74f','蘄口道中三首  其二','王令','宋','宋诗','song-poetry','','[]','稍稍江上雨，聲入窗壁寒。',96,'全唐诗/poet.song.39000.json','["稍稍江上雨，聲入窗壁寒。", "悄悄舟中人，曲肘自枕眠。", "安卧不成寐，起坐浩長嘆。", "離家日逾百，行路忽巳千。", "昔與燕俱来，今見北鴈還。", "道里苦不通，寄書如棄捐。", "風水相噴薄，歸期渺無端。", "空令秋夜夢，反覆如循環。"]'),
('d1bade1a-9425-43fd-b50b-955e84d26421','蘄口道中三首  其三','王令','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','維舟泝江流，人力與水爭。',48,'全唐诗/poet.song.39000.json','["維舟泝江流，人力與水爭。", "回視東下人，恍如御風行。", "誰能倒長江，奔瀉暫西傾。", "聊用快客意，何憚魚龍驚。"]'),
('e814d136-7efd-4adf-a623-be84487981ba','贈廬山老居訥','王令','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','訥公匡廬老，詩句整以雅。',120,'全唐诗/poet.song.39000.json','["訥公匡廬老，詩句整以雅。", "標韻樂天淳，不肯外禮假。", "所居遠城市，絕俗就閑暇。", "崗崖道路惡，亦爲佳客下。", "余雖昔所聞，相見今乃乍。", "愛其語言好，超絕忽世跨。", "馬舁就其居，燈火共清夜。", "惜不見其壯，已老吁可訝。", "髙才可施用，售世嗟無價。", "臨别更何論，共是忘言者。"]'),
('db24d71d-17f7-44bc-b207-1b32e3c88e80','旅次寄寶覺訥師','王令','宋','宋诗','song-poetry','','[]','小雨破宿暑，曉風忽焉遒。',120,'全唐诗/poet.song.39000.json','["小雨破宿暑，曉風忽焉遒。", "山深樹翳陰，蜩蚻應已秋。", "清坐想髙絕，語言誰應酬。", "豈不念一往，抱病終自留。", "覊旅少往還，有来或非儔。", "命僕一謝之，縱我冠屨休。", "移床上髙堂，解書散床頭。", "於此有嘉興，念世誰與謀。", "獨思山林人，兹意可綢繆。", "何當買田廬，共遂丘壑游。"]'),
('238c2f03-9b64-40b8-a2fd-31804acd00b3','寄吕惠卿吉甫兼簡林伯通','王令','宋','宋诗','song-poetry','','[]','踆踆門外馬，客至知謂誰。',204,'全唐诗/poet.song.39000.json','["踆踆門外馬，客至知謂誰。", "昔面尚未逢，那論心相知。", "揖客拜上堂，謝客辱弗遺。", "寒暑相問酬，唯諾坐無爲。", "靜默近尤遠，多言足瑕玼。", "勉從客所論，還顧所學非。", "念此廢無益，對書坐長嘻。", "獨思同懷子，念遠莫見之。", "豈無寄我書，歲晚若苦遲。", "聞頗困王事，豈無閑暇時。", "况有同僚賢，相期在書詩。", "人生天地間，常恐食所縻。", "去就兩莫謀，會合寜有期。", "余病不自樂，舊學益以隳。", "近者非所同，遠者勞夢思。", "江水日夕東，道途宛而夷。", "寄書當在勤，無謂往還稀。"]'),
('5704b8d0-af41-4366-9c28-9dd10f88813b','寄崔伯易','王令','宋','宋诗','song-poetry','','[]','擾擾閭巷士，過我何所爲。',204,'全唐诗/poet.song.39000.json','["擾擾閭巷士，過我何所爲。", "屢来徒我煩，不来我弗思。", "少年樂知聞，喜與客子隨。", "晚歲事恬默，與世益參差。", "騎馬出尋人，中路輒自歸。", "歸来亦何樂，書史自相期。", "巳與往者親，可無兹世違。", "欲語無所得，起視北鴈飛。", "念子遠千里，昔别今巳期。", "寄聲雖云多，所得竟亦稀。", "近者忽報書，期我往就之。", "不知予苦窮，繫此不可離。", "尚迫朝暮憂，寜有道路資。", "人生少所同，老去財幾時。", "予勢既若此，子復不肯来。", "但恐百年間，齟齬終莫齊。", "詩以寄子招，亦以寫我悲。"]'),
('b49195c6-fc8f-451f-959a-bf249d1df243','寄孫莘老','王令','宋','宋诗','song-poetry','','[]','默默不自得，勞勞非吾任。',216,'全唐诗/poet.song.39000.json','["默默不自得，勞勞非吾任。", "不與君子逢，誰復明此心。", "偶客来自南，口有千里音。", "知無木索勤，頗復山水吟。", "對之爲一笑，欣如獲千金。", "宣城風物佳，古語昔已忱。", "太平又其有，道途邈幽深。", "溪流渺彎環，山勢屹抱臨。", "况復寂寞人，黄綬事陸沉。", "公田秫既收，客席酒屢斟。", "悔予昔南浮，不往一就尋。", "波濤忘日月，疾病廢古今。", "歸来就覊銜，外慮日已侵。", "適時愧非才，對客輒自瘖。", "譬如火炙膚，暫忍久莫禁。", "惟思百畝田，爲可足釡鬵。", "投身脱世箝，歛足蹈古箴。", "寄言所同懷，相期在中林。"]'),
('8335e921-addf-441d-a925-8600ad918266','夏日平居奉寄崔伯易兼簡朱元弼  其一','王令','宋','宋诗','song-poetry','','[]','天風變春和，晝日差夏永。',108,'全唐诗/poet.song.39000.json','["天風變春和，晝日差夏永。", "門闌閉無事，燕雀去益靜。", "紛翻詩書帙，棄散懶收整。", "時来就枕卧，復可取窺省。", "心恬逐物閑，迹濶與世屏。", "鮮鮮南山暖，秀色在脩嶺。", "苟嫌安坐慵，還可遠遊騁。", "自緣智能薄，反得閑暇幸。", "交朋久相遠，疏懶欲誰警。"]'),
('1e2c13c9-0351-47cf-97a6-9db7e0a1c632','夏日平居奉寄崔伯易兼簡朱元弼  其二','王令','宋','宋诗','song-poetry','','[]','憮憮庭下樹，陰影日已敷。',132,'全唐诗/poet.song.39000.json','["憮憮庭下樹，陰影日已敷。", "癯癯閉門人，簟席自卷舒。", "髙枝就遠冠，曲枝掛裳裾。", "還來從此息，卧視詩與書。", "桓桓門外客，從徒駕驪駒。", "不知來何聞，乃肯顧我閭。", "呼兒往應門，謂言出在塗。", "非我敢厭客，非客與我疏。", "以予拙語言，無以得客娛。", "一不當客意，恐與世患俱。", "不如兩相忘，何能效紛如。"]'),
('441e0572-49cd-4a02-9b03-2e27ea7e641b','效古','王令','宋','宋诗','song-poetry','','[]','流沙不勝車，弱水不載舟。',48,'全唐诗/poet.song.39000.json','["流沙不勝車，弱水不載舟。", "謂言行子歸，無苦事遠遊。", "寄子素絲裳，聞子衣苦單。", "失今不来還，歲晚將奈寒。"]'),
('92f1fbd9-4e15-4936-8e24-3506f5ab88ba','送朱明之昌叔赴尉山陽','王令','宋','宋诗','song-poetry','','[]','朱使拜書天上回，去以身試百里障。',208,'全唐诗/poet.song.39000.json','["朱使拜書天上回，去以身試百里障。", "青衫飄若風外荷，借馬載出塵土上。", "凖眉嶄如見天秀，獨立繫馬萬里望。", "身軀雖小胸腹寛，沛如絕海横秋漲。", "久宜脱絕事髙致，豈願卑冗勞俗狀。", "髙堂華髪親老矣，四海無家寄几杖。", "世外言髙信獨奇，人前腰折嗟已强。", "尉官雖小俸雖薄，猶有餘錢買甘養。", "想當家帷奉顔面，綵衣躬率婦子餉。", "詵詵兒女戲滿前，累累諸兄坐相向。", "人間此樂不可幸，一笑自足百辱當。", "時清固應稀盗賊，俗弊寜不煩笞掠。", "好偷閑暇事簡編，思予寜無尺字况。"]'),
('ebf6d74a-8ca1-4014-a9e4-8babac13c75c','學子','王令','宋','宋诗','song-poetry','','[]','瑣瑣来學子，從我問古風。',96,'全唐诗/poet.song.39000.json','["瑣瑣来學子，從我問古風。", "謂言古之人，學不求世功。", "以其明智餘，施與天下同。", "能知學爲身，自不恤窮通。", "童子顧我笑，是言得無蒙。", "斯道使可遵，曾不聞父翁。", "謂言童子歸，益自謀厥躬。", "吾不能爾言，亦不必爾從。"]'),
('fd363819-3c60-4bf1-b5c7-5a73b597b9f7','出門','王令','宋','宋诗','song-poetry','','[]','出門將何從，中道忽自思。',48,'全唐诗/poet.song.39000.json','["出門將何從，中道忽自思。", "彼懷與爾殊，亦合念子歸。", "樂有詩與書，遊有山與陂。", "誰言竟無從，猶有影自隨。"]'),
('29c74baa-654c-49a7-bdc6-3ca3b31e9d39','雜詩','王令','宋','宋诗','song-poetry','','[]','古人重非道，饑不苟豆羮。',48,'全唐诗/poet.song.39000.json','["古人重非道，饑不苟豆羮。", "有爲非其心，或不脱冕行。", "如何後世人，以官業其生。", "鄙哉樂欺人，猶以聖自名。"]'),
('b137c9d6-d8b0-4d4e-9a06-316f5b56139c','寄滿子權','王令','宋','宋诗','song-poetry','','[]','昔心何悠悠，今學益漫漫。',288,'全唐诗/poet.song.39000.json','["昔心何悠悠，今學益漫漫。", "莽如浮江河，浩不際崖岸。", "生雖樂文字，勤不償几案。", "重編空堆塵，折簡久枯汗。", "徒知陳市肆，表列環四畔。", "已無探討勤，胡可賢否按。", "零丁晚觀玄，泯滅舊習彖。", "得指来歲期，失忘去日筭。", "嘗聞勤惰間，已是愚智判。", "蒙羞欲何顔，避恥愧無翰。", "不能繩已怠，何力禁人叛。", "文章觸世嫌，議語限客竄。", "時牽好惡卑，俗撓是非亂。", "早衰奪舊剛，多病襲新懦。", "心經衣食艱，事廢米鹽半。", "何謀脱身去，割迹與俗斷。", "耕荒食新收，鑿窒復舊貫。", "念生如冬冰，至死僅春泮。", "其間能幾時，何恃苦自緩。", "翩翩淮南英，顯顯士林冠。", "方予未爲游，辱子昔同閈。", "篇章覿新華，論說聽横捍。", "包奇晚自走，去實王府玩。", "近書何相撩，頗以名見謾。"]'),
('2e506f10-c7de-4c7f-87af-cf0cffcc1357','梅花','王令','宋','宋诗','song-poetry','','[]','風吹冬暖變春暖，江梅艶艶横新枝。',224,'全唐诗/poet.song.39000.json','["風吹冬暖變春暖，江梅艶艶横新枝。", "經年不逢間何久，忽此相遇如有期。", "初開珊珊尚寂寞，仙人綴佩懸瑶璣。", "後日重来不可辨，漫漫月樹留寒輝。", "清香芬敷去何遠，可惜不使蝶得知。", "遊人爭至無日夜，對之但笑果喜誰。", "不知春工用何術，摶造萬物皆可爲。", "得非各使出所巧，約與鬭競合一時。", "不然裁剪未易給，鞭役衆鬼寜不噫。", "終年成功財幾日，旋亦墮壞良可悲。", "傳聞昔時大烹享，九牛合鼎羊豕隨。", "一取所實薦滋味，神啜不吐人食宜。", "安知後世無所用，兒嚼不美還棄之。", "古今萬事皆若此，爲爾繞樹成嗟咨。"]'),
('432f0d3a-2409-4b1b-89e1-ea32ee6ad204','金山','王令','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江從天来，意欲以地分。',132,'全唐诗/poet.song.39000.json','["長江從天来，意欲以地分。", "西山避之逃，東山開爲門。", "木石所不捍，土沙固隨奔。", "東西兩隨海，勢已無完坤。", "如何中流居，獨遏萬里渾。", "坤維賴繫得，地靈煩窺捫。", "不然已飄泊，兩分不相存。", "禹力所不除，天意固可論。", "余欲沉九淵，下視萬古根。", "畏强激常情，中立愛此墩。", "詩成欲誰和，感慨心徒煩。"]'),
('2e7a76cd-851f-47b0-b6fd-95ca23c7230f','客次寄王正叔','王令','宋','宋诗','song-poetry','','[]','夜長夢反覆，百瞑百到家。',48,'全唐诗/poet.song.39000.json','["夜長夢反覆，百瞑百到家。", "歲計晚未成，客愁與日加。", "長途千萬門，何地容我過。", "而子壯亦貧，與余同一歌。"]'),
('f838b11a-1b05-4277-889b-406cc42517bd','南山雪','王令','宋','宋诗','song-poetry','','[]','世於利禄不擇義，苟可走奪足恐蹉。',96,'全唐诗/poet.song.39000.json','["世於利禄不擇義，苟可走奪足恐蹉。", "家儲千金吝銖兩，不敢盡費烏用多。", "百年到死財幾日，恃若固有理則那。", "莊生嘗以富爲病，愛其放達與俗過。", "南山衣雪變羣玉，舉以賣世售幾何。", "山翁固亦富自喜，稚子無誚貧猶歌。"]'),
('4b1f0871-7c97-4a47-9bb2-70c2f8f31a6c','短謡','王令','宋','宋诗','song-poetry','','[]','窗中燈冷暈重綠，窗前西風葉相逐。',128,'全唐诗/poet.song.39000.json','["窗中燈冷暈重綠，窗前西風葉相逐。", "曉霜披瓦月上軒，枕夢不成鴈聲續。", "拂衣起步行繞壁，萬慮無成淚沾臆。", "鉄房老劍澁不青，閃繫八柱不可索。", "白晝出門歸路迷，冬日易夜還空歸。", "人將豪傑視如草，天困英雄未與時。", "長鯨滯斬海波揺，塞甲不卷邊塵囂。", "吾徒顦顇乃如此，安得長喙呼重霄。"]'),
('05ca1146-a15c-4bb7-9d30-bccea8d47f0b','暑旱苦熱','王令','宋','宋诗','song-poetry','','["\u590f\u5929", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u6292\u6000", "\u5b8b\u8bd7"]','清風無力屠得熱，落日著翅飛上山。',64,'全唐诗/poet.song.39000.json','["清風無力屠得熱，落日著翅飛上山。", "人固已懼江海竭，天豈不惜河漢乾。", "崑崙之高有積雪，蓬莱之遠常遺寒。", "不能手提天下往，何忍身去遊其間。"]'),
('82742eda-f02a-4edd-abd0-5459f3d45625','贈杜漸子長','王令','宋','宋诗','song-poetry','','[]','吾鄙少與合，杜子愛所多。',48,'全唐诗/poet.song.39000.json','["吾鄙少與合，杜子愛所多。", "直木有正性，深源無亂波。", "齒少蔚未冠，心古先已皤。", "卓哉金石姿，勉矣勤鍜磨。"]'),
('0f04f6e9-94ad-4c55-82e1-c81fe3391a75','交難贈杜漸','王令','宋','宋诗','song-poetry','','[]','兩鼠共謀渴，相飲期入水。',120,'全唐诗/poet.song.39000.json','["兩鼠共謀渴，相飲期入水。", "一鼠下縋缶，一鼠上啣尾。", "前鼠以之跌，後鼠以之死。", "鼠死何足噫，夫人纔可悲。", "平地把手笑，乘崕撥足擠。", "賊防易爲力，壯楗完墻籬。", "交防難爲人，笑面惡肝脾。", "前日信其是，今日悟其非。", "安得先知明，有如灼火龜。", "然則奈之何，期子同吁戲。"]'),
('ff782281-3052-4da5-be9b-bb477dc50579','答友人','王令','宋','宋诗','song-poetry','','[]','幽蘭生深林，不佩亦自臭。',288,'全唐诗/poet.song.39000.json','["幽蘭生深林，不佩亦自臭。", "天馬苟伏皁，駑足日加驟。", "蘭生喻人學，不爲仕乃究。", "馬伏侔自怠，一失遂永後。", "以今曷爲言，念子不可逗。", "前我初識子，愛其肌骨秀。", "又觀所爲詩，往往擅髙右。", "迨熟相與言，低俯如有就。", "我樂成美者，遽以古詩叩。", "上言髙雄張，中雜富貴鬬。", "且將起其貪，固欲激其懋。", "尚謂非重邀，猶恐信不厚。", "揮汗謝爲書，戴雨去自奏。", "予始喜此讀，若獲弦逐彀。", "如何答我詩，遽此與前謬。", "我始得則謝，實若答雉嗅。", "大凡欲有爲，當决如蝠狖。", "苟進又安退，何自鼠穴首。", "吾見人自荒，未有耕不收。", "設或堅决爲，加以勤自副。", "石將爲溜穿，曲亦因累揉。", "大可入聖域，中能踐賢囿。", "借使不及然，猶足聞見富。", "中吾不可止，在我固無疚。"]'),
('a558c1b7-7e87-43c4-b395-2a15a26215e6','道士王元之以詩爲贈多見哀勉因以古詩爲答','王令','宋','宋诗','song-poetry','','[]','利劍不刺鼠，大釣不聯鮞。',288,'全唐诗/poet.song.39000.json','["利劍不刺鼠，大釣不聯鮞。", "天昏白日沉，劍决浮雲披。", "地蕩海水揺，釣引九鯨縻。", "固其用不常，安得易用爲。", "當其未效間，是亦鉛與鈹。", "吾非小丈夫，胸中少翹奇。", "少年嗜勇黠，跨壓百雄低。", "兩眼皆豚羊，一腹千熊羆。", "使氣睨羣輩，問今當我誰。", "四海有守兵，謂予皆恥之。", "左手將醢戎，右手期鋤夷。", "書足記姓名，劍亦棄不治。", "不願當世是，不羞羣曹嗤。", "曰富貴在我，又何有年時。", "塊視勒山功，芥拾封侯龜。", "一日忽自悟，吾豈虔强兒。", "舊聞有六經，條理兩可師。", "無不至聖人，有學中自隳。", "勿遂謂不及，吾由未嘗追。", "好勇不好道，吾將自誅非。", "浩乎如有失，茫乎其若思。", "望乎如未獲，專乎如有期。", "夜或不記寢，晝或忘其饑。", "不以懦自卻，不以庸自卑。"]'),
('0dbe3ee7-17b9-42b7-8ef7-3f7678dba666','客杭思李常伯滿粹翁及衡父子權因寄此','王令','宋','宋诗','song-poetry','','[]','始予既迂疏，城郭非所樂。',192,'全唐诗/poet.song.39000.json','["始予既迂疏，城郭非所樂。", "聞吳富山水，思往頗計較。", "脱身東南来，見實與聞效。", "吳之山稜稜，吳水清不撓。", "豈無適之徑，以可泳以棹。", "而獨何爲然，反門自閑罩。", "念我西北州，數子吳莫較。", "正心醇無醨，粹行瑩不皰。", "遞言張聖賢，賡口唱弟孝。", "大非友宜當，實可師而傚。", "我愚不敢望，時以管覘豹。", "進如暗赴明，退必醜厭貌。", "自恥以别白，疾匝天地趠。", "坐思朝成痴，夢遇夜不覺。", "山水雖素喜，實不如誨教。", "嗚呼何時歸，作詩以自閙。"]'),
('eb05ce03-9924-4535-8601-6bb77a072233','夜坐','王令','宋','宋诗','song-poetry','','[]','破窗多穿風，冷燭無定焰。',144,'全唐诗/poet.song.39000.json','["破窗多穿風，冷燭無定焰。", "滴瀝隨衣淚，反覆到心念。", "趨生迷夷塗，失城陷深塹。", "病拙未爲療，膏肓不容砭。", "無家可容歸，有竈亦斷掭。", "鳬短鶴脛長，飲啄兩自贍。", "天有不可問，何獨於我欠。", "吾觀序卦辭，否乃適泰漸。", "而余何爲者，獨此不見驗。", "譬如白爲緇，一造遂永染。", "久生人所羨，我獨處之厭。", "安得盖棺去，手足同一斂。"]'),
('29616d87-541c-4f8c-ad35-c90b2a4ab819','寄姊夫焦韞叔兼簡三姊','王令','宋','宋诗','song-poetry','','[]','風舟挽晴江，載客日夜行。',120,'全唐诗/poet.song.39000.json','["風舟挽晴江，載客日夜行。", "身遠心在家，腹腸何由平。", "未知所到期，先計還歸程。", "時尋别時語，涕淚下縱横。", "仰觀風中雲，下視水上萍。", "共在天地間，可無同飄零。", "瀉此罇中酒，美魚其飲羮。", "雖飽不厭饑，强醉終自醒。", "笑言雖在遠，音問猶有形。", "願因東南風，時寄西北聲。"]'),
('6bd06d91-996f-4393-bd9d-0b46dd781dd9','采選示王聖美葛子明','王令','宋','宋诗','song-poetry','','[]','酒盞厭連行，衆客喧已醉。',288,'全唐诗/poet.song.39000.json','["酒盞厭連行，衆客喧已醉。", "忽得簿上籍，共出名外仕。", "孤昂忽雄軒，泯默亦馴致。", "追爭相後先，得失自愚智。", "隨時有能稱，逐釁得呵訾。", "有非人力爲，竟亦天幸值。", "或果以禍覆，亦有終自遂。", "卒無及物效，徒自髙人氣。", "回罇變新局，忽若已異世。", "嗟人久已迷，髙爵樂自嗜。", "誰爲衎衎飽，竟是孜孜利。", "矜驕决雄奢，摧折嘆淹滯。", "昏昏忘所大，擾擾爭其細。", "安知茫昧間，身非天所戲。", "是非未暇辨，歡戚先已至。", "退之昔裁詩，頗以豪横恃。", "暮年志氣得，金玉多自慰。", "買居紀堂榮，顧影樂簪佩。", "喜將閭巷好，持與妻子議。", "彼哉何足道，進退於焉繫。", "安知九列榮，顧是德所累。", "寜論聖人爲，適莫固以義。", "有時曲肱樂，不以易富貴。", "吾曹頗勉修，兹道久自詣。"]'),
('bcce391b-4f20-48af-95c1-59b4de4f8360','古興','王令','宋','宋诗','song-poetry','','[]','颭颭樹頭葉，翻翻水中浮。',48,'全唐诗/poet.song.39000.json','["颭颭樹頭葉，翻翻水中浮。", "暮潮通長河，載入江海流。", "顛倒濕就溺，紛淪来不休。", "行人坐成嘆，風惡久藏舟。"]'),
('6b3fd825-9481-481a-9f67-e23fa4b6a430','中秋望月','王令','宋','宋诗','song-poetry','','[]','月形何完完，秋靜氣彌放。',180,'全唐诗/poet.song.39000.json','["月形何完完，秋靜氣彌放。", "玉輪困瑕纇，投擲去天仗。", "前無衡軛施，憑誰挽能上。", "回旋天地周，馳騁固已壯。", "古今磨不磷，剛耿固可諒。", "予欲假之游，自投上窮亢。", "東折扶桑枝，西塞昧谷曠。", "天機與迴斡，日馭縱休暢。", "苟留揚輝中，無復顛側悵。", "是謀敢吾專，行矣天帝訪。", "傳聞天路艱，蹉蹶就淪喪。", "帝居深九閽，有謁未易傍。", "鬼神喜陰暗，陳列忌忠亮。", "進知自致艱，退使斯謀妄。", "回頭暮堂上，螢爝光相望。"]'),
('0a20e7de-c80b-4583-8338-7de5bdb13b70','病起聞說貪山頗有泉石遠不能遊','王令','宋','宋诗','song-poetry','','[]','一病百志墮，起逢秋物闌。',120,'全唐诗/poet.song.39000.json','["一病百志墮，起逢秋物闌。", "力弱未勝行，厭聞客言山。", "言山多在遠，雖近尚莫攀。", "拏深吾無舟，逐陸誰借鞍。", "不如無所聞，收心就恬安。", "南軒頗扶疏，古木髙四觀。", "不知秋葉疏，但怪朝影斑。", "羸軀便偃側，籍有藁與莞。", "仰攀孤雲高，卧見飛鳥還。", "苟此且自適，何能謀所艱。"]'),
('0f069fdb-5d7c-4d9c-bd2d-448befa03caa','衆鳥','王令','宋','宋诗','song-poetry','','[]','鴉鴉枝上鳴，欲下飛復屢。',96,'全唐诗/poet.song.39000.json','["鴉鴉枝上鳴，欲下飛復屢。", "忽投羣輩先，以我棄肉去。", "羣鳥起爭攫，既失反親慕。", "餓鴟盤且下，欲奪進復懼。", "羣鵲何軒軒，聚噪如罵怒。", "鳩鴿恨不逮，回旋自號呼。", "庭雀審細微，知非已能預。", "跳梁暮堂下，不舍稗粒顧。"]'),
('0cd374cb-4674-427d-8253-04aab11353d7','贈周伯玉下第','王令','宋','宋诗','song-poetry','','[]','京塵漠無聊，客書聞報罷。',240,'全唐诗/poet.song.39000.json','["京塵漠無聊，客書聞報罷。", "拔身衆人後，載水千里下。", "微裝困無餘，歸馬劇連跨。", "邈無失時嘆，抗舉與俗謝。", "但言廢文學，從今益休暇。", "詩書得窮搜，朋友可邀迓。", "如解萬里駿，脱去銜軛駕。", "雖時念親貧，歎息忽自咤。", "已如嬰兒啼，心在聲不嗄。", "悲樂于俗異，使我喜失詫。", "吾聞百年生，暫就天地舍。", "中間有逢遇，窮達何足訝。", "譬之適時運，寒暑變冬夏。", "炎凉忽焉殊，裘葛代相藉。", "於身亦何預，時與外物借。", "嘗聞莊生言，中不怛外化。", "逢鷄就知時，遇彈因求炙。", "况持身售人，五羖豈真價。", "士材嫌易知，女好固擇嫁。", "勉之時我過，酒賤衣可貰。"]'),
('3a91e255-33c4-435f-9aa5-315bd7d7ebf9','送僧自總','王令','宋','宋诗','song-poetry','','[]','吾病不喜語，客来但寒暄。',288,'全唐诗/poet.song.39000.json','["吾病不喜語，客来但寒暄。", "頰舌且不能，况事文字間。", "彼總乃吾舊，不見今三年。", "一日踏我門，告我將南遷。", "問之行所止，其去何由緣。", "言方學從師，惜以日月閑。", "將求佛所宗，就乞世未傳。", "浮舟江海波，蹀屣山岳顛。", "行方極所到，未可歲月還。", "謂余昔同遊，當得送以言。", "噫佛與吾學，兩分不相全。", "今余與子遇，無異東西轅。", "共憇中道間，邂逅相留連。", "我駕志在遠，子驅良亦遄。", "吾終不爾從，爾終不回旋。", "兩各劇所勤，相遠日益懸。", "又出所爲文，要我加量銓。", "熒熒掇其英，曄曄粲滿編。", "惜哉不經師，如珠莫鑽穿。", "雖有可寶資，終以無用捐。", "吾觀古人書，盖亦不但然。", "道德藹於中，口實助使宣。", "豈有拔其根，而望華可搴。", "不知源所来，何用其流沿。"]'),
('1c151cd2-b084-4ac4-a1c7-e94d54943a9e','雜詩  其一','王令','宋','宋诗','song-poetry','','[]','關雎后之淑，棫樸君之明。',48,'全唐诗/poet.song.39000.json','["關雎后之淑，棫樸君之明。", "兔罝尚好德，况乃公與卿。", "所以彼行葦，敦然遂其生。", "誰能弦此歌，爲我發古聲。"]'),
('c96d5a7c-1067-453d-8b9a-3da36d5d99f6','雜詩  其二','王令','宋','宋诗','song-poetry','','[]','召公方伯尊，材亦聖人亞。',48,'全唐诗/poet.song.39000.json','["召公方伯尊，材亦聖人亞。", "農時憚煩民，聽訟小棠下。", "嗟今千里長，已恥問耕稼。", "彈琴髙堂上，欲以無爲化。"]'),
('feb23341-f0e6-4dd3-8dde-a5a891b6bb2f','答友','王令','宋','宋诗','song-poetry','','[]','客嘗疑西伯，何至羑里辱。',48,'全唐诗/poet.song.39000.json','["客嘗疑西伯，何至羑里辱。", "瞽鰥雖父子，尚脱井廩酷。", "昏主雖聖臣，飛禍安可卜。", "致命遂其志，雖窮不爲戮。"]'),
('98a2bdf1-2283-4e98-92e7-42463651a9f3','送崔伯易歸髙郵','王令','宋','宋诗','song-poetry','','[]','山頭喬木長山髙，山下泉深沒榜篙。',64,'全唐诗/poet.song.39000.json','["山頭喬木長山髙，山下泉深沒榜篙。", "春牛畢耕已閑暇，春馬還有人遊遨。", "田中青旗署沽酒，道上雙孫扶白毛。", "子有歸資好来比，我方飄泊可嗟勞。"]'),
('544fe30c-ea8f-4ec6-98f4-e39297603536','觀魚','王令','宋','宋诗','song-poetry','','[]','江渚日夜歸，江痕下汀磯。',48,'全唐诗/poet.song.39000.json','["江渚日夜歸，江痕下汀磯。", "漁者不自勞，推舟就寒漪。", "得魚樂幾多，忽忘身在泥。", "未聞任氏風，豈信絲緡非。"]'),
('97b567da-279f-49c5-8142-0c9cd7d2d873','山中','王令','宋','宋诗','song-poetry','','[]','山頭樹青青，山水日泠泠。',48,'全唐诗/poet.song.39000.json','["山頭樹青青，山水日泠泠。", "攀樹掛冠裳，飲水清肺腸。", "自然古心髙，忽與世態忘。", "有道不足名，無責身始康。"]'),
('b31d35df-b780-4c98-ad68-d0bdbf4809f9','快哉行呈諸友兼簡仲美','王令','宋','宋诗','song-poetry','','[]','脱巾草坐踏地歌，花影落酒生紅波。',128,'全唐诗/poet.song.39000.json','["脱巾草坐踏地歌，花影落酒生紅波。", "拔劍横膝仰面笑，醒眼不識天爲何。", "平時塵土埋英雄，却學弄筆爲雕蟲。", "太阿補履不足用，老驥捕鼠終無功。", "安得雄心大胆子，與之把臂論心事。", "不使生前眼見仇，何用死時尸磔市。", "人生病老多壮時，百歲祗如梭過機。", "安能跼促努筋力，眼穿仰望丹桂枝。"]'),
('8f276a86-cd9d-495b-a6e3-9d52851d07bd','壬辰三月二十一日讀李翰林墓銘云少以任俠爲事因激素志示杜子長','王令','宋','宋诗','song-poetry','','[]','嗟吾爲顓蒙，木朴無所思。',240,'全唐诗/poet.song.39000.json','["嗟吾爲顓蒙，木朴無所思。", "成童始就學，數歲通書詩。", "十五尚意氣，自待固不卑。", "嘗爲富貴易，有如塗上泥。", "苟意欲自進，足至則履之。", "二十忽自笑，學乃謀寒饑。", "倘富貴是致，其亦壟斷爲。", "雖曰爲學難，我易易則宜。", "墻籬號障塞，猶可鑽隙窺。", "豈此聖人道，苦勉不及期。", "反覆私自念，已急猶懼遲。", "思而或有得，行之固不疑。", "跛以見聖賢，不及猶可随。", "道遠志所畢，疾驅亦忘疲。", "逮兹五十年，財若穿銅鎚。", "柄執似可役，持用寧無施。", "何意甚困躓，不及庸常兒。", "多病骨出露，薄食筋力羸。", "鼠飽晝睡穴，鷄飛暮乘塒。", "世既鷄鼠儔，宜吾安窮奇。"]'),
('92cef3db-f3b5-4e29-91c7-1f5017561dad','慎交','王令','宋','宋诗','song-poetry','','[]','昏鏡無好面，惡土無善禾。',72,'全唐诗/poet.song.39000.json','["昏鏡無好面，惡土無善禾。", "鏡不但自昏，損人顔色多。", "地惡根不長，禾死其奈何。", "必欲識已真，抆鏡除埃塵。", "必欲得善禾，易地勤耕耘。", "安得浪與兒，誦口而思身。"]'),
('86f52512-b440-4a6b-8b03-62936745ea3d','西園月夜醉作短歌二闋  其一','王令','宋','宋诗','song-poetry','','[]','我有壹欝氣，從来未經吐。',100,'全唐诗/poet.song.39000.json','["我有壹欝氣，從来未經吐。", "欲作大嘆吁向天，穿天作孔恐天怒。", "琥珀春撥醅，泛艶紅出杯。", "無客尚有月，把對心尚開。", "踏地長歌仰天笑，突兀坐見朱顔頽。", "從他日月趁人老，一醉萬事皆悠哉。", "丈夫身在不憂困，未必天心竟不回。"]'),
('24e70144-7703-4060-8b9b-aac0937bbc14','西園月夜醉作短歌二闋  其二','王令','宋','宋诗','song-poetry','','[]','醉眼不識天，疑是髙帳幙。',52,'全唐诗/poet.song.39000.json','["醉眼不識天，疑是髙帳幙。", "忿月喝不住，起欲取繩縛。", "誰令吾不飲，飲劇始知樂。", "若令東海解醉人，吾亦去取北斗酌。"]'),
('a5604d9d-b9ea-4050-8121-acebca0b3bb3','春夢','王令','宋','宋诗','song-poetry','','[]','春風兒女喜，不合丈夫愛。',342,'全唐诗/poet.song.39000.json','["春風兒女喜，不合丈夫愛。", "日午困魔来，四體倦欲解。", "春禽只随花中飛，幸此無聲聒我睡。", "一夢夢周公，笑與伊尹語。", "問今天下賢者誰，何爲見棄不見取。", "紙傳周官十卷書，安用久留不燒去。", "二夢夢孔父，戟手怒目瞋。", "天下皆曰自孔氏，獵取利禄安榮身。", "髙官志遂不思道，牽以嗜利露己真。", "如何貧賤用我者皆是，富貴用我無一人。", "三夢夢我身，化爲鳴鳯雛。", "飛飛兩足髙，迅迅六翮舒。", "直上髙髙天，天門閉鎻阻我回。", "我留不肯去，以翼摶天天門開。", "天公遣玉女，問我何事来。", "再拜謝天公，賤臣無所知。", "幸至天公前，敢問無所尸。", "臣聞伊尹于湯旦于周，安致天下如山丘。", "愚孫騃子相承繼，卜世以過天位留。", "自從中代来，世世亦有相。", "如何反覆無定時，猶以亂割醫瘡痍。", "天公何忍是不救，恰如旁坐觀奕棋。", "又聞人間人，一一天與命。", "孔饑孟退荀楊賤，天公豈不知其賢與聖。"]'),
('c9396664-6b04-42bb-99ab-a667167f3fe0','寄王正叔','王令','宋','宋诗','song-poetry','','[]','形骸飫饜城市勞，思得遠去與俗逃。',384,'全唐诗/poet.song.39000.json','["形骸飫饜城市勞，思得遠去與俗逃。", "借来馬病行欲倒，著鞭迫急翻奔跳。", "連綿半日走十堠，急雨随濕衣與袍。", "到家覓火烘衣濕，亟書名紙揮墨毫。", "由来道同志易合，顧人謂我此可交。", "形穢向逢珠在側，聯坐愧用狗續貂。", "喜愛常令對面月，招延不許他有庖。", "玄談直抵世不到，大論許致君爲尭。", "喧呼脱落笑絕倒，中樂不肯旁誚嘲。", "久孤得聚氣遂振，張目視人皆麽么。", "促席捉手坐接膝，不肯放去逾分宵。", "平明懶睡未及起，稠叠僕足煩見招。", "披嚢示我文數紙，晚霞爛漫新晴霄。", "魂迷心醉不敢議，畏伏縮若鼠見猫。", "同騎疲馬遠眺望，獨止不進須連鑣。", "江東山水雅豐富，熟視若在圖畫抄。", "嶙峋髙疑地作限，浪渺遠若天不包。", "是時髙秋鱸可鱠，愛欲棄綬同魚舠。", "直道有知私自賀，生平欝結數日消。", "笑顔快意面改色，食飲愜足腸生膋。", "今之腐儒不可洽，欲近俗氣先腥臊。", "尋常語我我不聽，視如秋月鳴蜩蟧。", "數日忽得正叔語，温玉摐擊金相敲。", "胸懷坦儻氣焰大，天馬斷轡鯨横濤。"]'),
('474b4be7-7660-4255-97df-d2e2b43ae500','贈劉成文','王令','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','予生謝早先，晚世相逅邂。',288,'全唐诗/poet.song.39000.json','["予生謝早先，晚世相逅邂。", "禮俗不可徴，百孔千瘡壞。", "平時以是念，食美不知囋。", "誰爲醫國者，已亟不圖瘥。", "引脰望古人，去我遠以太。", "斕斑紙上語，十才一二在。", "思人樂其言，把讀不知懈。", "愛其善調理，未訖已期再。", "探窺古人心，憤懣世俗敗。", "常思得英奇，肝肺相誘勱。", "以是求世人，未免許以漑。", "不特學憂孤，直恐性失介。", "嗚呼聖賢人，既以舍我邁。", "如何有常者，亦不可得拜。", "雖然衆嘲揚，未忍徑伍噲。", "劉生江東儒，心臆寛不隘。", "遇我數日語，收若俯拾芥。", "久從固所望，驟得尤所快。", "立海觀鯨鯤，乘霄飲沆瀣。", "和風吹滯酲，利爪搔痒疥。", "我質遂愧陋，香禾映粃粺。", "和言遂愧疏，長江掩涔派。", "辱索宜有獻，百擇無一愛。", "作詩期笑咍，幸無怒目睚。"]'),
('7a73b71a-8c17-466c-a0ac-02a54ab0c212','唐介','王令','宋','宋诗','song-poetry','','[]','以諫得罪者爲誰，四海多作唐介詩。',352,'全唐诗/poet.song.39000.json','["以諫得罪者爲誰，四海多作唐介詩。", "俗兒口狹文字碎，欲状介事語反卑。", "嗟嗟我亦介之徒，此恨不助掀目眉。", "三更燈死百慮息，四睫不交雙目眵。", "推枕起坐壯介節，以手捫臆爲介思。", "信乎介亦壮男子，直能金鐵其肝脾。", "雷霆之怒萬鈞重，人主之威猶過之。", "一語所犯百死在，要領可斷族可夷。", "堂堂介也人之難，不畏所畏将所持。", "捧書入奏伏文陛，身視赴死如食飴。", "面折庭諍語論險，直舌鐵硬堅不移。", "天子怒叱大臣語，衆笏交抵侔戈揮。", "如何面笑目不瞬，氣不略讋顔怡怡。", "即日議下得遠斥，中使臨遣監妻兒。", "奈何左右口吻毒，只有死請無還辭。", "然今天子甚明聖，雖暫盛怒終復歸。", "嗚呼能對治亂鑑，介也能抆其瑕疵。", "語曰五諫吾從諷，仲尼逮有激而爲。", "後世巽懦禄位徒，緣此粉飾尸素非。", "必也事有不得已，宜乎訖死争不回。", "偉哉介也已不朽，日月爲字天爲碑。", "寄語瑣瑣媒孽子，介縱蹈死吾何悲。"]'),
('bc82872c-c957-4d9b-a100-55e1e8955f6d','還東野詩','王令','宋','宋诗','song-poetry','','[]','吾於古人少所同，惟識韓家十八翁。',194,'全唐诗/poet.song.39000.json','["吾於古人少所同，惟識韓家十八翁。", "其辭浩大無崖岸，有似碧海吞浸秋晴空。", "此老頗自負，把人常常看。", "于時未嘗有誇詫，只說東野口不乾。", "我生最遲暮，不識東野身。", "能得韓老低頭拜，料得亦是無量文章人。", "前日杜子長，借我孟子詩。", "三日三夜讀不倦，坐得脊折臀生胑。", "旁人笑我苦若是，何爲竟此故字紙。", "童子請我願去燒，此詩苦澁讀不喜。", "吾聞旁人笑，嘆之殊不已。", "又畏童子言，藏之不敢示。", "奈何天下俱若然，吾與東野安得不冺焉。"]'),
('722dc51f-584d-4429-9f23-4eb606b39b8e','偶作','王令','宋','宋诗','song-poetry','','[]','女醜忌明鏡，不知自羞人。',60,'全唐诗/poet.song.39000.json','["女醜忌明鏡，不知自羞人。", "士醜忌公言，不知自修身。", "羞人不出前，醜聲日可湮。", "修身無不至，令問日益振。", "鏡與言何尤，見忌不見親。"]'),
('45782d76-a748-4e22-a079-5d9521271119','烏鴟','王令','宋','宋诗','song-poetry','','[]','雄烏無空衝，雌烏無定飛。',84,'全唐诗/poet.song.39000.json','["雄烏無空衝，雌烏無定飛。", "一巢不易成，兩口千柴枝。", "已髙懼風顛，已下憂人窺。", "欲集更自翔，既安復重移。", "烏巢又生烏，復哺猶可期。", "鴟梟亦有巢，母死子後飛。", "嗚呼造物者，於此竟誰尸。"]'),
('a7564430-4b5a-45f0-8d6e-56693d2a20ab','寄王正叔','王令','宋','宋诗','song-poetry','','[]','微生不過人，氣力兩眇麽。',192,'全唐诗/poet.song.39000.json','["微生不過人，氣力兩眇麽。", "力學失自謀，徑古與今左。", "病世相陷賊，樹性期剛果。", "豈不中是時，然亦未嘗過。", "奈何衆好殊，未語咻已夥。", "倀倀獨何之，云云鋭亦挫。", "忠言不售耳，直面屢得唾。", "怒目瞋以環，謗口焰而火。", "出門先自羞，有衣恍疑裸。", "過市不成步，傴僂侔鼈跛。", "周旋不出扉，迷若蟻循磨。", "人惡固爲甚，自厭近亦頗。", "媚世定有術，欲學從誰可。", "必也泥自售，恐由此始禍。", "賢子遠相問，幸有以敎我。", "得報速是宜，翹企不容坐。"]'),
('c3d4877a-af32-4227-8ca7-d9e2129c46b0','不願漁  其一','王令','宋','宋诗','song-poetry','','[]','終焉可伯爲，不願爲漁子。',60,'全唐诗/poet.song.39000.json','["終焉可伯爲，不願爲漁子。", "當時渭陽人，自是直釣耳。", "今非結網身，豈有得魚喜。", "試身風波間，特用豢妻子。", "古今同爲漁，意義不相似。"]'),
('1b3f2251-dd2f-41a2-ad47-69e9759a14ac','不願漁  其二','王令','宋','宋诗','song-poetry','','[]','採薇南山阿，歸耕南山下。',48,'全唐诗/poet.song.39000.json','["採薇南山阿，歸耕南山下。", "食苦心無虞，守約自閑暇。", "出處皆有義，在理無用訝。", "今人舉一隅，何足語學稼。"]'),
('bcc285c4-8bb2-4466-8c05-21f83c0c6621','雜詩效孫莘老  其一','王令','宋','宋诗','song-poetry','','[]','魚蝦無所能，動輒困人得。',48,'全唐诗/poet.song.39000.json','["魚蝦無所能，動輒困人得。", "蛟鯨能則乖，覆舟取人食。", "龜龞能謂殊，刳剥同一劇。", "龍不入網羅，亦不爲人識。"]'),
('f53a950d-1871-4ad4-8cce-f5e3002dd335','雜詩效孫莘老  其二','王令','宋','宋诗','song-poetry','','[]','犬羊飬於人，壮則人食之。',48,'全唐诗/poet.song.39000.json','["犬羊飬於人，壮則人食之。", "猛虎嗜人肉，終昧獵者機。", "豺狼與狗同，爲害豈必威。", "封狐能爲人，還作行子妻。"]'),
('10f67544-77cb-4e47-80a1-9d9a08a24129','呼雞','王令','宋','宋诗','song-poetry','','[]','雞呼雞来前，犬嗾犬至止。',48,'全唐诗/poet.song.39000.json','["雞呼雞来前，犬嗾犬至止。", "夫豈必可召，役以食乃爾。", "今吾曷爲悲，人而雞犬爲。", "自計無自存，西山謝夷齊。"]'),
('b8ac2c30-d58b-44ef-a05d-89baafa2e3e9','江上四首  其一','王令','宋','宋诗','song-poetry','','[]','風吹平江起長瀾，野客坐嘯酒在顔。',40,'全唐诗/poet.song.39000.json','["風吹平江起長瀾，野客坐嘯酒在顔。", "興来就上南山觀。", "固應散髮游更好，何用美質加弊冠。"]'),
('f9e2b0d1-c426-4961-ac8e-ee281c7925a2','江上四首  其二','王令','宋','宋诗','song-poetry','','[]','夢載十舟勝一鈎，曳緡萬里懸十牛。',40,'全唐诗/poet.song.39000.json','["夢載十舟勝一鈎，曳緡萬里懸十牛。", "飽食身至東海投。", "還踞秦山待魚食，所得果可餔九州。"]'),
('e20f30cc-4fb6-4a6d-9a27-b65ed905876b','江上四首  其三','王令','宋','宋诗','song-poetry','','[]','山頭斫竹下作竿，繫鈎沉水坐岸觀。',40,'全唐诗/poet.song.39000.json','["山頭斫竹下作竿，繫鈎沉水坐岸觀。", "餌微水濁魚不干。", "棲遲終日或有得，歸去猶可妻子歡。"]'),
('033ad0b6-7750-4da7-a00d-e77a27c4d03d','江上四首  其四','王令','宋','宋诗','song-poetry','','[]','江頭風平可照水，衣冠面目略相似。',40,'全唐诗/poet.song.39000.json','["江頭風平可照水，衣冠面目略相似。", "與我同笑固相喜。", "何用妄携客子来，不可與語祗相視。"]'),
('bb7f79b8-1464-4b94-9eb1-66099f524d63','飲客','王令','宋','宋诗','song-poetry','','[]','青山何巖巖，江流自渾渾。',96,'全唐诗/poet.song.39000.json','["青山何巖巖，江流自渾渾。", "欲由白石道，先自長松門。", "其間有萬景，軒豁忘乾坤。", "適可得以心，不可爲客論。", "安得山水交，共無世俗言。", "携琴寫古聲，酌泉求清源。", "適時固雖疏，謀道豈不敦。", "誰能歌此詩，侑我飲客樽。"]'),
('68a92723-13e7-4c85-bbf0-ae3084045fa1','江城','王令','宋','宋诗','song-poetry','','[]','江城酒熟賤賣醉，江人提魚不到市。',64,'全唐诗/poet.song.39000.json','["江城酒熟賤賣醉，江人提魚不到市。", "半道得錢相和歌，翁倒子扶相枕睡。", "江南山髙不見天，江北水遠無復地。", "馬驚堕崖舟覆波，可惜行人死聲利。"]'),
('d64bbc78-6022-494b-9b9f-0d5a1cc6429d','效退之青青水中蒲  其一','王令','宋','宋诗','song-poetry','','[]','雙雙水中鳬，足短翼有餘。',24,'全唐诗/poet.song.39000.json','["雙雙水中鳬，足短翼有餘。", "飛髙既能遠，行陸安事俱。"]'),
('0b1d78dd-efeb-47bd-b92f-387c0c76768b','效退之青青水中蒲  其二','王令','宋','宋诗','song-poetry','','[]','雙雙水中鳬，来疾去閑暇。',24,'全唐诗/poet.song.39000.json','["雙雙水中鳬，来疾去閑暇。", "江湖風晚波，泛泛自髙下。"]'),
('1d2ce0a4-ac6d-4861-a2a3-163a04179f36','效退之青青水中蒲  其三','王令','宋','宋诗','song-poetry','','[]','雙雙水中鳬，已往又回顧。',24,'全唐诗/poet.song.39000.json','["雙雙水中鳬，已往又回顧。", "弋者窺未知，舟来避還去。"]'),
('c2d8265d-3a29-4d9e-8bc8-475af8bee491','效退之青青水中蒲  其四','王令','宋','宋诗','song-poetry','','[]','雙雙水中鳬，常在水中居。',24,'全唐诗/poet.song.39000.json','["雙雙水中鳬，常在水中居。", "還有籠中鶩，騰軒仰不如。"]'),
('208f9f99-d49a-44db-a602-33836059f7dd','效退之青青水中蒲  其五','王令','宋','宋诗','song-poetry','','[]','雙雙水中鳬，食飽不出水。',24,'全唐诗/poet.song.39000.json','["雙雙水中鳬，食飽不出水。", "靈鳯来何時，鴻鵠志萬里。"]'),
('c9766950-d28e-4c1e-b597-1b604e442352','霜風','王令','宋','宋诗','song-poetry','','[]','霜風裂寒窗，餘响到我床。',48,'全唐诗/poet.song.39000.json','["霜風裂寒窗，餘响到我床。", "聞鼠有嚙聲，不省何物傷。", "兒呼須我起，顧無燈燭光。", "伏枕置所念，去夢通扶桑。"]'),
('4b8586b7-7428-4b85-bf8f-60e2f2b35dc1','孟子','王令','宋','宋诗','song-poetry','','[]','孟子不肯比伊尹，仲尼方可期文王。',64,'全唐诗/poet.song.39000.json','["孟子不肯比伊尹，仲尼方可期文王。", "聖賢自得固厚重，庸俗始以已較量。", "微生喜以佞面詆，臧氏惡非禮所當。", "惜哉二子不自重，以人可否何不詳。"]'),
('60a74c02-43c0-4b15-9210-ff42dee236ce','過揚子江','王令','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江来何從，遠自西極詹。',288,'全唐诗/poet.song.39000.json','["長江来何從，遠自西極詹。", "中破蜀山流，始與巴水兼。", "川原日混合，激射勢益嚴。", "奔渾萬里流，不自頃刻淹。", "駭如瀉天来，急若赴海添。", "潮汐日往復，旦暮難安恬。", "攻冲氣何雄，吞囓勢未厭。", "因思禹功成，自匪尭謀僉。", "久已口効噞，豈復頭今黔。", "余来方冬時，怒風何沾沾。", "掀轟駕髙浪，山阜相聯粘。", "有如合萬鼎，就沸烹羣憸。", "天陽盛焚爍，鬼力争炰燖。", "聲勢欲状說，有口嗟如箝。", "須臾稍收斂，晴風蕩氛揫。", "涵澄動自息，拂拭痕無纖。", "宛然帝女鏡，仰照青天奩。", "遐觀清神心，俯視分眉髯。", "有如尭舜時，惠澤四海霑。", "登賢默與慮，流惡聲無霑。", "洗除巖穴空，蕩滌昏奸殱。", "恩波浩滂沛，浸潤咸滋漸。", "羣山西南来，垂天下帷幨。", "霜風月凌厲，紫翠生觚廉。"]'),
('d907ea7b-a103-4877-ac36-c4fb27ba62e9','晚泊','王令','宋','宋诗','song-poetry','','[]','月形如張弓，下影射秋水。',72,'全唐诗/poet.song.39000.json','["月形如張弓，下影射秋水。", "寒江風静時，逮目失洲沚。", "漁歌去時唱，歸和讙未已。", "豈無人間樂，自快適爲喜。", "客子有倦懷，歸心動秋葦。", "更假滄浪清，聊用洗塵耳。"]'),
('a1296fba-f0cf-4a37-9a33-7dfca9966084','姚堅老見約偶成','王令','宋','宋诗','song-poetry','','[]','初正布新和，餘臘争近候。',180,'全唐诗/poet.song.39000.json','["初正布新和，餘臘争近候。", "升騰陽力微，恇怯老陰鬬。", "江雲蕩空碧，疏雨沐清晝。", "林梢釋冬枯，土蘖壮春簇。", "萎蕤風日舒，刻畫山野秀。", "關關先春鳥，格磔弄晴咮。", "無人與調和，終日自嘲詬。", "唯君卜近適，過我許来就。", "遷延日屢蹉，嘆惜月復彀。", "人生誠多故，世事那可究。", "惟當自推置，障絕俗慮寇。", "休閑倘能偷，疏懶當自宥。", "徒行苟憚勞，借馬欲誰廏。", "清沽如定携，佳客可先購。", "勉之無使遲，梅蕚已堪齅。"]'),
('20323a73-9f8e-4f92-89aa-b198b3c40346','初聞思歸鳥憶昨寄崔伯易朱元弼','王令','宋','宋诗','song-poetry','','[]','去年春日花盛開，嘗有鳥啼歸去来。',384,'全唐诗/poet.song.39000.json','["去年春日花盛開，嘗有鳥啼歸去来。", "余詩告爾東海志，子笑属我南山杯。", "将睎遐踪蹈髙軼，就拔去跡離俗埋。", "同時游者最誰上，朱子峭擢凌春材。", "門關午景卧正懶，過我呼號如春雷。", "鄰驚偷窺婦女怪，婢駭奔走兒童咍。", "門開納坐聽論列，笑口侈哆傾胸懷。", "寒葅半菽要同飰，韲醤叫乞喧鄰隈。", "僧從南浮雲異角，尉解西去遺亭臺。", "心争誇漫詰蜒蜿，日樂虛豁留崔嵬。", "柳梢黪黪坌晴絮，杏蕚爍爍翻遺埃。", "春湖平停照空碧，淮帆曉上攙天桅。", "西歸頗阨窮餓久，南泛未免丐乞哀。", "朅来随人事卑折，忽自顧影慚低摧。", "平時客坐不敢語，苟以唯諾償嫌猜。", "胸中糾結浩千萬，到口不吐如横枚。", "比来頗自撥俗礙，日傍竹樹良徘徊。", "昏昏萬事置不省，知已疏懶心難裁。", "一聞春風動啼鳥，猛若重睡忽喚回。", "咨嗟歲月急若矢，嘆息無地安蒿莱。", "比于見人日加懶，行恐合俗老益乖。", "不知飄浮寄兹世，竟亦何計收形骸。", "春林沾沾風日好，飛止自便宜爾諧。", "何爲猶尚歸不得，世間萬事真悠哉。"]'),
('ac0147eb-a137-4588-ada1-53ff0737006c','望招隱山花回遊江山思崔伯易因寄朱元弼','王令','宋','宋诗','song-poetry','','[]','春山曬日開百花，紅紫亂眼生交加。',64,'全唐诗/poet.song.39000.json','["春山曬日開百花，紅紫亂眼生交加。", "青天晴髙褰翠幄，繡被堆叠帝所家。", "平江千里鋪一席，扁舟脫若棄履舄。", "安得一醉眠千年，世間萬事都棄捐。"]'),
('1f24ec72-54ef-41f1-a4bc-9682394e0eeb','同顧保之遊靈隱','王令','宋','宋诗','song-poetry','','[]','閉門不知春色到，出城始見江梅開。',64,'全唐诗/poet.song.39000.json','["閉門不知春色到，出城始見江梅開。", "行探幽泉至髙絕，共坐巨石聊徘徊。", "時逢天風吹客過，還有野鳥驚人来。", "林間躬惜所未歷，歸馬空載斜陽回。"]'),
('b95f61c1-172f-4037-bf77-bf10526f6391','揚子江阻風','王令','宋','宋诗','song-poetry','','[]','揚子江風十月初，西駕巨浪渺無隅。',64,'全唐诗/poet.song.39000.json','["揚子江風十月初，西駕巨浪渺無隅。", "常憂傾摇地爲動，意欲起塞天無虛。", "大舟不行就繫岸，小舟分去争得魚。", "舟中壮士起坐笑，有酒更爲斜陽酤。"]'),
('257ff273-4ec1-4a18-9fc3-d4f1d61c4d40','山中','王令','宋','宋诗','song-poetry','','[]','山中亦有出山路，山人自不與世通。',64,'全唐诗/poet.song.39000.json','["山中亦有出山路，山人自不與世通。", "拂衣起行飲流水，枕書就卧聽松風。", "地寛江河競摇蕩，天濶日月争西東。", "乾坤自爲四時役，萬事不到幽人胸。"]'),
('b34e67e6-4a45-47ff-9cf4-b3a4d943f5af','出門','王令','宋','宋诗','song-poetry','','[]','出門萬事非，聊復閉關坐。',48,'全唐诗/poet.song.39000.json','["出門萬事非，聊復閉關坐。", "親識久相遠，與世絕弔賀。", "適時既非謀，接俗益加惰。", "外物等不来，何必問客過。"]'),
('10d8d5df-48da-41de-aa9e-9bc0e55f8467','南徐懷古','王令','宋','宋诗','song-poetry','','[]','昔人戰血化爲土，今人常懷昔人苦。',64,'全唐诗/poet.song.39000.json','["昔人戰血化爲土，今人常懷昔人苦。", "大江冥冥截海流，鐵甕城髙排萬虎。", "乾坤未定龍蛇争，日月須歸仁義主。", "江山本不爲英雄，英雄自負江山死。"]'),
('8f04cf44-e7c4-4a06-b1ac-f4e7217e7c35','東城','王令','宋','宋诗','song-poetry','','[]','昔予出東城，初見壟上耕。',48,'全唐诗/poet.song.39000.json','["昔予出東城，初見壟上耕。", "忽忽自北至，歲月令人驚。", "雖云一草死，萬物尚華榮。", "誰能當此時，歎息微陰生。"]'),
('01416935-b2ec-4540-a72a-d0d5dc058fe2','餓虎不食子','王令','宋','宋诗','song-poetry','','[]','餓虎不食子，饑鷹不雌求。',120,'全唐诗/poet.song.39000.json','["餓虎不食子，饑鷹不雌求。", "虎餓不擇肉，盛怒遇子收。", "鷹饑爪喙獰，尚與雌同韝。", "人豈二者然，恩義宜綢繆。", "親戚不宜怒，割恩以爲仇。", "此割非常割，此傷無血流。", "肉割愈有日，恩割傷不收。", "一割大義死，再割面相仇。", "親戚尚皆然，况又他人儔。", "是己與世絕，于世何足尤。"]'),
('cb95716c-7b38-492d-9709-bef1d241dc44','松江曲','王令','宋','宋诗','song-poetry','','[]','松江深處八九尺，去眼百里長風波。',48,'全唐诗/poet.song.39000.json','["松江深處八九尺，去眼百里長風波。", "吾山井泉廢不汲，一泓不知深幾何。", "君家自無千尺綆，那知江深不如井。"]'),
('0d5f3faa-0fd8-49b8-b717-122697d6d5eb','贈王介甫','王令','宋','宋诗','song-poetry','','[]','當世胸懷萬古淳，平生才術老經綸。',64,'全唐诗/poet.song.39000.json','["當世胸懷萬古淳，平生才術老經綸。", "况逢尭舜登賢日，不復伊周望古人。", "得志定知移弊俗，聞風猶足警斯民。", "九門無謁天旒邃，何惜長令仕爲貧。"]'),
('afb5afe0-0550-4645-8250-c1779a0a2954','贈王平甫','王令','宋','宋诗','song-poetry','','[]','當世所交識者稀，十年聞子幸見之。',64,'全唐诗/poet.song.39000.json','["當世所交識者稀，十年聞子幸見之。", "平生所負自信重，他日可期人莫知。", "誰肯草茅窮釣築，世方簡策誦臯夔。", "丈夫出處誠何較，却痛蒼生爲泪垂。"]'),
('cc52b4f6-c53d-44fd-b147-a6cf1c35a899','贈孫莘老','王令','宋','宋诗','song-poetry','','[]','至愚不學常如足，盛德之充久自彰。',64,'全唐诗/poet.song.39000.json','["至愚不學常如足，盛德之充久自彰。", "管小始疑天可盡，綆窮終信海非量。", "始慚自待從来薄，不及時中適取狂。", "安得此生天與幸，沒身得不去門墻。"]'),
('74de551b-ca6b-4348-9677-2127b476dcb3','思京口戯周器之','王令','宋','宋诗','song-poetry','','[]','江南别日醉方醺，貪愛青天带水痕。',64,'全唐诗/poet.song.39000.json','["江南别日醉方醺，貪愛青天带水痕。", "忘却碧山歸路直，誤投浮世俗塵昏。", "終期散髮江邊釣，當有漁舟日繫門。", "但恨故人猶喜仕，他時胸腹未堪論。"]'),
('c6e32ad3-e3fc-4635-b29b-24e65fbb27ef','舟中作','王令','宋','宋诗','song-poetry','','[]','杳杳波濤去莫窮，要須流合海天東。',32,'全唐诗/poet.song.39000.json','["杳杳波濤去莫窮，要須流合海天東。", "長帆百尺嗟無用，醉絕重湖笑逆風。"]'),
('d1a30397-dd66-408c-9c81-f4062e34260d','寄束伯仁','王令','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','身逐南舟去不回，匡廬留滯得徘徊。',64,'全唐诗/poet.song.39000.json','["身逐南舟去不回，匡廬留滯得徘徊。", "峰頭夜宿平看斗，巖下朝陰俯聽雷。", "西顧波濤浮日月，東歸天地入塵埃。", "何時得遂幽棲志，常把韋編静處開。"]'),
('d1186593-2eed-401f-919f-53464bf6d774','題假山','王令','宋','宋诗','song-poetry','','[]','擾擾人心巧謂何，我腸愚只愛無它。',32,'全唐诗/poet.song.39000.json','["擾擾人心巧謂何，我腸愚只愛無它。", "目前好且留平地，浪愛山髙險自多。"]'),
('60450335-cdb3-4d0f-b057-1dfe0cf2e765','夜歸','王令','宋','宋诗','song-poetry','','[]','冲冲行路自多岐，已踏歸途尚慮非。',32,'全唐诗/poet.song.39000.json','["冲冲行路自多岐，已踏歸途尚慮非。", "夜犬只知人是盗，不知人亦夜来歸。"]'),
('1cf19434-9894-48ba-9dcd-744ae479ae78','口占示姊','王令','宋','宋诗','song-poetry','','[]','盎竭嚢空且笑歌，更從吾命聽如何。',32,'全唐诗/poet.song.39000.json','["盎竭嚢空且笑歌，更從吾命聽如何。", "不須直有牛羊樂，只以無求富自多。"]'),
('8ceba323-84d2-457d-bba2-23da19dc142c','孫莘老将赴太平二首  其一','王令','宋','宋诗','song-poetry','','[]','先生素志已形詩，弟子何妨鼓瑟希。',64,'全唐诗/poet.song.39000.json','["先生素志已形詩，弟子何妨鼓瑟希。", "時若伊周方有任，命如孔孟可無歸。", "要終四海乘槎去，髙謝西山食粟非。", "此道難言身未果，且當從世共依違。"]'),
('74d78e8c-2575-4d5f-ade1-3e775c915466','孫莘老将赴太平二首  其二','王令','宋','宋诗','song-poetry','','[]','紛紛世俗競朱金，仕道人人說直尋。',64,'全唐诗/poet.song.39000.json','["紛紛世俗競朱金，仕道人人說直尋。", "但以一官求飬志，豈於千古有遺心。", "嗜偏羊棗情何甚，戯及牛刀意自深。", "何日山林遂歸計，南風進講五弦琹。"]'),
('fd17bbe7-7307-4ec7-95da-786216c50354','露筋貞女廟','王令','宋','宋诗','song-poetry','','[]','待夫以死如知命，信己輕生可謂貞。',32,'全唐诗/poet.song.39000.json','["待夫以死如知命，信己輕生可謂貞。", "指爾爲愚今尚衆，莫言吾志不難行。"]'),
('8b2cca42-bd78-462e-9ff5-f36b9c90db88','渰渰','王令','宋','宋诗','song-poetry','','[]','渰渰輕雲弄落暉，壞簷巢滿燕来歸。',32,'全唐诗/poet.song.39000.json','["渰渰輕雲弄落暉，壞簷巢滿燕来歸。", "小園桃李東風後，却看楊花自在飛。"]'),
('72a14572-fc9c-401c-9c59-6ab5136e86d4','寄聱隅先生黄晞','王令','宋','宋诗','song-poetry','','[]','王朝簪笏擁天扉，肯以經綸假布衣。',64,'全唐诗/poet.song.39000.json','["王朝簪笏擁天扉，肯以經綸假布衣。", "老信蒼生終有命，窮憂當世益思歸。", "一身誰作千年望，兩眼空看萬事非。", "聞說韋編日開閲，可應三復嘆知幾。"]'),
('fcacde3a-f73f-4453-90fd-51c0ce902540','春愁','王令','宋','宋诗','song-poetry','','[]','只聞来客說春遊，不逐花前笑自留。',32,'全唐诗/poet.song.39000.json','["只聞来客說春遊，不逐花前笑自留。", "浪說春期計春盡，留春無術只春愁。"]'),
('e7b03e02-bbd1-44c4-b2ed-eb0e375f690b','少年答春愁','王令','宋','宋诗','song-poetry','','[]','花枝裊裊笑當觴，且作春風幾日狂。',32,'全唐诗/poet.song.39000.json','["花枝裊裊笑當觴，且作春風幾日狂。", "縱使春歸猶有酒，酒酣春去亦何傷。"]'),
('b00cb2b8-ca29-44de-b400-14c1f713b700','和朱元弼春遊','王令','宋','宋诗','song-poetry','','[]','閉門無著只疏慵，謾出留連與衆同。',64,'全唐诗/poet.song.39000.json','["閉門無著只疏慵，謾出留連與衆同。", "柳却有情愁落日，花惟能笑謝東風。", "恨無日到三春外，盡看人狂六極中。", "泛泛相逢且相笑，久将吾道付窮通。"]'),
('3d04a5d5-2a69-4937-8ac9-7c198d698dae','春日','王令','宋','宋诗','song-poetry','','[]','提壺聒聒惟呼酒，杜宇喧喧只說歸。',64,'全唐诗/poet.song.39000.json','["提壺聒聒惟呼酒，杜宇喧喧只說歸。", "坐怪鳥聲皆有取，静于人事益知非。", "已嫌世濁胡爲混，能待河清固已稀。", "爲語夷齊既甘餓，可能分我首陽薇。"]'),
('71d41e28-e2ed-41b8-a0fb-61302efe6291','對花','王令','宋','宋诗','song-poetry','','[]','憂愁卒卒人無樂，花草紛紛物又春。',32,'全唐诗/poet.song.39000.json','["憂愁卒卒人無樂，花草紛紛物又春。", "安得無憂與無慮，對花還作笑歌人。"]'),
('4bf516be-6c84-40e6-8bb2-22e0824793a7','靡靡','王令','宋','宋诗','song-poetry','','[]','源源世俗尚依違，靡靡風流日正微。',64,'全唐诗/poet.song.39000.json','["源源世俗尚依違，靡靡風流日正微。", "吾病未能終是是，人言何似喜非非。", "况當天下難能地，欲撥憸人未發機。", "要格君心是知術，不然應合買山歸。"]'),
('f899229f-30ba-46a2-abb1-58c56639ba87','觀水','王令','宋','宋诗','song-poetry','','[]','細如蝦蚓足留連，大可蛟鯨出自然。',64,'全唐诗/poet.song.39000.json','["細如蝦蚓足留連，大可蛟鯨出自然。", "當使川流應到海，只今坎止亦成淵。", "民憂不見尭咨日，地礙何由禹鑿穿。", "可惜卧龍無意思，不随雲去雨春田。"]'),
('f390537b-bddc-473a-baa6-ccbd8697ed85','讀孟子','王令','宋','宋诗','song-poetry','','[]','去梁無故又辭齊，弟子紛紛益不知。',64,'全唐诗/poet.song.39000.json','["去梁無故又辭齊，弟子紛紛益不知。", "天下未平雖我事，己身已枉更何爲。", "後来誰是聞風者，當世何嘗不召師。", "士要自髙無顧世，遺編今亦有人疑。"]'),
('256fb7b8-5cfe-430a-81ca-008c5a8a37c0','鸛','王令','宋','宋诗','song-poetry','','[]','毛羽人将鶴品流，斜陽髙處自遲留。',32,'全唐诗/poet.song.39000.json','["毛羽人将鶴品流，斜陽髙處自遲留。", "人言殺爾三年旱，應是巢成更不憂。"]'),
('5e9773c9-d375-45cb-b688-119f9725815f','寄朱元弼','王令','宋','宋诗','song-poetry','','[]','春城春雨綠春潭，冉冉歸舟上去帆。',64,'全唐诗/poet.song.39000.json','["春城春雨綠春潭，冉冉歸舟上去帆。", "愛子有詩留我别，悔予無酒伴君銜。", "東風随卷行人袖，落日猶明去客衫。", "好有新詩寄幽寂，我心無泊似摇窗。"]'),
('de5941ac-0897-49ef-8952-b03ff6bf5d6c','春遊','王令','宋','宋诗','song-poetry','','["\u6e38\u73a9", "\u6292\u60c5", "\u6625\u5929"]','春城兒女縱春遊，醉倚層臺笑上樓。',32,'全唐诗/poet.song.39000.json','["春城兒女縱春遊，醉倚層臺笑上樓。", "滿眼落花多少意，若何無箇解春愁。"]'),
('77356632-71cf-4423-8dcc-e02933591b76','龍池二絕  其一','王令','宋','宋诗','song-poetry','','[]','滿目塵埃白日陰，皇天無命且深沉。',32,'全唐诗/poet.song.39000.json','["滿目塵埃白日陰，皇天無命且深沉。", "終當力卷滄溟水，来作人間十日霖。"]'),
('c8795b6f-5d8e-44eb-860f-c3f238685d88','龍池二絕  其二','王令','宋','宋诗','song-poetry','','[]','盡道神龍此有靈，一池澄静暮痕清。',32,'全唐诗/poet.song.39000.json','["盡道神龍此有靈，一池澄静暮痕清。", "如何蟠屈無飛志，却放鳴蛙有怒聲。"]'),
('77dce90e-de1d-4517-aed8-0243eb24705d','月蝕','王令','宋','宋诗','song-poetry','','[]','盧仝不作昌黎死，天目雖盲未見嗟。',32,'全唐诗/poet.song.39000.json','["盧仝不作昌黎死，天目雖盲未見嗟。", "坐嘆清光無惜處，一将吞吐聽蝦蟆。"]'),
('65016774-4240-4fe1-a8f6-a835ab07ff3b','偶成','王令','宋','宋诗','song-poetry','','[]','種花紅不實，俗客醉仍喧。',24,'全唐诗/poet.song.39000.json','["種花紅不實，俗客醉仍喧。", "拔去樹嘉穀，日無人過門。"]'),
('398bdccc-f46a-49c7-b62e-aefd70f886ce','偶感','王令','宋','宋诗','song-poetry','','[]','壮志老来退，窮愁無易攻。',48,'全唐诗/poet.song.39000.json','["壮志老来退，窮愁無易攻。", "風雲詩氣焰，天地醉心胸。", "午枕著不覺，晝門關更慵。", "由来自疏拙，底處不相容。"]'),
('2144ff0d-ede2-4adf-8f57-665c1ab9f248','寄滿子權','王令','宋','宋诗','song-poetry','','[]','西北風吹數紙詩，神門樞鑰鬼關機。',64,'全唐诗/poet.song.39000.json','["西北風吹數紙詩，神門樞鑰鬼關機。", "九原黄土英靈活，萬古青天霹靂飛。", "我是懦夫無壮志，近思依日竊餘輝。", "髙樓暮插暗空肋，東望君心着翅歸。"]'),
('e8a9141b-ae45-43f6-b60c-5aeb49f78cd1','寄洪與權','王令','宋','宋诗','song-poetry','','[]','劍氣寒髙倚暮空，男兒日月鏁心胸。',64,'全唐诗/poet.song.39000.json','["劍氣寒髙倚暮空，男兒日月鏁心胸。", "莫藏牙爪同痴虎，好召風雷起卧龍。", "舊說王侯無世種，古嘗富貴及耕傭。", "須将大道爲奇遇，莫踏人間齷齪踪。"]'),
('39abbbd7-5d76-49f0-9fba-a7d08b4be986','上聱隅先生','王令','宋','宋诗','song-poetry','','[]','夫子儒門傑，心誠行亦醇。',264,'全唐诗/poet.song.39000.json','["夫子儒門傑，心誠行亦醇。", "玉金精粹美，椒桂性芬辛。", "一入随邦計，咸期利國賓。", "生民待儒效，天意属人倫。", "蜀犬争驚日，鄒人不識麟。", "窮途千古泪，白髮四方塵。", "弊世誰思救，仁賢自合振。", "愛狙徒食費，好鶴浪軒馴。", "不結臨川網，偷安厝火薪。", "忠言驚苦逆，恬議貴因循。", "漆軌書三上，清時死九濱。", "不思防蟻壌，徒欲衞龍鱗。", "當道豺狼愎，升堂犬馬嚚。", "旱餘雲不雨，命塞器藏身。", "獨抱遺經老，来爲後進陳。", "手提三聖出，口壓九師堙。", "衆耳雷霆震，羣觀日月新。", "韋編重斷絕，文席互酬詢。", "魯變全歸道，陳糧絕更貧。", "賤生無自幸，俗繫弗容親。", "盆覆徒經日，龜埋不伏人。", "短詩徒自訟，已伏下斯民。"]'),
('affce742-1d1a-4319-bb99-983bc8f8703c','春晚雨後','王令','宋','宋诗','song-poetry','','[]','東風柔弱事春權，劇雨無端轉愴然。',64,'全唐诗/poet.song.39000.json','["東風柔弱事春權，劇雨無端轉愴然。", "不惜好花都委地，却令遠草直平天。", "龍蛇久蟄應思奮，蛙蟈乘時巳自先。", "綠柳由来却堪笑，葉眉愁劇遂長眠。"]'),
('f169f465-4974-4960-ab1a-6d0bf1c3857d','良農','王令','宋','宋诗','song-poetry','','[]','良農手足胝，老賈不親犂。',48,'全唐诗/poet.song.39000.json','["良農手足胝，老賈不親犂。", "歉歲糠糟絕，髙門犬馬肥。", "天心不宜咎，人理自誰尸。", "安得悠悠者，来同予一悲。"]'),
('b1cb5410-1ba2-46c1-b36e-abcf5330c5f1','瓊花','王令','宋','宋诗','song-poetry','','[]','無雙亭下枝，密密復稀稀。',48,'全唐诗/poet.song.39000.json','["無雙亭下枝，密密復稀稀。", "蚌碎珠駢出，鬚牽蝶合圍。", "會須珍作寶，常恐散成飛。", "况是東風後，游人莫易歸。"]'),
('1b697429-cc8b-4c31-8d1c-a9c933f9d3ed','夜深吟','王令','宋','宋诗','song-poetry','','[]','叩几悲歌涕滿襟，聖賢千古我如今。',32,'全唐诗/poet.song.39000.json','["叩几悲歌涕滿襟，聖賢千古我如今。", "凍琴弦斷燈青暈，誰會男兒半夜心。"]'),
('cf7e0075-e50a-4dc3-8c27-cd127908a6cc','和人春雪','王令','宋','宋诗','song-poetry','','[]','莫嘆年来雪句遲，雪遲詩句更依微。',64,'全唐诗/poet.song.39000.json','["莫嘆年来雪句遲，雪遲詩句更依微。", "風来海國鹽波涸，春入仙田玉氣肥。", "雛鶴暖嬌揺羽脱，老龍枯痒退鱗飛。", "天工人代如端的，安得吾能及九畿。"]'),
('004ea0ba-06ca-4384-b626-b144732f7996','紙鳶','王令','宋','宋诗','song-poetry','','[]','誰作輕鳶壮遠觀，似嫌飛鳥未多端。',64,'全唐诗/poet.song.39000.json','["誰作輕鳶壮遠觀，似嫌飛鳥未多端。", "才乘一線憑風去，便有愚兒仰面看。", "未必碧霄因可到，偶能終日遂爲安。", "扶揺不起滄溟遠，笑殺鵬搏似爾難。"]'),
('0930e8ac-baec-4f23-a6af-8ee21d943516','贈别晏樊父太祝','王令','宋','宋诗','song-poetry','','[]','縮伏蒿莱聽命沉，舊房孤劍鐵塵侵。',64,'全唐诗/poet.song.39000.json','["縮伏蒿莱聽命沉，舊房孤劍鐵塵侵。", "方思力舉滄溟水，潑殺生平氣焰心。", "不謂偶君誇意氣，無端起我舊胸襟。", "男兒合是公侯器，未忍風前墮泪吟。"]'),
('fb786a9a-bc8f-4a6e-bf9c-fe49b2477abb','和洪與權','王令','宋','宋诗','song-poetry','','[]','溝中老弱轉流尸，夫不容妻母棄兒。',64,'全唐诗/poet.song.39000.json','["溝中老弱轉流尸，夫不容妻母棄兒。", "常得民愚猶是幸，不然死等更何爲。", "布衣空有蒿莱泪，肉食方多妾馬思。", "君也天心省民數，未知死所又何辭。"]'),
('e0f066bd-0c67-4354-9032-d78925ae035a','題天長縣蘇太尉廟','王令','宋','宋诗','song-poetry','','[]','唐室無臣覆手移，坐看悍媪制庸兒。',32,'全唐诗/poet.song.39000.json','["唐室無臣覆手移，坐看悍媪制庸兒。", "思量可惜當年死，却是西来問鼎師。"]'),
('1a33487a-0047-4731-8ded-0edda2615357','春雪有感呈王正叔束徽之','王令','宋','宋诗','song-poetry','','[]','彼雪晚何滛，乘時横此臨。',132,'全唐诗/poet.song.39000.json','["彼雪晚何滛，乘時横此臨。", "必将滋及物，自合大爲霖。", "也道春来好，何餘臈後陰。", "冬冥誠不道，蒼帝亦何心。", "俗口誇同粉，愚觀謂似琳。", "獨于平處薄，不似險中深。", "逆吹争爲力，凌寒苦助侵。", "落疑天未悟，壓恐地難任。", "蟄户開重墐，冰魚上復沉。", "欲開花謾妬，垂死草奚禁。", "短韻徒堪嘆，憑君附入琴。"]'),
('7cfbf3a6-0419-4eb9-b98e-dbb5724b9ced','古鑑','王令','宋','宋诗','song-poetry','','[]','一片靈光合有神，不知鎔鑄更何人。',64,'全唐诗/poet.song.39000.json','["一片靈光合有神，不知鎔鑄更何人。", "春耕破塜衣冠盡，鬼手摩天日月新。", "鑒面祗知西子姣，照心難見比干真。", "主人深有收藏意，當待清明不受塵。"]'),
('053bf55b-3940-40ff-bea6-547e9403686a','代人送常州致仕張待制','王令','宋','宋诗','song-poetry','','[]','心貪進退適全宜，上印飛書劇去翬。',64,'全唐诗/poet.song.39000.json','["心貪進退適全宜，上印飛書劇去翬。", "荐口不加張柬老，明朝竟放孔戣歸。", "黄堂合有遺思在，青史還留後世稀。", "此去江湖見鷗鳥，爲言今合信無機。"]'),
('e25ca5dd-ae9f-41d7-93f0-ec77f4bbbf85','代人送常州張卿掛冠','王令','宋','宋诗','song-poetry','','[]','清優四皓官，瀟洒二疏顔。',48,'全唐诗/poet.song.39000.json','["清優四皓官，瀟洒二疏顔。", "直道空華髮，明時獨買山。", "如聞元老議，尚恐輭輪還。", "誰是塵埃者，清風合自攀。"]'),
('1de6e7eb-8d07-4b88-a8ce-5324e03808ea','謝束丈','王令','宋','宋诗','song-poetry','','[]','卓鄭簪裾密作林，相如貧病強来臨。',64,'全唐诗/poet.song.39000.json','["卓鄭簪裾密作林，相如貧病強来臨。", "藜羮才飽無他志，肉食俄充有愧心。", "死馬偶能逢市骨，濫竽常恐負知音。", "古来一飯皆論報，何日王孫遂有金。"]'),
('6ee51940-2edd-4b48-ab9b-21130a38f5b2','和束熙之雨後','王令','宋','宋诗','song-poetry','','[]','獵獵風吹雨氣腥，誰翻碧海踏天傾。',64,'全唐诗/poet.song.39000.json','["獵獵風吹雨氣腥，誰翻碧海踏天傾。", "如何農畯三時望，只得官蛙一處鳴。", "何處斷虹殘冷落，有時斜照蹔分明。", "當車收轍雲藏迹，依舊晴空萬里平。"]'),
('a54779bd-94f3-4542-8495-9f142391368d','寄衡父滿翁','王令','宋','宋诗','song-poetry','','[]','隻卓来篇不許雙，社壇髙處立旌幢。',64,'全唐诗/poet.song.39000.json','["隻卓来篇不許雙，社壇髙處立旌幢。", "自知孤敵難爲勝，欲豎長幡一面降。", "須學依墻勤哭楚，莫同伏弩助收龐。", "何時玉手歸重搦，笑倒秋醪瀲灔缸。"]'),
('a0d19ad9-3542-4673-bd3b-5a9a53027bf1','幽居感懷寄滿子權','王令','宋','宋诗','song-poetry','','[]','卜得幽居四絕鄰，尋常庭巷斷蹄輪。',64,'全唐诗/poet.song.39000.json','["卜得幽居四絕鄰，尋常庭巷斷蹄輪。", "門前犬豕卧横道，城上牛羊下視人。", "滿眼夕陽閑草樹，回頭歸路正埃塵。", "思君未有東来計，何日雙眉對面伸。"]'),
('a006c563-7470-4e3c-8ba3-20ca4c43984c','偶成','王令','宋','宋诗','song-poetry','','[]','十日九自病，偶平還苦吟。',48,'全唐诗/poet.song.39000.json','["十日九自病，偶平還苦吟。", "萬金無枉志，千古有遺心。", "静隐支憑几，寒搔髪解簪。", "南風久寂寞，誰繼五弦琴。"]'),
('9a428087-88c9-4d90-9fc8-704e07becaa1','信筆','王令','宋','宋诗','song-poetry','','[]','紛紛世趣竟多途，失在從人得在吾。',64,'全唐诗/poet.song.39000.json','["紛紛世趣竟多途，失在從人得在吾。", "苟獲一時兒女笑，定罹千古聖賢誅。", "微生何事疑人佞，孟子當年亦自迂。", "滿眼悠悠懶商較，盡留來者議賢愚。"]'),
('11a5e5c4-6a35-427e-ba79-781701488659','蜣蜋','王令','宋','宋诗','song-poetry','','[]','擾擾蜣蜋不足評，區區只逐糞丸行。',32,'全唐诗/poet.song.39000.json','["擾擾蜣蜋不足評，區區只逐糞丸行。", "若乘飲露嘶風便，又作人間第一清。"]'),
('70c89e6c-6038-424a-ae23-b18baa8f5b91','答王薄正叔','王令','宋','宋诗','song-poetry','','[]','當年論友笑常情，誰使風波忽沸騰。',64,'全唐诗/poet.song.39000.json','["當年論友笑常情，誰使風波忽沸騰。", "自有赤心包白日，竟無綺語敵青蠅。", "重來赭面還如火，自許清誠卒似冰。", "反覆來篇却堪嘆，待將遺恨寄朱繩。"]'),
('4f5f411e-e36b-4809-9564-873b85543693','秋懷寄呈子權先示徽之兼簡孝先熙之','王令','宋','宋诗','song-poetry','','[]','樹哭寒蜩草哭蟲，何堪覊客憤時窮。',64,'全唐诗/poet.song.39000.json','["樹哭寒蜩草哭蟲，何堪覊客憤時窮。", "卒無可樂羣書外，百不堪言一嘆中。", "雲黯暮天沉白日，土塵平地斷清風。", "夫君若問秋來况，泪滿遺編髪亂蓬。"]'),
('1c16b2a1-bbb0-400b-87a4-2f0f3f729a33','送仲寶叔赴秦幕','王令','宋','宋诗','song-poetry','','[]','秦關千古有雄名，秦地寧時息戰爭。',176,'全唐诗/poet.song.39000.json','["秦關千古有雄名，秦地寧時息戰爭。", "草野英雄無敵國，朝廷勳德倚長城。", "錦纒紅帕將軍府，紫電清霜武庫兵。", "絕幕烽烟沉遠候，太平金鼓雜讙聲。", "淮西司馬新恩重，魯國儒生舊望清。", "黑膽赤心男子事，大弨長劍丈夫行。", "待垂賈誼言餘餌，就試終軍請去纓。", "縱不首傳函報死，亦須頸繫背笞生。", "當年功業鯨鯢盡，振古勳名日月明。", "莫嘆暫從紅幕去，待于歸望碧幢迎。", "愚時若忝書功筆，未信燕然有舊銘。"]'),
('e32e276e-ce03-40b7-8eac-13c8b56be4c9','從光師求花','王令','宋','宋诗','song-poetry','','[]','我有歸心不可寛，憶君花好舊常歡。',64,'全唐诗/poet.song.39000.json','["我有歸心不可寛，憶君花好舊常歡。", "若令醉眼異鄉見，定作故人相笑看。", "知有靈根分客易，却憂平地得春難。", "只應胡蝶還相識，飛過東風又可嘆。"]'),
('8ad84db9-6ce5-4c23-a6e7-b07e9a0be640','九日寄滿子權','王令','宋','宋诗','song-poetry','','[]','懶將衰病照清流，爲有歸心欲白頭。',64,'全唐诗/poet.song.39000.json','["懶將衰病照清流，爲有歸心欲白頭。", "幸自好花開便笑，不甘爲客見成愁。", "長歌欲強秋風醉，髙處先輸俗子遊。", "我在無聊元亮死，當年今日共悠悠。"]'),
('64cf65cd-9242-4d0d-b838-cf43460883db','上黄任道','王令','宋','宋诗','song-poetry','','[]','家世無雙舊，材資第一良。',216,'全唐诗/poet.song.39000.json','["家世無雙舊，材資第一良。", "山川儲地秀，日月合天光。", "遠色抵千古，洪聲壓四方。", "道如天未喪，子讓世誰當。", "文斧摩空運，儒工縮手藏。", "鎔金斥淄石，截玉出端剛。", "追復軒羲舊，裨縫典誥亡。", "誇傳爭噍噍，問望蔚堂堂。", "章甫通期冠，緇裘詎合裳。", "計量遺丈引，收取竟尋常。", "有漸雖宜賀，論才固在傷。", "偶來官簿版，何異任牛羊。", "客有装垂槖，時窮道括囊。", "貧才完竪褐，義不及妻糠。", "劍折終羞屈，蘭移不改香。", "幸偷容足地，恥學及羮墻。", "同日如無善，當年尚取狂。", "互鄉前事在，北面有先望。"]'),
('3a9278b3-2a18-4cfa-8b70-8ef0732c24bb','答滿子權兼簡衡父','王令','宋','宋诗','song-poetry','','[]','君唱奈髙何，君休我試歌。',48,'全唐诗/poet.song.39000.json','["君唱奈髙何，君休我試歌。", "古今愚智府，天地是非羅。", "何日功名就，青雲日月磨。", "俗兒吾不較，計此竟誰多。"]'),
('e21dec49-d618-4ab7-88e4-c57b74229ed7','寄滿粹翁','王令','宋','宋诗','song-poetry','','[]','心愛滿夫子，論師不敢交。',48,'全唐诗/poet.song.39000.json','["心愛滿夫子，論師不敢交。", "誠明大中性，二五老陽爻。", "後學誰思進，吾蒙久辱包。", "思之無見日，夢把客門敲。"]'),
('57509f5e-634d-447e-b4eb-a42cb2db41b4','寄滿衡父','王令','宋','宋诗','song-poetry','','[]','寒葉落傞傞，荆榛刺出柯。',48,'全唐诗/poet.song.39000.json','["寒葉落傞傞，荆榛刺出柯。", "四鄰松竹少，晚歳雪霜多。", "兹世居無可，勞生計奈何。", "此心須見子，不敢向人歌。"]'),
('824bc008-6ec5-4f7c-b70c-10b247185567','多陰','王令','宋','宋诗','song-poetry','','[]','寒雲慘四垂，萬景浩成悲。',48,'全唐诗/poet.song.39000.json','["寒雲慘四垂，萬景浩成悲。", "白日不可見，青天自取欺。", "晚烟先夜色，宿雨借寒威。", "泥潦莫相涴，西風會有時。"]'),
('f38a487f-5bd1-4d4f-a7a8-389624037671','次韵立之紅葉','王令','宋','宋诗','song-poetry','','[]','雨露三春少，風霜一夜多。',48,'全唐诗/poet.song.39000.json','["雨露三春少，風霜一夜多。", "從來有根本，不怕下枝柯。", "楚岸楓相屬，吳山橘與和。", "秋居好相慰，醉色伴吾酡。"]'),
('50253354-dbc9-4cd4-83cb-2e47996bfade','聞富并州入相','王令','宋','宋诗','song-poetry','','[]','元首賡歌樂股肱，四方強遠喜聲盈。',64,'全唐诗/poet.song.39000.json','["元首賡歌樂股肱，四方強遠喜聲盈。", "忠賢不死天心在，輔弼終歸聖慮精。", "中國自今應更重，本朝前日可嗟輕。", "要須待見成堯舜，未敢輕浮作頌聲。"]'),
('bbbe935d-543d-43c0-8964-b8ef287ee5fd','寄黄任道','王令','宋','宋诗','song-poetry','','[]','勞生滚滚欲何如，去髪紛紛日滿梳。',64,'全唐诗/poet.song.39000.json','["勞生滚滚欲何如，去髪紛紛日滿梳。", "萬古聖賢同夢寐，百年天地只蘧蒢。", "詩書計出田園後，歲月期收道路餘。", "安得優游似濠上，共將談笑戲觀魚。"]'),
('dca550ac-b33e-4e1c-8fa4-47716caa2480','答劉仲美','王令','宋','宋诗','song-poetry','','[]','多謝劉夫子，殷懃寄我編。',48,'全唐诗/poet.song.39000.json','["多謝劉夫子，殷懃寄我編。", "何時共杯酒，一笑似當年。", "歲月回霜雪，生涯廢簡編。", "終期收晚學，茅屋送歸田。"]'),
('0cc5716c-2958-4b9e-b117-ed3455bb8672','舟次','王令','宋','宋诗','song-poetry','','[]','梢梢修竹夾溪斜，樹繫孤篷白淺沙。',64,'全唐诗/poet.song.39000.json','["梢梢修竹夾溪斜，樹繫孤篷白淺沙。", "風力引雲行玉馬，水光流月動金蛇。", "村酤客聚還成市，晚釣舟横便當家。", "山野生涯本閑暇，誰令客子自勞嗟。"]'),
('75f6bf8b-f4b2-4ced-ace0-15e4102c8ca6','次韵子權京口夜宿見寄','王令','宋','宋诗','song-poetry','','[]','寒江漠漠客帆稀，獨泊扁舟望翠微。',64,'全唐诗/poet.song.39000.json','["寒江漠漠客帆稀，獨泊扁舟望翠微。", "巳瀉綠醽聊自適，更邀白鳥共忘機。", "水閑海月寒初上，樹盡秋城碧自圍。", "嗟我相思邈千里，不來同此兩忘歸。"]'),
('b0485cf5-561a-42fe-8982-b6536d8f4861','答孫莘老見寄','王令','宋','宋诗','song-poetry','','[]','髙門鞍馬日光榮，勢力紛紛起共爭。',64,'全唐诗/poet.song.39000.json','["髙門鞍馬日光榮，勢力紛紛起共爭。", "偶以不能聊自便，敢于兹世獨求清。", "生無人愧寧非樂，死有天知豈待名。", "客食官居同是苟，何須稱别異平生。"]'),
('2a09faf2-a9e2-4488-869f-e1c2198e0d1b','登郡樓','王令','宋','宋诗','song-poetry','','[]','江城朝雨濕晴烟，樓上風帆送去船。',64,'全唐诗/poet.song.39000.json','["江城朝雨濕晴烟，樓上風帆送去船。", "苟得息肩閑歲月，時來開口笑山川。", "田園啼鳥三春月，江海扁舟萬里天。", "何計脫身來此老，青山白髪兩忘年。"]'),
('06b3a9d2-61b5-4cde-b278-c0490e5a0e02','感憤','王令','宋','宋诗','song-poetry','','[]','二十男兒面似冰，出門嘘氣玉蜺横。',64,'全唐诗/poet.song.39000.json','["二十男兒面似冰，出門嘘氣玉蜺横。", "未甘身世成虛老，大見天心却太平。", "狂去詩渾誇俗句，醉餘歌有過人聲。", "燕然未勒胡雛在，不信吾無萬古名。"]'),
('0d1a3e6b-1df3-4e39-b2c3-f7691d143ec3','聞邕盗','王令','宋','宋诗','song-poetry','','[]','病中雙泪語前流，藜藿無端肉食憂。',64,'全唐诗/poet.song.39000.json','["病中雙泪語前流，藜藿無端肉食憂。", "常嘆平時輕死士，未知誰手付天矛。", "好将弓劍随軍去，况是英雄得志秋。", "若使班超終把筆，由來何路取封侯。"]'),
('acab00b4-75af-4fb0-a10c-be2ae00c71f4','登瓜州迎波亭','王令','宋','宋诗','song-poetry','','[]','海面清風萬里寛，偶來知已脫塵關。',64,'全唐诗/poet.song.39000.json','["海面清風萬里寛，偶來知已脫塵關。", "自嗟客世無虛日，却被斜陽占盡山。", "海鳥不來青嶂静，漁師歸去暮江閑。", "從來雲水有期約，直待功成是厚顔。"]'),
('1c73e17d-a32d-4c8d-9ec7-ed84899c5d1a','聞雁','王令','宋','宋诗','song-poetry','','[]','可憐飲啄鎮随陽，何處聞時最斷腸。',64,'全唐诗/poet.song.39000.json','["可憐飲啄鎮随陽，何處聞時最斷腸。", "萬里波濤九秋後，五更風雨一燈旁。", "乾坤莽莽連舟楫，繒繳紛紛羃稻梁。", "安得人同覊旅意，悠悠南北不相傷。"]'),
('4fe64861-b76f-4847-90de-0d5d055d468d','憶潤州葛使君','王令','宋','宋诗','song-poetry','','[]','六朝遊觀委蒿蓬，想像當時事已空。',64,'全唐诗/poet.song.39000.json','["六朝遊觀委蒿蓬，想像當時事已空。", "半夜樓臺横海日，萬家簫鼓過江風。", "金山寺近塵埃絕，鐡甕城深氣象雄。", "欲放船随明月去，應留閑暇待詩翁。"]'),
('00130d7d-8c98-471d-befc-0664efd622e3','何處難忘酒十首  其一','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，君臣草昧初。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，君臣草昧初。", "謀臣偷賊胆，力士斡凶鋤。", "日月明將霽，乾坤害欲除。", "此時無一盞，何以壮雄圖。"]'),
('f18971c5-68d2-431a-bdb8-1a6851634f18','何處難忘酒十首  其二','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，天心渇太平。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，天心渇太平。", "焚山急賢出，拔草惡奸生。", "議盡芻蕘口，歌回雅頌音。", "此時無一盞，何以快輿情。"]'),
('c85faade-4a8e-4eae-882d-d4f7807f55be','何處難忘酒十首  其三','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，登賢入用初。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，登賢入用初。", "一身兼禹稷，四海再唐虞。", "去聖千年恨，明時一日舒。", "此時無一盞，何以酹亨衢。"]'),
('d0cf63bb-f187-4a4e-ae4a-b7799b0728d1','何處難忘酒十首  其四','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，王朝四海中。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，王朝四海中。", "魚鳶上下樂，羌狄朔南通。", "萬玉叢丹陛，千簪合辟廱。", "此時無一盞，何以樂成功。"]'),
('ec13c846-6f97-4441-a995-be71ed70401e','何處難忘酒十首  其五','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，君王宴豫年。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，君王宴豫年。", "羣謀安一統，無口議將然。", "閑暇開元後，優游大業前。", "此時無一盞，何以慰遺賢。"]'),
('7979c730-d04f-4259-9417-6553ca639626','何處難忘酒十首  其六','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，王臣立藎方。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，王臣立藎方。", "羣邪終自直，萬死不摧剛。", "社鼠旁難塞，龍鱗逆易傷。", "此時無一盞，何以洗憂腸。"]'),
('790c6d09-769d-42d5-8027-7ef756ab7a74','何處難忘酒十首  其七','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，窮邊壮士歌。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，窮邊壮士歌。", "寒弓彎未試，秋劍拔新磨。", "月落陰山暗，沙昏伏甲多。", "此時無一盞，何以陷前戈。"]'),
('bca0b9fa-1240-4e3e-8cd1-919ad7186d5a','何處難忘酒十首  其八','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，欃槍世不平。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，欃槍世不平。", "孤兒未勝甲，孀母送爲兵。", "氣絕心肝裂，號窮血泪横。", "此時無一盞，何以活餘生。"]'),
('dcdb706e-f865-425b-bd13-5e6abe355131','何處難忘酒十首  其九','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，窮才世不知。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，窮才世不知。", "出門無直道，開口礙當時。", "白髪無端速，青山不忍期。", "此時無一盞，何以慰憂思。"]'),
('3bb2c32e-6e75-4c3e-bdc8-ce58f35ad74f','何處難忘酒十首  其一○','王令','宋','宋诗','song-poetry','','[]','何處難忘酒，亡君復舊遊。',48,'全唐诗/poet.song.39000.json','["何處難忘酒，亡君復舊遊。", "黍離經故國，麥秀悼前羞。", "遠目何勝盡，行車逆自留。", "此時無一盞，何以謝悠悠。"]'),
('67d72a75-4372-45ca-a79d-b58e32521eb4','送錢公輔赴舉','王令','宋','宋诗','song-poetry','','[]','廣庭簪紱立差肩，黼坐雍容第衆賢。',64,'全唐诗/poet.song.39000.json','["廣庭簪紱立差肩，黼坐雍容第衆賢。", "士得采衣如晝錦，人瞻歸馬若天仙。", "况提巨筆乘時出，應有髙文與世傳。", "我久疏慵無壮思，聊傾病耳待江邊。"]'),
('9cad474e-6bb0-4aa2-a175-2918d4202add','春興','王令','宋','宋诗','song-poetry','','[]','眼前紅綠日加增，欲遣春愁興未能。',64,'全唐诗/poet.song.39000.json','["眼前紅綠日加增，欲遣春愁興未能。", "安得好花渾自實，使無閑地得生荆。", "欲圖長醉貧無計，起逐東風懶不勝。", "芳草斜陽正柔媚，益知髙處不堪登。"]'),
('64a847f1-7b7f-4c62-bef9-1a51ab49341b','庭草  其一','王令','宋','宋诗','song-poetry','','[]','庭草綠毰毸，庭花閑自開。',48,'全唐诗/poet.song.39000.json','["庭草綠毰毸，庭花閑自開。", "長鴻抱寒去，輕燕逐春來。", "時節看風柳，生涯寄酒杯。", "傷春欲誰語，遊子正徘徊。"]'),
('d7988315-9064-4f75-9427-2b04e63872b1','庭草  其二','王令','宋','宋诗','song-poetry','','[]','平時已多病，春至更蹉跎。',48,'全唐诗/poet.song.39000.json','["平時已多病，春至更蹉跎。", "惡土種花少，東風生草多。", "客愁渾寄泪，野思不堪歌。", "獨有詩心在，時時一自哦。"]'),
('393dfb4c-3a0c-41b0-8e9f-af143a3212a3','春怨','王令','宋','宋诗','song-poetry','','[]','掃地待花落，惜花輕着塵。',24,'全唐诗/poet.song.39000.json','["掃地待花落，惜花輕着塵。", "遊人空眷戀，踏去却尋春。"]'),
('886a317e-6592-4c63-bd85-4230cfe8daae','春晚二首  其一','王令','宋','宋诗','song-poetry','','[]','春來還自有遊人，常是春歸獨念春。',32,'全唐诗/poet.song.39000.json','["春來還自有遊人，常是春歸獨念春。", "落後見花尤更惜，不知誰忍掃和塵。"]'),
('73225e42-5d36-487b-89c4-16dc058d710e','春晚二首  其二','王令','宋','宋诗','song-poetry','','["\u6625\u5929", "\u5199\u666f", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u60dc\u6625", "\u5b8b\u8bd7"]','三月殘花落更開，小簷日日燕飛來。',32,'全唐诗/poet.song.39000.json','["三月殘花落更開，小簷日日燕飛來。", "子規夜半猶啼血，不信東風喚不回。"]'),
('68de6751-c3f6-4f2e-8f6c-f6fade2390b9','暑中懶出','王令','宋','宋诗','song-poetry','','[]','暑雲無雨易飛揚，旱日當天不可望。',64,'全唐诗/poet.song.39000.json','["暑雲無雨易飛揚，旱日當天不可望。", "浪走俗塵無遠到，不如嘉樹坐餘凉。", "巳嫌風少難平暑，更被蟬饑取實腸。", "夢到周公才我事，如何陶令說羲皇。"]'),
('c649415c-038a-4bb9-8880-75065f8ca16f','暑熱思風','王令','宋','宋诗','song-poetry','','[]','坐将赤熱憂天下，安得清風借我曹。',64,'全唐诗/poet.song.39000.json','["坐将赤熱憂天下，安得清風借我曹。", "力卷雨來無歲旱，盡吹雲去放天髙。", "豈随虎口令輕嘯，願助鴻毛絕遠勞。", "江海可憐無際岸，等閑假借作波濤。"]'),
('efe0f014-7026-4e83-b82f-4c23cd89972b','悲秋','王令','宋','宋诗','song-poetry','','[]','歲事荒凉晚易悲，西風日夜弄寒威。',64,'全唐诗/poet.song.39000.json','["歲事荒凉晚易悲，西風日夜弄寒威。", "秋來寡婦尤勤織，誰是行人未有衣。", "常恐衰顔随節換，空看落葉倚風飛。", "從來最是悲秋者，况是悲秋客未歸。"]'),
('58baa87e-1d8c-4d57-99f8-0e72226e0cac','秋日寄滿子權','王令','宋','宋诗','song-poetry','','[]','樓前暮靄暗平林，樓上人愁意思深。',64,'全唐诗/poet.song.39000.json','["樓前暮靄暗平林，樓上人愁意思深。", "未必薄雲能作雨，從來秋日自多陰。", "三年客夢迷歸路，一夜西風老壮心。", "欲作新聲寄遺恨，直弦先斷淚盈琴。"]'),
('1176bab1-53b6-493c-a745-cfcd322572a4','次韵介父冬日','王令','宋','宋诗','song-poetry','','[]','客夢愁生枕，雞號喜向晨。',48,'全唐诗/poet.song.39000.json','["客夢愁生枕，雞號喜向晨。", "朔風能動地，短日更随人。", "宫柳看埋凍，江梅想漏春。", "淹留歸未得，塵土暗烏巾。"]'),
('2bb159a6-b5e1-4cb7-9b2a-11b06ed620e4','白雞冠花','王令','宋','宋诗','song-poetry','','[]','如飛如舞對瑶臺，一頂春雲若剪裁。',32,'全唐诗/poet.song.39000.json','["如飛如舞對瑶臺，一頂春雲若剪裁。", "誰爲移根蓂莢畔，玉雞應爲太平來。"]'),
('5995cec9-c1e8-470f-a9e4-d7f65202a8bf','去草','王令','宋','宋诗','song-poetry','','[]','毿毿出土初如直，嫋嫋随風競自斜。',64,'全唐诗/poet.song.39000.json','["毿毿出土初如直，嫋嫋随風競自斜。", "漫借人鋤勞剗拔，只消夜雨又萌芽。", "良田力盡農夫嘆，直道春荒志士嗟。", "滿目青青盡蕪蔓，更於何處問蓬麻。"]'),
('8a2a9a2c-d28f-4752-bb7c-2d4feec5d181','次韵和人古松','王令','宋','宋诗','song-poetry','','[]','直枝難立鳥徘徊，地瘦根孤礙石回。',64,'全唐诗/poet.song.39000.json','["直枝難立鳥徘徊，地瘦根孤礙石回。", "山野不逢終更老，閭閻無用始爲材。", "更無匠伯身嘗過，祗有幽人眼暫開。", "誰與東風記霜雪，争令平地肯栽培。"]'),
('bc6d9063-da9d-4520-82aa-7818bc4688e9','大松','王令','宋','宋诗','song-poetry','','[]','十尋瘦幹三冬綠，一畝濃陰六月清。',64,'全唐诗/poet.song.39000.json','["十尋瘦幹三冬綠，一畝濃陰六月清。", "莫謂世材難見用，須知天意不徒生。", "長蛟老蜃空中影，驟雨驚雷半夜聲。", "却笑五株喬嶽下，肯将直節事秦嬴。"]'),
('32c656a3-352c-4a4d-9d98-30c7208bcc72','松','王令','宋','宋诗','song-poetry','','[]','直道峍峍日蚪拳，雷拔僵龍出靄烟。',64,'全唐诗/poet.song.39000.json','["直道峍峍日蚪拳，雷拔僵龍出靄烟。", "但假深根常得地，何憂直幹不扶天。", "雖然世匠遺掄度，肯與凡材較後先。", "可惜春風愛桃李，獨令霜雪漫年年。"]'),
('df1f7ed2-789c-4587-af74-23facd6fadac','和人雙柏','王令','宋','宋诗','song-poetry','','[]','一時封植由誰力，萬古樵萊偶自全。',64,'全唐诗/poet.song.39000.json','["一時封植由誰力，萬古樵萊偶自全。", "不惜以材同失地，好留更老共支天。", "人疑久有神靈守，客愛生無雨露偏。", "爲語長松號孤勁，得秦封爵果何緣。"]'),
('684055b0-f214-4196-8cce-b2310023f4ef','慈竹','王令','宋','宋诗','song-poetry','','[]','不求丹鳯食，不學景龍吟。',48,'全唐诗/poet.song.39000.json','["不求丹鳯食，不學景龍吟。", "自有慈仁意，相依歲月深。", "潜符君子道，可愧世人心。", "徒爾秋郊外，青青數畝陰。"]'),
('3c4686da-da54-45a1-af85-25a233b51d95','落葉','王令','宋','宋诗','song-poetry','','[]','暮秋木落剥霜紅，俄覺平林一夜空。',32,'全唐诗/poet.song.39000.json','["暮秋木落剥霜紅，俄覺平林一夜空。", "茂遂本憑枝幹力，却辭枝幹逐西風。"]'),
('f56869ea-daa3-48ee-a4d5-d3d4b19899d5','不雨','王令','宋','宋诗','song-poetry','','[]','去歲秋霖若决川，今春不雨旱良田。',64,'全唐诗/poet.song.39000.json','["去歲秋霖若决川，今春不雨旱良田。", "道邊老幼饑將死，雲外蛟龍懶自眠。", "赤日有威空射地，清江無際漫連天。", "誰將民瘼牋雙闕，四海皇恩一漏泉。"]'),
('78ddf817-691e-4175-a94b-fad011bead45','雨後','王令','宋','宋诗','song-poetry','','[]','毶毶柳色綠垂齊，草引青天去自迷。',64,'全唐诗/poet.song.39000.json','["毶毶柳色綠垂齊，草引青天去自迷。", "人說春園有尋路，我嗟荒徑正行泥。", "蝶多平日渾如夢，花好誰家又有蹊。", "兒女狂嬌随馬逐，髙眠可惜日垂西。"]'),
('bbe9afe9-ede1-4a45-b16d-a43a607fe577','約僧宿北山庵先寄平甫','王令','宋','宋诗','song-poetry','','[]','上人合動山間興，吾恨衰遲學謝安。',64,'全唐诗/poet.song.39000.json','["上人合動山間興，吾恨衰遲學謝安。", "納屐操笻那有限，吹雲落雨漫無端。", "先憑報信春枝破，預想分題雪屋寒。", "林下不諳人世苦，笑將霜鬂與君看。"]'),
('be7565e2-24d2-4c93-b5bd-e451ff40f8d2','和人久雨','王令','宋','宋诗','song-poetry','','[]','拂拂春郊起綠煙，羣農日日望豐年。',64,'全唐诗/poet.song.39000.json','["拂拂春郊起綠煙，羣農日日望豐年。", "龍移海去遺天漏，蚓得泥深樂地穿。", "憶酒有心吞俗價，傷春無語寄哀弦。", "無田却作無憂者，贏得豐凶一聽天。"]');
